-- Poems batch 447
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-44','玩春因寄馮衛二補闕戲呈李益','盧綸','唐','御定全唐诗','yuding','','[]','掖垣春色自天來，紅藥當階次第開。',32,'御定全唐詩/json/278.json','["掖垣春色自天來，紅藥當階次第開。", "萱草叢叢爾何物，等閒穿破綠莓苔。"]'),
('yuding-45','新移北廳因貽同院諸公兼呈暢博士','盧綸','唐','御定全唐诗','yuding','','[]','華軒邇台座，顧影忝時倫。弱質偃彌曠，清風來亦頻。',48,'御定全唐詩/json/278.json','["華軒邇台座，顧影忝時倫。弱質偃彌曠，清風來亦頻。", "恩輝坐淩邁，景物恣芳新。終乃愧吾友，無容私此身。"]'),
('yuding-46','與張擢對酌','盧綸','唐','御定全唐诗','yuding','','[]','張翁對盧叟，一榼山村酒。傾酒請予歌，忽蒙張翁呵。',108,'御定全唐詩/json/278.json','["張翁對盧叟，一榼山村酒。傾酒請予歌，忽蒙張翁呵。", "呵予官非屈，曲有怨詞多。歌罷謝張翁，所思殊不同。", "予悲方為老，君責一何空。曾看樂官錄，向是悲翁曲。", "張老聞此詞，汪汪淚盈目。盧叟醉言粗，一杯凡數呼。", "回頭顧張老，敢欲戲為儒。"]'),
('yuding-47','喜從弟激初至','盧綸','唐','御定全唐诗','yuding','','[]','儒服策羸車，惠然過我廬。敘年慚已長，稱從意何疏。',48,'御定全唐詩/json/278.json','["儒服策羸車，惠然過我廬。敘年慚已長，稱從意何疏。", "作吏清無比，為文麗有餘。應嗤受恩者，頭白讀兵書。"]'),
('yuding-48','尋賈尊師','盧綸','唐','御定全唐诗','yuding','','[]','玉洞秦時客，焚香映綠蘿。新傳左慈訣，曾與右軍鵝。',48,'御定全唐詩/json/278.json','["玉洞秦時客，焚香映綠蘿。新傳左慈訣，曾與右軍鵝。", "井臼陰苔遍，方書古字多。成都今日雨，應與酒相和。"]'),
('yuding-49','秋中過獨孤郊居','盧綸','唐','御定全唐诗','yuding','','[]','開園過水到郊居，共引家童拾野蔬。高樹夕陽連古巷，',40,'御定全唐詩/json/278.json','["開園過水到郊居，共引家童拾野蔬。高樹夕陽連古巷，", "帝裏諸親別來久，豈知王粲愛樵漁。"]'),
('yuding-50','同耿拾遺春中題第四郎新修書院','盧綸','唐','御定全唐诗','yuding','','[]','得接西園會，多因野性同。引藤連樹影，移石間花叢。',72,'御定全唐詩/json/278.json','["得接西園會，多因野性同。引藤連樹影，移石間花叢。", "學就晨昏外，歡生禮樂中。春遊隨墨客，夜宿伴潛公。", "散帙燈驚燕，開簾月帶風。朝朝在門下，自與五侯通。"]'),
('yuding-51','春日題杜叟山下別業','盧綸','唐','御定全唐诗','yuding','','[]','白鳥群飛山半晴，渚田相接有泉聲。園中曉露青叢合，',40,'御定全唐詩/json/278.json','["白鳥群飛山半晴，渚田相接有泉聲。園中曉露青叢合，", "今朝醉舞同君樂，始信幽人不愛榮。"]'),
('yuding-52','過終南柳處士','盧綸','唐','御定全唐诗','yuding','','[]','五老正相尋，圍棋到煮金。石摧丹井閉，月過洞門深。',72,'御定全唐詩/json/278.json','["五老正相尋，圍棋到煮金。石摧丹井閉，月過洞門深。", "猿鳥三時下，藤蘿十裏陰。綠泉多草氣，青壁少花林。", "自愧非仙侶，何言見道心。悠哉宿山口，雷雨夜沉沉。"]'),
('yuding-53','宿澄上人院','盧綸','唐','御定全唐诗','yuding','','[]','竹窗聞遠水，月出似溪中。香覆經年火，幡飄後夜風。',48,'御定全唐詩/json/278.json','["竹窗聞遠水，月出似溪中。香覆經年火，幡飄後夜風。", "性昏知道晚，學淺喜言同。一悟歸身處，何山路不通。"]'),
('yuding-54','題李沆林園','盧綸','唐','御定全唐诗','yuding','','[]','古巷牛羊出，重門接柳陰。閑看入竹路，自有向山心。',48,'御定全唐詩/json/278.json','["古巷牛羊出，重門接柳陰。閑看入竹路，自有向山心。", "種藥齊幽石，耕田到遠林。願同詞賦客，得興謝家深。"]'),
('yuding-0','過司空曙村居','盧綸','唐','御定全唐诗','yuding','','[]','南北與山鄰，蓬庵庇一身。繁霜疑有雪，枯草似無人。',48,'御定全唐詩/json/279.json','["南北與山鄰，蓬庵庇一身。繁霜疑有雪，枯草似無人。", "遂性在耕稼，所交唯賤貧。何言張掾傲，每重德璋親。"]'),
('yuding-1','題念濟寺暈上人院','盧綸','唐','御定全唐诗','yuding','','[]','泉響竹瀟瀟，潛公居處遙。虛空聞偈夜，清淨雨花朝。',72,'御定全唐詩/json/279.json','["泉響竹瀟瀟，潛公居處遙。虛空聞偈夜，清淨雨花朝。", "放鶴臨山閣，降龍步石橋。世塵徒委積，劫火定焚燒。", "苔壁雲難聚，風篁露易搖。浮生亦無著，況乃是芭蕉。"]'),
('yuding-2','題楊虢縣竹亭','盧綸','唐','御定全唐诗','yuding','','[]','夜宿密公室，話餘將晝興。繞階三徑雪，當戶一池冰。',48,'御定全唐詩/json/279.json','["夜宿密公室，話餘將晝興。繞階三徑雪，當戶一池冰。", "家訓資風化，心源隱政能。明朝複何見，萊草古溝塍。"]'),
('yuding-3','過樓觀李尊師','盧綸','唐','御定全唐诗','yuding','','[]','城闕望煙霞，常悲仙路賒。寧知樵子徑，得到葛洪家。',72,'御定全唐詩/json/279.json','["城闕望煙霞，常悲仙路賒。寧知樵子徑，得到葛洪家。", "犬吠松間月，人行洞裏花。留詩千歲鶴，送客五雲車。", "訪世山空在，觀棋日未斜。不知塵俗士，誰解種胡麻。"]'),
('yuding-4','雪謗後逢李叔度','盧綸','唐','御定全唐诗','yuding','','[]','相逢空握手，往事不堪思。見少情難盡，愁深語自遲。',48,'御定全唐詩/json/279.json','["相逢空握手，往事不堪思。見少情難盡，愁深語自遲。", "草生分路處，雨散出山時。強得寬離恨，唯當說後期。"]'),
('yuding-5','春日過李侍禦','盧綸','唐','御定全唐诗','yuding','','[]','高柳滿春城，東園有鳥聲。折花朝露滴，漱石野泉清。',48,'御定全唐詩/json/279.json','["高柳滿春城，東園有鳥聲。折花朝露滴，漱石野泉清。", "心許陶家醉，詩逢謝客呈。應憐末行吏，曾是魯諸生。"]'),
('yuding-6','出山逢耿湋','盧綸','唐','御定全唐诗','yuding','','[]','雲雪離披山萬里，別來曾住最高峰。',32,'御定全唐詩/json/279.json','["雲雪離披山萬里，別來曾住最高峰。", "暫到人間歸不得，長安陌上又相逢。"]'),
('yuding-7','題金吾郭將軍石伏茅堂','盧綸','唐','御定全唐诗','yuding','','[]','雲戟曙沉沉，軒墀清且深。家傳成棟美，堯寵結茅心。',96,'御定全唐詩/json/279.json','["雲戟曙沉沉，軒墀清且深。家傳成棟美，堯寵結茅心。", "玉佩多依石，油幢亦在林。爐香諸洞暖，殿影眾山陰。", "草奏風生筆，筵開雪滿琴。客從龍闕至，僧自虎溪尋。", "蕭灑延清賞，風流會素襟。終朝息塵步，一醉間華簪。"]'),
('yuding-8','題賈山人園林','盧綸','唐','御定全唐诗','yuding','','[]','竹影朦朧松影長，素琴清簟好風涼。連春詩會煙花滿，',40,'御定全唐詩/json/279.json','["竹影朦朧松影長，素琴清簟好風涼。連春詩會煙花滿，", "長沙流謫君非遠，莫遣英名負洛陽。"]'),
('yuding-9','秋夜同暢當宿藏公院','盧綸','唐','御定全唐诗','yuding','','[]','禮足一垂淚，醫王知病由。風螢方喜夜，露槿已傷秋。',48,'御定全唐詩/json/279.json','["禮足一垂淚，醫王知病由。風螢方喜夜，露槿已傷秋。", "顧以兒童愛，每從仁者求。將祈竟何得，滅跡在緇流。"]'),
('yuding-10','重同暢當奘公院聞琴','盧綸','唐','御定全唐诗','yuding','','[]','誤以音聲祈遠公，請將徽軫付秋風。',32,'御定全唐詩/json/279.json','["誤以音聲祈遠公，請將徽軫付秋風。", "漾漾硤流吹不盡，月華如在白波中。"]'),
('yuding-11','同耿湋宿陸澧旅舍','盧綸','唐','御定全唐诗','yuding','','[]','當軒雲月開，清夜故人杯。擁褐覺霜下，抱琴聞雁來。',48,'御定全唐詩/json/279.json','["當軒雲月開，清夜故人杯。擁褐覺霜下，抱琴聞雁來。", "迎風君顧步，臨路我遲回。雙鬢共如此，此歡非易陪。"]'),
('yuding-12','題苗員外竹間亭','盧綸','唐','御定全唐诗','yuding','','[]','高甃絕行塵，開簾似有春。風傾竹上雪，山對酒邊人。',48,'御定全唐詩/json/279.json','["高甃絕行塵，開簾似有春。風傾竹上雪，山對酒邊人。", "步暖先逢日，書空遠見鄰。還同內齋暇，登賞及諸姻。"]'),
('yuding-13','奉陪侍中登白樓','盧綸','唐','御定全唐诗','yuding','','[]','高樓倚玉梯，朱檻與雲齊。顧盼親霄漢，談諧息鼓鼙。',48,'御定全唐詩/json/279.json','["高樓倚玉梯，朱檻與雲齊。顧盼親霄漢，談諧息鼓鼙。", "洪河斜更直，野雨急仍低。今日陪尊俎，唯當醉似泥。"]'),
('yuding-14','九日奉陪侍郎登白樓','盧綸','唐','御定全唐诗','yuding','','[]','碧霄孤鶴發清音，上宰因添望闕心。睥睨三層連步障，',40,'御定全唐詩/json/279.json','["碧霄孤鶴發清音，上宰因添望闕心。睥睨三層連步障，", "此日所從何所問，儼然冠劍擁成林。"]'),
('yuding-15','春日喜雨奉和馬侍中宴白樓','盧綸','唐','御定全唐诗','yuding','','[]','鸛鶴相呼綠野寬，鼎臣閑倚玉欄幹。洪河擁沫流仍急，',40,'御定全唐詩/json/279.json','["鸛鶴相呼綠野寬，鼎臣閑倚玉欄幹。洪河擁沫流仍急，", "今朝醉舞共鄉老，不覺傾欹獬豸冠。"]'),
('yuding-16','奉陪侍中游石筍溪十二韻','盧綸','唐','御定全唐诗','yuding','','[]','朝日照靈山，山溪浩紛錯。圖書無舊記，鯀禹應新鑿。',144,'御定全唐詩/json/279.json','["朝日照靈山，山溪浩紛錯。圖書無舊記，鯀禹應新鑿。", "雙壁瀉天河，一峰吐蓮萼。潭心亂雪卷，岩腹繁珠落。", "彩蛤攢錦囊，芳蘿嫋花索。猿群曝陽嶺，龍穴腥陰壑。", "靜得漁者言，閑聞洞仙博。欹松倚朱幰，廣石屯油幕。", "國泰事留侯，山春縱康樂。間關殊狀鳥，爛熳無名藥。", "欲驗少君方，還吟大隱作。旌幢不可駐，古塞新沙漠。"]'),
('yuding-17','九日奉陪侍中宴白樓','盧綸','唐','御定全唐诗','yuding','','[]','露白菊氛氳，西樓盛襲文。玉筵秋令節，金鉞漢元勳。',48,'御定全唐詩/json/279.json','["露白菊氛氳，西樓盛襲文。玉筵秋令節，金鉞漢元勳。", "說劍風生座，抽琴鶴繞雲。謏儒無以答，願得備前軍。"]'),
('yuding-18','九日奉陪侍中宴後亭','盧綸','唐','御定全唐诗','yuding','','[]','玉壺傾菊酒，一顧得淹留。彩筆征枚叟，花筵舞莫愁。',48,'御定全唐詩/json/279.json','["玉壺傾菊酒，一顧得淹留。彩筆征枚叟，花筵舞莫愁。", "管弦能駐景，松桂不停秋。為謝蓬蒿輩，如何霜霰稠。"]'),
('yuding-19','九日奉陪令公登白樓同詠菊','盧綸','唐','御定全唐诗','yuding','','[]','瓊尊猶有菊，可以獻留侯。願比三花秀，非同百卉秋。',48,'御定全唐詩/json/279.json','["瓊尊猶有菊，可以獻留侯。願比三花秀，非同百卉秋。", "金英分蕊細，玉露結房稠。黃雀知恩在，銜飛亦上樓。"]'),
('yuding-20','奉陪渾侍中上巳日泛渭河','盧綸','唐','御定全唐诗','yuding','','[]','青舸錦帆開，浮天接上臺。晚鶯和玉笛，春浪動金罍。',48,'御定全唐詩/json/279.json','["青舸錦帆開，浮天接上臺。晚鶯和玉笛，春浪動金罍。", "舟楫方朝海，鯨鯢自曝腮。應憐似萍者，空逐榜人回。"]'),
('yuding-21','奉陪侍中春日過武安君廟','盧綸','唐','御定全唐诗','yuding','','[]','長裾間貔虎，遺廟盛攀登。白羽三千騎，紅林一萬層。',72,'御定全唐詩/json/279.json','["長裾間貔虎，遺廟盛攀登。白羽三千騎，紅林一萬層。", "元臣達幽契，祝史告明征。撫坐悲今古，瞻容感廢興。", "回風卷叢柏，驟雨濕諸陵。倏忽煙花霽，當營看月生。"]'),
('yuding-22','過玉真公主影殿','盧綸','唐','御定全唐诗','yuding','','[]','夕照臨窗起暗塵，青松繞殿不知春。',32,'御定全唐詩/json/279.json','["夕照臨窗起暗塵，青松繞殿不知春。", "君看白髮誦經者，半是宮中歌舞人。"]'),
('yuding-23','題嘉祥殿南溪印禪師壁畫影堂','盧綸','唐','御定全唐诗','yuding','','[]','雙屐參差錫杖斜，衲衣交膝對天花。',32,'御定全唐詩/json/279.json','["雙屐參差錫杖斜，衲衣交膝對天花。", "瞻容悟問修持劫，似指前溪無數沙。"]'),
('yuding-24','題伯夷廟','盧綸','唐','御定全唐诗','yuding','','[]','中條山下黃礓石，壘作夷齊廟裏神。',32,'御定全唐詩/json/279.json','["中條山下黃礓石，壘作夷齊廟裏神。", "落葉滿階塵滿座，不知澆酒為何人。"]'),
('yuding-25','早春遊樊川野居卻寄李端校書兼呈崔峒補闕司空曙主簿耿湋拾遺','盧綸','唐','御定全唐诗','yuding','','[]','白水遍溝塍，青山對杜陵。晴明人望鶴，曠野鹿隨僧。',168,'御定全唐詩/json/279.json','["白水遍溝塍，青山對杜陵。晴明人望鶴，曠野鹿隨僧。", "古柳連巢折，荒堤帶草崩。陰橋全覆雪，瀑溜半垂冰。", "鬥鼠搖松影，游龜落石層。韶光偏不待，衰敗巧相仍。", "桂樹曾爭折，龍門幾共登。琴師阮校尉，詩和柳吳興。", "舐筆求書扇，張屏看畫蠅。卜鄰空遂約，問卦獨無征。", "投足經危路，收才遇直繩。守農窮自固，行樂病何能。", "掩帙蓬蒿晚，臨川景氣澄。颯然成一叟，誰更慕鶱騰。"]'),
('yuding-26','同錢郎中晚春過慈恩寺','盧綸','唐','御定全唐诗','yuding','','[]','不見僧中舊，仍逢雨後春。惜花將愛寺，俱是白頭人。',24,'御定全唐詩/json/279.json','["不見僧中舊，仍逢雨後春。惜花將愛寺，俱是白頭人。"]'),
('yuding-27','曲江春望','盧綸','唐','御定全唐诗','yuding','','[]','菖蒲翻葉柳交枝，暗上蓮舟鳥不知。',96,'御定全唐詩/json/279.json','["菖蒲翻葉柳交枝，暗上蓮舟鳥不知。", "更到無花最深處，玉樓金殿影參差。", "翠黛紅妝畫鷁中，共驚雲色帶微風。", "簫管曲長吹未盡，花南水北雨濛濛。", "泉聲遍野入芳洲，擁沫吹花草上流。", "落日行人漸無路，巢烏乳燕滿高樓。"]'),
('yuding-28','春日陪李庶子遵善寺東院曉望','盧綸','唐','御定全唐诗','yuding','','[]','映竹水田分，當山起雁群。陽峰高對寺，陰井下通雲。',48,'御定全唐詩/json/279.json','["映竹水田分，當山起雁群。陽峰高對寺，陰井下通雲。", "雪晝唯逢鶴，花時此見君。由來禪誦地，多有謝公文。"]'),
('yuding-29','華清宮','盧綸','唐','御定全唐诗','yuding','','[]','漢家天子好經過，白日青山宮殿多。',64,'御定全唐詩/json/279.json','["漢家天子好經過，白日青山宮殿多。", "見說只今生草處，禁泉荒石已相和。", "水氣朦朧滿畫梁，一回開殿滿山香。", "宮娃幾許經歌舞，白首翻令憶建章。"]'),
('yuding-30','題興善寺後池','盧綸','唐','御定全唐诗','yuding','','[]','隔窗棲白鶴，似與鏡湖鄰。月照何年樹，花逢幾遍人。',48,'御定全唐詩/json/279.json','["隔窗棲白鶴，似與鏡湖鄰。月照何年樹，花逢幾遍人。", "岸莎青有路，苔徑綠無塵。永願容依止，僧中老此身。"]'),
('yuding-31','陪中書李紓舍人夜泛東池','盧綸','唐','御定全唐诗','yuding','','[]','看月複聽琴，移舟出樹陰。夜村機杼急，秋水芰荷深。',48,'御定全唐詩/json/279.json','["看月複聽琴，移舟出樹陰。夜村機杼急，秋水芰荷深。", "石靜龜潛上，萍開果暗沈。何言奉杯酒，得見五湖心。"]'),
('yuding-32','宴趙氏昆季書院因與會文並率爾投贈','盧綸','唐','御定全唐诗','yuding','','[]','詩禮挹餘波，相歡在琢磨。琴尊方會集，珠玉忽駢羅。',72,'御定全唐詩/json/279.json','["詩禮挹餘波，相歡在琢磨。琴尊方會集，珠玉忽駢羅。", "謝族風流盛，于門福慶多。花攢騏驥櫪，錦絢鳳凰窠。", "詠雪因饒妹，書經為愛鵝。仍聞廣練被，更有遠儒過。"]'),
('yuding-33','題天華觀','盧綸','唐','御定全唐诗','yuding','','[]','峰嶂徘徊霞景新，一潭寒水絕纖鱗。朱字靈書千萬軸，',40,'御定全唐詩/json/279.json','["峰嶂徘徊霞景新，一潭寒水絕纖鱗。朱字靈書千萬軸，", "眼見仙丹求不得，漢家簪紱在羸身。"]'),
('yuding-34','宿石甕寺','盧綸','唐','御定全唐诗','yuding','','[]','殿有寒燈草有螢，千林萬壑寂無聲。煙凝積水龍蛇蟄，',40,'御定全唐詩/json/279.json','["殿有寒燈草有螢，千林萬壑寂無聲。煙凝積水龍蛇蟄，", "回瞻相好因垂淚，苦海波濤何日平。"]'),
('yuding-35','題悟真寺','盧綸','唐','御定全唐诗','yuding','','[]','萬峰交掩一峰開，曉色常從天上來。',32,'御定全唐詩/json/279.json','["萬峰交掩一峰開，曉色常從天上來。", "似到西方諸佛國，蓮花影裏數樓臺。"]'),
('yuding-36','題雲際寺上方','盧綸','唐','御定全唐诗','yuding','','[]','松高蘿蔓輕，中有石床平。下界水長急，上方燈自明。',48,'御定全唐詩/json/279.json','["松高蘿蔓輕，中有石床平。下界水長急，上方燈自明。", "空門不易啟，初地本無程。回步忽山盡，萬緣從此生。"]'),
('yuding-37','九日同司直九叔崔侍禦登寶雞南樓','盧綸','唐','御定全唐诗','yuding','','[]','把菊歎將老，上樓悲未還。短長新白髮，重疊舊青山。',48,'御定全唐詩/json/279.json','["把菊歎將老，上樓悲未還。短長新白髮，重疊舊青山。", "霜氣清襟袖，琴聲引醉顏。竹林唯七友，何幸亦登攀。"]'),
('yuding-38','同王員外雨後登開元寺南樓因寄西岩警上人','盧綸','唐','御定全唐诗','yuding','','[]','過雨開樓看晚虹，白雲相逐水相通。寒蟬噪暮野無日，',40,'御定全唐詩/json/279.json','["過雨開樓看晚虹，白雲相逐水相通。寒蟬噪暮野無日，", "何言暫別東林友，惆悵人間事不同。"]'),
('yuding-39','同趙進馬元陽春日登長春宮古城望河中因寄鄭損倉曹','盧綸','唐','御定全唐诗','yuding','','[]','城頭春靄曉濛濛，指望關橋滿袖風。雲騎閑嘶宮柳外，',40,'御定全唐詩/json/279.json','["城頭春靄曉濛濛，指望關橋滿袖風。雲騎閑嘶宮柳外，", "跡忝已成方戀賞，此時離恨與君同。"]'),
('yuding-40','同崔峒補闕慈恩寺避暑','盧綸','唐','御定全唐诗','yuding','','[]','寺涼高樹合，臥石綠陰中。伴鶴慚仙侶，依僧學老翁。',48,'御定全唐詩/json/279.json','["寺涼高樹合，臥石綠陰中。伴鶴慚仙侶，依僧學老翁。", "魚沉荷葉露，鳥散竹林風。始悟塵居者，應將火宅同。"]'),
('yuding-41','春日登樓有懷','盧綸','唐','御定全唐诗','yuding','','[]','花正濃時人正愁，逢花卻欲替花羞。',32,'御定全唐詩/json/279.json','["花正濃時人正愁，逢花卻欲替花羞。", "年來笑伴皆歸去，今日晴明獨上樓。"]'),
('yuding-42','長安春望','盧綸','唐','御定全唐诗','yuding','','[]','東風吹雨過青山，卻望千門草色閑。家在夢中何日到，',40,'御定全唐詩/json/279.json','["東風吹雨過青山，卻望千門草色閑。家在夢中何日到，", "誰念為儒逢世難，獨將衰鬢客秦關。"]'),
('yuding-43','冬日登城樓有懷因贈程騰','盧綸','唐','御定全唐诗','yuding','','[]','生涯何事多羈束，賴此登臨暢心目。郭南郭北無數山，',94,'御定全唐詩/json/279.json','["生涯何事多羈束，賴此登臨暢心目。郭南郭北無數山，", "風聲肅肅雁飛絕，雲色茫茫欲成雪。遙思海客天外歸，", "誰知白首窗下人，不接朱門坐中客。賤亦不足歎，", "如今萬乘方用武，國命天威借貔虎。窮達皆為身外名，"]'),
('yuding-44','過仙游寺','盧綸','唐','御定全唐诗','yuding','','[]','上方下方雪中路，白雲流水如閒步。',32,'御定全唐詩/json/279.json','["上方下方雪中路，白雲流水如閒步。", "數峰行盡猶未歸，寂寞經聲竹陰暮。"]'),
('yuding-45','同路郎中韓侍禦春日題野寺','盧綸','唐','御定全唐诗','yuding','','[]','寺前山遠古陂寬，寺裏人稀春草寒。',32,'御定全唐詩/json/279.json','["寺前山遠古陂寬，寺裏人稀春草寒。", "何事最堪悲色相，折花將與老僧看。"]'),
('yuding-46','奉和李益遊棲岩寺','盧綸','唐','御定全唐诗','yuding','','[]','林香雨氣新，山寺綠無塵。遂結雲外賞，共遊天上春。',72,'御定全唐詩/json/279.json','["林香雨氣新，山寺綠無塵。遂結雲外賞，共遊天上春。", "鶴鳴金闕麗，僧語竹房鄰。待月水流急，惜花風起頻。", "何方非壞境，此地有歸人。回首空門路，皤然一幻身。"]'),
('yuding-47','秋夜同暢當宿潭上西亭','盧綸','唐','御定全唐诗','yuding','','[]','圓月出山頭，七賢林下游。梢梢寒葉墜，灩灩月波流。',48,'御定全唐詩/json/279.json','["圓月出山頭，七賢林下游。梢梢寒葉墜，灩灩月波流。", "鳧鵠共思曉，菰蒲相與秋。明當此中別，一為望汀洲。"]'),
('yuding-48','山中一絕','盧綸','唐','御定全唐诗','yuding','','[]','饑食松花渴飲泉，偶從山后到山前。',32,'御定全唐詩/json/279.json','["饑食松花渴飲泉，偶從山后到山前。", "陽坡軟草厚如織，因與鹿麛相伴眠。"]'),
('yuding-49','與暢當夜泛秋潭','盧綸','唐','御定全唐诗','yuding','','[]','螢火颺蓮叢，水涼多夜風。離人將落葉，俱在一船中。',24,'御定全唐詩/json/279.json','["螢火颺蓮叢，水涼多夜風。離人將落葉，俱在一船中。"]'),
('yuding-50','秋夜宴集陳翃郎中圃亭美校書郎張正元歸鄉','盧綸','唐','御定全唐诗','yuding','','[]','泉清蘭菊稠，紅果落城溝。保慶台榭古，感時琴瑟秋。',48,'御定全唐詩/json/279.json','["泉清蘭菊稠，紅果落城溝。保慶台榭古，感時琴瑟秋。", "碩儒歡頗至，名士禮能周。為謝邑中少，無驚池上鷗。"]'),
('yuding-51','春遊東潭','盧綸','唐','御定全唐诗','yuding','','[]','移舟試望家，漾漾似天涯。日暮滿潭雪，白鷗和柳花。',24,'御定全唐詩/json/279.json','["移舟試望家，漾漾似天涯。日暮滿潭雪，白鷗和柳花。"]'),
('yuding-52','同薛存誠登棲岩寺','盧綸','唐','御定全唐诗','yuding','','[]','衰蹇步難前，上山如上天。塵泥來自晚，猿鶴到何先。',48,'御定全唐詩/json/279.json','["衰蹇步難前，上山如上天。塵泥來自晚，猿鶴到何先。", "萬壑應孤磬，百花通一泉。蒼蒼此明月，下界正沈眠。"]'),
('yuding-53','河中府崇福寺看花','盧綸','唐','御定全唐诗','yuding','','[]','聞道山花如火紅，平明登寺已經風。',32,'御定全唐詩/json/279.json','["聞道山花如火紅，平明登寺已經風。", "老僧無見亦無說，應與看人心不同。"]'),
('yuding-54','冬日宴郭監林亭','盧綸','唐','御定全唐诗','yuding','','[]','玉勒聚如雲，森森鸞鶴群。據梧花罽接，沃盥石泉分。',48,'御定全唐詩/json/279.json','["玉勒聚如雲，森森鸞鶴群。據梧花罽接，沃盥石泉分。", "華味慚初識，新聲喜盡聞。此山招老賤，敢不謝夫君。"]'),
('yuding-55','奉和李舍人昆季詠玫瑰花寄贈徐侍郎','盧綸','唐','御定全唐诗','yuding','','[]','獨鶴寄煙霜，雙鸞思晚芳。舊陰依謝宅，新豔出蕭牆。',96,'御定全唐詩/json/279.json','["獨鶴寄煙霜，雙鸞思晚芳。舊陰依謝宅，新豔出蕭牆。", "蝶散搖輕露，鶯銜入夕陽。雨朝勝濯錦，風夜劇焚香。", "斷日千層豔，孤霞一片光。密來驚葉少，動處覺枝長。", "布影期高賞，留春為遠方。嘗聞贈瓊玖，叨和愧升堂。"]'),
('yuding-56','同耿湋、司空曙二拾遺題韋員外東齋花樹','盧綸','唐','御定全唐诗','yuding','','[]','綠砌紅花樹，狂風獨未吹。光中疑有焰，密處似無枝。',48,'御定全唐詩/json/279.json','["綠砌紅花樹，狂風獨未吹。光中疑有焰，密處似無枝。", "鳥動香輕發，人愁影屢移。今朝數片落，為報漢郎知。"]'),
('yuding-57','觀袁修侍郎漲新池','盧綸','唐','御定全唐诗','yuding','','[]','引水香山近，穿雲複繞林。才聞籬外響，已覺石邊深。',48,'御定全唐詩/json/279.json','["引水香山近，穿雲複繞林。才聞籬外響，已覺石邊深。", "滿處侵苔色，澄來見柳陰。微風月明夜，知有五湖心。"]'),
('yuding-58','和徐法曹贈崔洛陽斑竹杖以詩見答','盧綸','唐','御定全唐诗','yuding','','[]','玉幹一尋餘，苔花錦不如。勁堪和醉倚，輕好向空書。',48,'御定全唐詩/json/279.json','["玉幹一尋餘，苔花錦不如。勁堪和醉倚，輕好向空書。", "采拂稽山曲，因依釋氏居。方辰將獨步，豈與此君疏。"]'),
('yuding-59','早秋望華清宮中樹因以成詠','盧綸','唐','御定全唐诗','yuding','','[]','可憐雲木叢，滿禁碧濛濛。色潤靈泉近，陰清輦路通。',120,'御定全唐詩/json/279.json','["可憐雲木叢，滿禁碧濛濛。色潤靈泉近，陰清輦路通。", "玉壇標八桂，金井識雙桐。交映凝寒露，相和起夜風。", "數枝磐石上，幾葉落雲中。燕拂宜秋霽，蟬鳴覺晝空。", "翠屏更隱見，珠綴共玲瓏。雷雨生成早，樵蘇禁令雄。", "野藤高助綠，仙果迥呈紅。惆悵繚垣暮，茲山聞暗蛩。"]'),
('yuding-60','小魚詠寄涇州楊侍郎','盧綸','唐','御定全唐诗','yuding','','[]','蓮花影裏暫相離，才出浮萍值罟師。',32,'御定全唐詩/json/279.json','["蓮花影裏暫相離，才出浮萍值罟師。", "上得龍門還失浪，九江何處是歸期。"]'),
('yuding-61','賊中與嚴越卿曲江看花','盧綸','唐','御定全唐诗','yuding','','[]','紅枝欲折紫枝殷，隔水連宮不用攀。',32,'御定全唐詩/json/279.json','["紅枝欲折紫枝殷，隔水連宮不用攀。", "會待長風吹落盡，始能開眼向青山。"]'),
('yuding-62','同暢當詠蒲團','盧綸','唐','御定全唐诗','yuding','','[]','團團錦花結，乃是前溪蒲。擁坐稱儒褐，倚眠宜病夫。',36,'御定全唐詩/json/279.json','["團團錦花結，乃是前溪蒲。擁坐稱儒褐，倚眠宜病夫。", "唯當學禪寂，終老與之俱。"]'),
('yuding-63','焦籬店醉題','盧綸','唐','御定全唐诗','yuding','','[]','洛下渠頭百卉新，滿筵歌笑獨傷春。',32,'御定全唐詩/json/279.json','["洛下渠頭百卉新，滿筵歌笑獨傷春。", "何須更弄邵翁伯，即我此身如此人。"]'),
('yuding-64','陳翃中丞東齋賦白玉簪','盧綸','唐','御定全唐诗','yuding','','[]','美矣新成太華峰，翠蓮枝折葉重重。松陰滿澗閑飛鶴，',40,'御定全唐詩/json/279.json','["美矣新成太華峰，翠蓮枝折葉重重。松陰滿澗閑飛鶴，", "因聲遠報浮丘子，不奏登封時不容。"]'),
('yuding-65','新茶詠寄上西川相公二十三舅大夫二十舅','盧綸','唐','御定全唐诗','yuding','','[]','三獻蓬萊始一嘗，日調金鼎閱芳香。',32,'御定全唐詩/json/279.json','["三獻蓬萊始一嘗，日調金鼎閱芳香。", "貯之玉合才半餅，寄與阿連題數行。"]'),
('yuding-66','泊揚子江岸','盧綸','唐','御定全唐诗','yuding','','[]','山映南徐暮，千帆入古津。魚驚出浦火，月照渡江人。',48,'御定全唐詩/json/279.json','["山映南徐暮，千帆入古津。魚驚出浦火，月照渡江人。", "清鏡催雙鬢，滄波寄一身。空憐莎草色，長接故園春。"]'),
('yuding-67','晚次鄂州','盧綸','唐','御定全唐诗','yuding','','[]','雲開遠見漢陽城，猶是孤帆一日程。估客晝眠知浪靜，',40,'御定全唐詩/json/279.json','["雲開遠見漢陽城，猶是孤帆一日程。估客晝眠知浪靜，", "舊業已隨征戰盡，更堪江上鼓鼙聲。"]'),
('yuding-68','夜投豐德寺謁海上人','盧綸','唐','御定全唐诗','yuding','','[]','半夜中峰有磬聲，偶逢樵者問山名。上方月曉聞僧語，',40,'御定全唐詩/json/279.json','["半夜中峰有磬聲，偶逢樵者問山名。上方月曉聞僧語，", "願得遠公知姓字，焚香洗缽過浮生。"]'),
('yuding-69','江行次武昌縣','盧綸','唐','御定全唐诗','yuding','','[]','家寄五湖間，扁舟往復還。年年生白髮，處處上青山。',48,'御定全唐詩/json/279.json','["家寄五湖間，扁舟往復還。年年生白髮，處處上青山。", "去國空知遠，安身竟不閑。更悲江畔柳，長是北人攀。"]'),
('yuding-70','夜泊金陵','盧綸','唐','御定全唐诗','yuding','','[]','圓月出高城，蒼蒼照水營。江中正吹笛，樓上又無更。',48,'御定全唐詩/json/279.json','["圓月出高城，蒼蒼照水營。江中正吹笛，樓上又無更。", "洛下仍傳箭，關西欲進兵。誰知五湖外，諸將但爭名。"]'),
('yuding-71','渡浙江','盧綸','唐','御定全唐诗','yuding','','[]','前船後船未相及，五兩頭平北風急。',32,'御定全唐詩/json/279.json','["前船後船未相及，五兩頭平北風急。", "飛沙卷地日色昏，一半征帆浪花濕。"]'),
('yuding-0','李端公','盧綸','唐','御定全唐诗','yuding','','[]','故關衰草遍，離別自堪悲。路出寒雲外，人歸暮雪時。',48,'御定全唐詩/json/280.json','["故關衰草遍，離別自堪悲。路出寒雲外，人歸暮雪時。", "少孤為客早，多難識君遲。掩淚空相向，風塵何處期。"]'),
('yuding-1','秋晚山中別業','盧綸','唐','御定全唐诗','yuding','','[]','樹老野泉清，幽人好獨行。去閑知路靜，歸晚喜山明。',48,'御定全唐詩/json/280.json','["樹老野泉清，幽人好獨行。去閑知路靜，歸晚喜山明。", "蘭芰通荒井，牛羊出古城。茂陵秋最冷，誰念一書生。"]'),
('yuding-2','關口逢徐邁','盧綸','唐','御定全唐诗','yuding','','[]','廢寺連荒壘，那知見子真。關城夜有雪，冰渡曉無人。',48,'御定全唐詩/json/280.json','["廢寺連荒壘，那知見子真。關城夜有雪，冰渡曉無人。", "酒裏唯多病，山中願作鄰。常聞兄弟樂，誰肯信家貧。"]'),
('yuding-3','山中詠古木','盧綸','唐','御定全唐诗','yuding','','[]','高木已蕭索，夜雨複秋風。墜葉鳴叢竹，斜根擁斷蓬。',48,'御定全唐詩/json/280.json','["高木已蕭索，夜雨複秋風。墜葉鳴叢竹，斜根擁斷蓬。", "半侵山色裏，長在水聲中。此地何人到，雲門去亦通。"]'),
('yuding-4','酬李端公野寺病居見寄','盧綸','唐','御定全唐诗','yuding','','[]','野寺鐘昏山正陰，亂藤高竹水聲深。田夫就餉還依草，',40,'御定全唐詩/json/280.json','["野寺鐘昏山正陰，亂藤高竹水聲深。田夫就餉還依草，", "寂寞日長誰問疾，料君惟取古方尋。"]'),
('yuding-5','送少微上人游蜀','盧綸','唐','御定全唐诗','yuding','','[]','瓶缽繞禪衣，連宵宿翠微。樹開巴水遠，山曉蜀星稀。',48,'御定全唐詩/json/280.json','["瓶缽繞禪衣，連宵宿翠微。樹開巴水遠，山曉蜀星稀。", "識遍中朝貴，多諳外學非。何當一傳付，道侶願知歸。"]'),
('yuding-6','送甯國夏侯丞','盧綸','唐','御定全唐诗','yuding','','[]','楚國青蕪上，秋雲似白波。五湖長路少，九派亂山多。',48,'御定全唐詩/json/280.json','["楚國青蕪上，秋雲似白波。五湖長路少，九派亂山多。", "謝守通詩宴，陶公許醉過。憮然餞離阻，年鬢兩蹉跎。"]'),
('yuding-7','送袁偁','盧綸','唐','御定全唐诗','yuding','','[]','諫獵名空久，多因病與貧。買書行幾市，帶雨別何人。',48,'御定全唐詩/json/280.json','["諫獵名空久，多因病與貧。買書行幾市，帶雨別何人。", "客路山連水，軍州日映塵。淒涼一分手，俱恨老相親。"]'),
('yuding-8','贈別李紛','盧綸','唐','御定全唐诗','yuding','','[]','頭白乘驢懸布囊，一回言別淚千行。',32,'御定全唐詩/json/280.json','["頭白乘驢懸布囊，一回言別淚千行。", "兒孫滿眼無歸處，唯到尊前似故鄉。"]'),
('yuding-9','罪所送苗員外上都','盧綸','唐','御定全唐诗','yuding','','[]','謀身當議罪，甯遣友朋聞。禍近防難及，愁長事未分。',48,'御定全唐詩/json/280.json','["謀身當議罪，甯遣友朋聞。禍近防難及，愁長事未分。", "寂寥驚遠語，幽閉望歸雲。親戚如相見，唯應泣向君。"]'),
('yuding-10','送李校書赴東川幕','盧綸','唐','御定全唐诗','yuding','','[]','泥阪望青城，浮雲與棧平。字形知國號，眉勢識山名。',48,'御定全唐詩/json/280.json','["泥阪望青城，浮雲與棧平。字形知國號，眉勢識山名。", "編簡塵封閣，戈鋋雪照營。男兒須聘用，莫信筆堪耕。"]'),
('yuding-11','至德中贈內兄劉贊','盧綸','唐','御定全唐诗','yuding','','[]','時難訪親戚，相見喜還悲。好學年空在，從戎事已遲。',48,'御定全唐詩/json/280.json','["時難訪親戚，相見喜還悲。好學年空在，從戎事已遲。", "聽琴泉落處，步履雪深時。惆悵多邊信，青山共有期。"]'),
('yuding-12','春日灞亭同苗員外寄皇甫侍禦','盧綸','唐','御定全唐诗','yuding','','[]','坐見春雲暮，無因報所思。川平人去遠，日暖雁飛遲。',48,'御定全唐詩/json/280.json','["坐見春雲暮，無因報所思。川平人去遠，日暖雁飛遲。", "對酒山長在，看花鬢自衰。誰堪登灞岸，還作舊鄉悲。"]'),
('yuding-13','送顏推官游銀夏謁韓大夫','盧綸','唐','御定全唐诗','yuding','','[]','叢篁叫寒笛，滿眼塞山青。才子尊前畫，將軍石上銘。',48,'御定全唐詩/json/280.json','["叢篁叫寒笛，滿眼塞山青。才子尊前畫，將軍石上銘。", "獵聲雲外響，戰血雨中腥。苦樂從來事，因君一涕零。"]'),
('yuding-14','咸陽送房濟侍禦歸太原幕','盧綸','唐','御定全唐诗','yuding','','[]','舊居無舊鄰，似見故鄉春。複對別離酒，欲成衰老人。',48,'御定全唐詩/json/280.json','["舊居無舊鄰，似見故鄉春。複對別離酒，欲成衰老人。", "客衣頻染淚，軍旅亦多塵。握手重相勉，平生心所因。"]'),
('yuding-15','寶泉寺送李益端公歸邠甯幕','盧綸','唐','御定全唐诗','yuding','','[]','參差岩障東，雲日晃龍宮。石淨非因雨，松涼不為風。',72,'御定全唐詩/json/280.json','["參差岩障東，雲日晃龍宮。石淨非因雨，松涼不為風。", "戀泉將鶴並，偷果與猿同。眼界塵雖染，心源蔽已通。", "蓮花國何限，貝葉字無窮。早晚登麟閣，慈門欲付公。"]'),
('yuding-16','送何召下第後歸蜀','盧綸','唐','御定全唐诗','yuding','','[]','褒斜行客過，棧道響危空。路濕雲初上，山明日正中。',48,'御定全唐詩/json/280.json','["褒斜行客過，棧道響危空。路濕雲初上，山明日正中。", "水程通海貨，地利雜吳風。一別金門遠，何人複薦雄。"]'),
('yuding-17','宿定陵寺','盧綸','唐','御定全唐诗','yuding','','[]','古塔荒台出禁牆，磬聲初盡漏聲長。雲生紫殿幡花濕，',40,'御定全唐詩/json/280.json','["古塔荒台出禁牆，磬聲初盡漏聲長。雲生紫殿幡花濕，", "誰悟威靈同寂滅，更堪砧杵發昭陽。"]'),
('yuding-18','送彭開府往雲中覲使君兄','盧綸','唐','御定全唐诗','yuding','','[]','一門三代貴，非是主恩偏。破虜山銘在，承家劍藝全。',72,'御定全唐詩/json/280.json','["一門三代貴，非是主恩偏。破虜山銘在，承家劍藝全。", "奪旗貂帳側，射虎雪林前。雁塞逢兄弟，雲州發管弦。", "凍河光帶日，枯草淨無煙。儒者曾修武，因貽上將篇。"]'),
('yuding-19','送李緗','盧綸','唐','御定全唐诗','yuding','','[]','舊國仍連五將營，儒衣何處謁公卿。波翻遠水蒹葭動，',40,'御定全唐詩/json/280.json','["舊國仍連五將營，儒衣何處謁公卿。波翻遠水蒹葭動，", "為問西來雨中客，空山幾處是前程。"]'),
('yuding-20','送內弟韋宗仁歸信州覲省','盧綸','唐','御定全唐诗','yuding','','[]','常嗟外族弟兄稀，轉覺心孤是送歸。醉掩壺觴人有淚，',40,'御定全唐詩/json/280.json','["常嗟外族弟兄稀，轉覺心孤是送歸。醉掩壺觴人有淚，", "聞說江樓長卷幔，幾回風起望胡威。"]'),
('yuding-21','長安疾後首秋夜即事','盧綸','唐','御定全唐诗','yuding','','[]','九重深鎖禁城秋，月過南宮漸映樓。紫陌夜深槐露滴，',40,'御定全唐詩/json/280.json','["九重深鎖禁城秋，月過南宮漸映樓。紫陌夜深槐露滴，", "楚客病來鄉思苦，寂寥燈下不勝愁。"]'),
('yuding-22','送崔琦赴宣州幕','盧綸','唐','御定全唐诗','yuding','','[]','五馬臨流待幕賓，羨君談笑出風塵。身閑就養寧辭遠，',40,'御定全唐詩/json/280.json','["五馬臨流待幕賓，羨君談笑出風塵。身閑就養寧辭遠，", "何處遙知最惆悵，滿湖青草雁聲春。"]'),
('yuding-23','送楊皞東歸','盧綸','唐','御定全唐诗','yuding','','[]','登樓掩泣話歸期，楚樹荊雲發遠思。日裏揚帆聞戍鼓，',40,'御定全唐詩/json/280.json','["登樓掩泣話歸期，楚樹荊雲發遠思。日裏揚帆聞戍鼓，", "若說湓城楊司馬，知君望國有新詩。"]'),
('yuding-24','至德中途中書事卻寄李僴','盧綸','唐','御定全唐诗','yuding','','[]','亂離無處不傷情，況複看碑對古城。路繞寒山人獨去，',40,'御定全唐詩/json/280.json','["亂離無處不傷情，況複看碑對古城。路繞寒山人獨去，", "今日主人還共醉，應憐世故一儒生。"]'),
('yuding-25','奉和太常王卿酬中書李舍人中書寓直春夜對月見寄','盧綸','唐','御定全唐诗','yuding','','[]','露如輕雨月如霜，不見星河見雁行。虛暈入池波自泛，',40,'御定全唐詩/json/280.json','["露如輕雨月如霜，不見星河見雁行。虛暈入池波自泛，", "是夜巴歌應金石，豈殊螢影對清光。"]'),
('yuding-26','酬包佶郎中覽拙卷後見寄','盧綸','唐','御定全唐诗','yuding','','[]','令伯支離晚讀書，豈知詞賦稱相如。枉逢花木無新思，',40,'御定全唐詩/json/280.json','["令伯支離晚讀書，豈知詞賦稱相如。枉逢花木無新思，", "沉憂敢望金門召，空愧巴歈並子虛。"]'),
('yuding-27','送史寀滑州謁賈僕射','盧綸','唐','御定全唐诗','yuding','','[]','朱門洞啟儼行車，金鐍裝囊半是書。',32,'御定全唐詩/json/280.json','["朱門洞啟儼行車，金鐍裝囊半是書。", "君向東州問徐胤，羊公何事滅吹魚。"]'),
('yuding-28','送鮑中丞赴太原','盧綸','唐','御定全唐诗','yuding','','[]','分路引鳴騶，喧喧似隴頭。暫移西掖望，全解北門憂。',72,'御定全唐詩/json/280.json','["分路引鳴騶，喧喧似隴頭。暫移西掖望，全解北門憂。", "專幕臨都護，分曹制督郵。積冰營不下，盛雪獵方休。", "白草連胡帳，黃雲擁戍樓。今朝送旌旆，一減魯儒羞。"]'),
('yuding-29','送耿拾遺湋充括圖書使往江淮','盧綸','唐','御定全唐诗','yuding','','[]','傳令收遺籍，諸儒喜餞君。孔家唯有地，禹穴但生雲。',48,'御定全唐詩/json/280.json','["傳令收遺籍，諸儒喜餞君。孔家唯有地，禹穴但生雲。", "編簡知還續，蟲魚亦自分。如逢北山隱，一為謝移文。"]'),
('yuding-30','送郭判官赴振武','盧綸','唐','御定全唐诗','yuding','','[]','黃河九曲流，繚繞古邊州。鳴雁飛初夜，羌胡正晚秋。',48,'御定全唐詩/json/280.json','["黃河九曲流，繚繞古邊州。鳴雁飛初夜，羌胡正晚秋。", "淒涼金管思，迢遞玉人愁。七葉推多慶，須懷殺敵憂。"]'),
('yuding-31','春江夕望','盧綸','唐','御定全唐诗','yuding','','[]','洞庭芳草遍，楚客莫思歸。經難人空老，逢春雁自飛。',48,'御定全唐詩/json/280.json','["洞庭芳草遍，楚客莫思歸。經難人空老，逢春雁自飛。", "東西兄弟遠，存沒友朋稀。獨立還垂淚，天南一布衣。"]'),
('yuding-32','送元昱尉義興','盧綸','唐','御定全唐诗','yuding','','[]','欲成雲海別，一夜夢天涯。白浪緣江雨，青山繞縣花。',48,'御定全唐詩/json/280.json','["欲成雲海別，一夜夢天涯。白浪緣江雨，青山繞縣花。", "風標當劇部，冠帶稱儒家。去矣謝親愛，知予發已華。"]'),
('yuding-33','送黎兵曹往陝府結親','盧綸','唐','御定全唐诗','yuding','','[]','郎馬兩如龍，春朝上路逢。鴛鴦初集水，薜荔欲依松。',48,'御定全唐詩/json/280.json','["郎馬兩如龍，春朝上路逢。鴛鴦初集水，薜荔欲依松。", "步帳歌聲轉，妝台燭影重。何言在陰者，得是戴侯宗。"]'),
('yuding-34','送樂平苗明府','盧綸','唐','御定全唐诗','yuding','','[]','累職比柴桑，清秋入楚鄉。一船燈照浪，兩岸樹凝霜。',48,'御定全唐詩/json/280.json','["累職比柴桑，清秋入楚鄉。一船燈照浪，兩岸樹凝霜。", "亭吏趨寒霧，山城斂曙光。無辭折腰久，仲德在鴛行。"]'),
('yuding-35','晚到盩厔耆老家','盧綸','唐','御定全唐诗','yuding','','[]','老翁曾舊識，相引出柴門。苦話別時事，因尋溪上村。',72,'御定全唐詩/json/280.json','["老翁曾舊識，相引出柴門。苦話別時事，因尋溪上村。", "數年何處客，近日幾家存。冒雨看禾黍，逢人憶子孫。", "亂藤穿井口，流水到籬根。惆悵不堪住，空山月又昏。"]'),
('yuding-36','臥病書懷','盧綸','唐','御定全唐诗','yuding','','[]','苦心三十載，白首遇艱難。舊地成孤客，全家賴釣竿。',48,'御定全唐詩/json/280.json','["苦心三十載，白首遇艱難。舊地成孤客，全家賴釣竿。", "貌衰緣藥盡，起晚為山寒。老病今如此，無人更問看。"]'),
('yuding-37','落第後歸終南別業','盧綸','唐','御定全唐诗','yuding','','[]','久為名所誤，春盡始歸山。落羽羞言命，逢人強破顏。',48,'御定全唐詩/json/280.json','["久為名所誤，春盡始歸山。落羽羞言命，逢人強破顏。", "交疏貧病裏，身老是非間。不及東溪月，漁翁夜往還。"]'),
('yuding-38','送朝邑張明府','盧綸','唐','御定全唐诗','yuding','','[]','千室暮山西，浮雲與樹齊。剖辭雲落紙，擁吏雪成泥。',48,'御定全唐詩/json/280.json','["千室暮山西，浮雲與樹齊。剖辭雲落紙，擁吏雪成泥。", "野火蘆千頃，河田水萬畦。不知琴月夜，誰得聽烏啼。"]'),
('yuding-39','送李方東歸','盧綸','唐','御定全唐诗','yuding','','[]','故交三四人，聞別共沾巾。舉目是陳事，滿城無至親。',48,'御定全唐詩/json/280.json','["故交三四人，聞別共沾巾。舉目是陳事，滿城無至親。", "身從喪日病，家自儉年貧。此去何堪遠，遺孤在舊鄰。"]'),
('yuding-40','秋晚霽後野望憶夏侯審','盧綸','唐','御定全唐诗','yuding','','[]','天晴禾黍平，暢目亦傷情。野店雲日麗，孤莊砧杵鳴。',48,'御定全唐詩/json/280.json','["天晴禾黍平，暢目亦傷情。野店雲日麗，孤莊砧杵鳴。", "川原唯寂寞，岐路自縱橫。前後無儔侶，此懷誰與呈。"]'),
('yuding-41','送王尊師','盧綸','唐','御定全唐诗','yuding','','[]','夢別一仙人，霞衣滿鶴身。旌幢天路晚，桃杏海山春。',48,'御定全唐詩/json/280.json','["夢別一仙人，霞衣滿鶴身。旌幢天路晚，桃杏海山春。", "種玉非求稔，燒金不為貧。自憐頭白早，難與葛洪親。"]'),
('yuding-42','送撫州周使君','盧綸','唐','御定全唐诗','yuding','','[]','周郎三十餘，天子賜魚書。龍節隨雲水，金鐃動裏閭。',48,'御定全唐詩/json/280.json','["周郎三十餘，天子賜魚書。龍節隨雲水，金鐃動裏閭。", "松聲三楚遠，鄉思百花初。若轉弘農守，蕭咸事不如。"]'),
('yuding-43','贈別司空曙','盧綸','唐','御定全唐诗','yuding','','[]','有月曾同賞，無秋不共悲。如何與君別，又是菊花時。',24,'御定全唐詩/json/280.json','["有月曾同賞，無秋不共悲。如何與君別，又是菊花時。"]'),
('yuding-44','送王錄事赴任蘇州','盧綸','唐','御定全唐诗','yuding','','[]','古堤迎拜路，萬里一帆前。潮作澆田雨，雲成煮海煙。',48,'御定全唐詩/json/280.json','["古堤迎拜路，萬里一帆前。潮作澆田雨，雲成煮海煙。", "吏閑唯重法，俗富不憂邊。西掖今宵詠，還應寄阿連。"]'),
('yuding-45','大梵山寺院奉呈趣上人趙中丞','盧綸','唐','御定全唐诗','yuding','','[]','漸欲休人事，僧房學閉關。伴魚浮水上，看鶴向林間。',48,'御定全唐詩/json/280.json','["漸欲休人事，僧房學閉關。伴魚浮水上，看鶴向林間。", "寺古秋仍早，松深暮更閑。月中隨道友，夜夜坐空山。"]'),
('yuding-46','送恒操上人歸江外覲省','盧綸','唐','御定全唐诗','yuding','','[]','依佛不違親，高堂與寺鄰。問安雙樹曉，求膳一僧貧。',48,'御定全唐詩/json/280.json','["依佛不違親，高堂與寺鄰。問安雙樹曉，求膳一僧貧。", "持咒過龍廟，翻經化海人。還同惠休去，儒者亦沾巾。"]'),
('yuding-47','上巳日陪齊相公花樓宴','盧綸','唐','御定全唐诗','yuding','','[]','鐘陵暮春月，飛觀延群英。晨霞耀中軒，滿席羅金瓊。',72,'御定全唐詩/json/280.json','["鐘陵暮春月，飛觀延群英。晨霞耀中軒，滿席羅金瓊。", "持杯凝遠睇，觸物結幽情。樹色參差綠，湖光瀲灩明。", "禮卑瞻絳帳，恩浹廁華纓。徒記山陰興，祓禊乃為榮。"]'),
('yuding-48','寒食','盧綸','唐','御定全唐诗','yuding','','[]','孤客飄飄歲載華，況逢寒食倍思家。鶯啼遠墅多從柳，',40,'御定全唐詩/json/280.json','["孤客飄飄歲載華，況逢寒食倍思家。鶯啼遠墅多從柳，", "驅車西近長安好，宮觀參差半隱霞。"]'),
('yuding-49','舟中寒食','盧綸','唐','御定全唐诗','yuding','','[]','寒食空江曲，孤舟渺水前。鬥雞沙鳥異，禁火岸花然。',48,'御定全唐詩/json/280.json','["寒食空江曲，孤舟渺水前。鬥雞沙鳥異，禁火岸花然。", "日霽開愁望，波喧警醉眠。因看數莖鬢，倍欲惜芳年。"]'),
('yuding-50','元日早朝呈故省諸公','盧綸','唐','御定全唐诗','yuding','','[]','萬戟淩霜布，森森瑞氣間。垂衣當曉日，上壽對南山。',48,'御定全唐詩/json/280.json','["萬戟淩霜布，森森瑞氣間。垂衣當曉日，上壽對南山。", "濟濟延多士，躚躚舞百蠻。小臣無事諫，空愧伴鳴環。"]'),
('yuding-51','元日朝回中夜書情，寄南宮二故人','盧綸','唐','御定全唐诗','yuding','','[]','鳴佩隨鵷鷺，登階見冕旒。無能裨聖代，何事別滄洲。',48,'御定全唐詩/json/280.json','["鳴佩隨鵷鷺，登階見冕旒。無能裨聖代，何事別滄洲。", "閑夜貧還醉，浮名老漸羞。鳳城春欲晚，郎吏憶同遊。"]'),
('yuding-52','裴給事宅白牡丹','盧綸','唐','御定全唐诗','yuding','','[]','長安豪貴惜春殘，爭玩街西紫牡丹。',32,'御定全唐詩/json/280.json','["長安豪貴惜春殘，爭玩街西紫牡丹。", "別有玉盤承露冷，無人起就月中看。"]'),
('yuding-53','送韋判官得雨中山','盧綸','唐','御定全唐诗','yuding','','[]','前峰後嶺碧濛濛，草擁驚泉樹帶風。',32,'御定全唐詩/json/280.json','["前峰後嶺碧濛濛，草擁驚泉樹帶風。", "人語馬嘶聽不得，更堪長路在雲中。"]'),
('yuding-54','送宛丘任少府','盧綸','唐','御定全唐诗','yuding','','[]','帶綬別鄉親，東為千里人。俗訛唯競祭，地古不留春。',48,'御定全唐詩/json/280.json','["帶綬別鄉親，東為千里人。俗訛唯競祭，地古不留春。", "野戍雲藏火，軍城樹擁塵。少年何所重，才子又清貧。"]'),
('yuding-55','送永陽崔明府','盧綸','唐','御定全唐诗','yuding','','[]','鶴唳蒹葭曉，中流見楚城。浪清風乍息，山白月猶明。',48,'御定全唐詩/json/280.json','["鶴唳蒹葭曉，中流見楚城。浪清風乍息，山白月猶明。", "廢路開荒木，歸人種古營。懸聞正訛俗，邴曼更知名。"]'),
('yuding-56','割飛二刀子歌','盧綸','唐','御定全唐诗','yuding','','[]','我家有翦刀，人雲鬼國鐵。裁羅裁綺無鈍時，',84,'御定全唐詩/json/280.json','["我家有翦刀，人雲鬼國鐵。裁羅裁綺無鈍時，", "改鍛割飛二刀子，色迎霽雪鋒含霜。兩條神物秋冰薄，", "日試曾磨漢水邊，掌中恄栗聲冷然。神驚魄悸卻收得，", "若非良工變爾形，只向裁縫委箱篋。"]'),
('yuding-57','送郎士元使君赴郢州','盧綸','唐','御定全唐诗','yuding','','[]','賜衣兼授節，行日郢中聞。花發登山廟，天晴閱水軍。',48,'御定全唐詩/json/280.json','["賜衣兼授節，行日郢中聞。花發登山廟，天晴閱水軍。", "漁商三楚接，郡邑九江分。高興應難遂，元戎有大勳。"]'),
('yuding-58','春詞','盧綸','唐','御定全唐诗','yuding','','[]','北苑羅裙帶，塵衢錦繡鞋。醉眠芳樹下，半被落花埋。',24,'御定全唐詩/json/280.json','["北苑羅裙帶，塵衢錦繡鞋。醉眠芳樹下，半被落花埋。"]'),
('yuding-59','清如玉壺冰','盧綸','唐','御定全唐诗','yuding','','[]','玉壺冰始結，循吏政初成。既有虛心鑒，還如照膽清。',72,'御定全唐詩/json/280.json','["玉壺冰始結，循吏政初成。既有虛心鑒，還如照膽清。", "瑤池慚洞澈，金鏡讓澄明。氣若朝霜動，形隨夜月盈。", "臨人能不蔽，待物本無情。怯對圓光裏，妍蚩自此呈。"]'),
('yuding-60','山店','盧綸','唐','御定全唐诗','yuding','','[]','登登山路行時盡，決決溪泉到處聞。',32,'御定全唐詩/json/280.json','["登登山路行時盡，決決溪泉到處聞。", "風動葉聲山犬吠，一家松火隔秋雲。"]'),
('yuding-0','長至日上公獻壽','崔琮','唐','御定全唐诗','yuding','','[]','應律三陽首，朝天萬國同。鬥邊看子月，臺上候祥風。',72,'御定全唐詩/json/281.json','["應律三陽首，朝天萬國同。鬥邊看子月，臺上候祥風。", "五夜鐘初動，千門日正融。玉階文物盛，仙仗武貔雄。", "率舞皆群辟，稱觴即上公。南山為聖壽，長對未央宮。"]'),
('yuding-1','長至日上公獻壽','李竦','唐','御定全唐诗','yuding','','[]','候曉金門辟，乘時玉曆長。羽儀瞻上宰，雲物麗初陽。',72,'御定全唐詩/json/281.json','["候曉金門辟，乘時玉曆長。羽儀瞻上宰，雲物麗初陽。", "漢禮方傳佩，堯年正捧觴。日行臨觀闕，帝錫洽珪璋。", "盛美超三代，洪休降百祥。自憐朝末坐，空此詠無疆。"]'),
('yuding-2','賦得西戎獻白玉環','張惟儉','唐','御定全唐诗','yuding','','[]','當時無外守，方物四夷通。列土金河北，朝天玉塞東。',72,'御定全唐詩/json/281.json','["當時無外守，方物四夷通。列土金河北，朝天玉塞東。", "自將荊璞比，不與鄭環同。正朔雖傳漢，衣冠尚帶戎。", "幸承提佩寵，多愧琢磨功。絕域知文教，爭趨上國風。"]'),
('yuding-3','新安江行','章八元','唐','御定全唐诗','yuding','','[]','江源南去永，野渡暫維梢。古戍懸魚網，空林露鳥巢。',48,'御定全唐詩/json/281.json','["江源南去永，野渡暫維梢。古戍懸魚網，空林露鳥巢。", "雪晴山脊見，沙淺浪痕交。自笑無媒者，逢人作解嘲。"]'),
('yuding-4','酬劉員外月下見寄','章八元','唐','御定全唐诗','yuding','','[]','夜涼河漢白，卷箔出南軒。過月鴻爭遠，辭枝葉暗翻。',48,'御定全唐詩/json/281.json','["夜涼河漢白，卷箔出南軒。過月鴻爭遠，辭枝葉暗翻。", "獨謠聞麗曲，緩步接清言。宣室思前席，行看拜主恩。"]'),
('yuding-5','寄都官劉員外','章八元','唐','御定全唐诗','yuding','','[]','舊宅平津邸，槐陰接漢宮。鳴騶馳道上，寒日直廬中。',48,'御定全唐詩/json/281.json','["舊宅平津邸，槐陰接漢宮。鳴騶馳道上，寒日直廬中。", "白雪歌偏麗，青雲宦早通。悠然一縫掖，千里限清風。"]'),
('yuding-6','題慈恩寺塔','章八元','唐','御定全唐诗','yuding','','[]','十層突兀在虛空，四十門開面面風。卻怪鳥飛平地上，',40,'御定全唐詩/json/281.json','["十層突兀在虛空，四十門開面面風。卻怪鳥飛平地上，", "落日鳳城佳氣合，滿城春樹雨濛濛。"]'),
('yuding-7','歸桐廬舊居寄嚴長史','章八元','唐','御定全唐诗','yuding','','[]','昨辭夫子棹歸舟，家在桐廬憶舊丘。三月暖時花競發，',40,'御定全唐詩/json/281.json','["昨辭夫子棹歸舟，家在桐廬憶舊丘。三月暖時花競發，", "或在醉中逢夜雪，懷賢應向剡川遊。"]'),
('yuding-8','天臺道中示同行','章八元','唐','御定全唐诗','yuding','','[]','八重岩崿疊晴空，九色煙霞繞洞宮。',32,'御定全唐詩/json/281.json','["八重岩崿疊晴空，九色煙霞繞洞宮。", "仙道多因迷路得，莫將心事問樵翁。"]'),
('yuding-9','元日望含元殿禦扇開合','張莒','唐','御定全唐诗','yuding','','[]','萬國來朝歲，千年覲聖君。輦迎仙仗出，扇匝禦香焚。',72,'御定全唐詩/json/281.json','["萬國來朝歲，千年覲聖君。輦迎仙仗出，扇匝禦香焚。", "俯對朝容近，先知曙色分。冕旒開處見，鐘磬合時聞。", "影動承朝日，花攢似慶雲。蒲葵那可比，徒用隔炎氛。"]'),
('yuding-10','清明日賜百僚新火','史延','唐','御定全唐诗','yuding','','[]','上苑連侯第，清明及暮春。九天初改火，萬井屬良辰。',72,'御定全唐詩/json/281.json','["上苑連侯第，清明及暮春。九天初改火，萬井屬良辰。", "頒賜恩逾洽，承時慶自均。翠煙和柳嫩，紅焰出花新。", "寵命尊三老，祥光燭萬人。太平當此日，空複荷陶甄。"]'),
('yuding-11','清明日賜百僚新火','韓浚','唐','御定全唐诗','yuding','','[]','朱騎傳紅燭，天廚賜近臣。火隨黃道見，煙繞白榆新。',72,'御定全唐詩/json/281.json','["朱騎傳紅燭，天廚賜近臣。火隨黃道見，煙繞白榆新。", "榮耀分他日，恩光共此辰。更調金鼎膳，還暖玉堂人。", "灼灼千門曉，輝輝萬井春。應憐螢聚夜，瞻望及東鄰。"]'),
('yuding-12','清明日賜百僚新火','鄭轅','唐','御定全唐诗','yuding','','[]','改火清明後，優恩賜近臣。漏殘丹禁晚，燧發白榆新。',72,'御定全唐詩/json/281.json','["改火清明後，優恩賜近臣。漏殘丹禁晚，燧發白榆新。", "瑞彩來雙闕，神光煥四鄰。氣回侯第暖，煙散帝城春。", "利用調羹鼎，餘輝燭縉紳。皇明如照隱，願及聚螢人。"]'),
('yuding-13','清明日賜百僚新火','王濯','唐','御定全唐诗','yuding','','[]','禦火傳香殿，華光及侍臣。星流中使馬，燭耀九衢人。',72,'御定全唐詩/json/281.json','["禦火傳香殿，華光及侍臣。星流中使馬，燭耀九衢人。", "轉影連金屋，分輝麗錦茵。焰迎紅蕊發，煙染綠條春。", "助律和風早，添爐暖氣新。誰憐一寒士，猶望照東鄰。"]'),
('yuding-14','投珠於泉','獨孤綬','唐','御定全唐诗','yuding','','[]','至道歸淳樸，明珠被棄捐。天真來照乘，成性卻沈泉。',72,'御定全唐詩/json/281.json','["至道歸淳樸，明珠被棄捐。天真來照乘，成性卻沈泉。", "不是靈蛇吐，非緣合浦還。岸傍隨月落，波底共星懸。", "致遠終無脛，懷貪遂息肩。欲知恭儉德，所寶在惟賢。"]'),
('yuding-15','秦鏡','仲子陵','唐','御定全唐诗','yuding','','[]','萬古秦時鏡，從來抱至精。依台月自吐，在匣水常清。',72,'御定全唐詩/json/281.json','["萬古秦時鏡，從來抱至精。依台月自吐，在匣水常清。", "爛爛金光發，澄澄物象生。雲天皆洞鑒，表裏盡虛明。", "但見人窺膽，全勝回應聲。妍媸定可識，何處更逃情。"]'),
('yuding-16','秦鏡','張佐','唐','御定全唐诗','yuding','','[]','樓上秦時鏡，千秋獨有名。菱花寒不落，冰質夏長清。',72,'御定全唐詩/json/281.json','["樓上秦時鏡，千秋獨有名。菱花寒不落，冰質夏長清。", "龍在形難掩，人來膽易呈。升台宜遠照，開匣乍藏明。", "皎色新磨出，圓規舊鑄成。愁容如可鑒，當欲拂塵纓。"]'),
('yuding-17','憶遊天臺寄道流','張佐','唐','御定全唐诗','yuding','','[]','憶昨天台到赤城，幾朝仙籟耳中生。雲龍出水風聲急，',40,'御定全唐詩/json/281.json','["憶昨天台到赤城，幾朝仙籟耳中生。雲龍出水風聲急，", "今來儘是人間夢，劉阮茫茫何處行。"]'),
('yuding-18','龜負圖','丁澤','唐','御定全唐诗','yuding','','[]','天意將垂象，神龜出負圖。五方行有配，八卦義寧孤。',72,'御定全唐詩/json/281.json','["天意將垂象，神龜出負圖。五方行有配，八卦義寧孤。", "作瑞旌君德，披文協帝謨。乘流喜得路，逢聖倖存軀。", "蓮葉池通泛，桃花水自浮。還尋九江去，安肯曳泥途。"]'),
('yuding-19','上元日夢王母獻白玉環','丁澤','唐','御定全唐诗','yuding','','[]','夢中朝上日，闕下拜天顏。仿佛瞻王母，分明獻玉環。',72,'御定全唐詩/json/281.json','["夢中朝上日，闕下拜天顏。仿佛瞻王母，分明獻玉環。", "靈姿趨甲帳，悟道契玄關。似見霜姿白，如看月彩彎。", "霓裳歸物外，鳳曆曉人寰。仙聖非相遠，昭昭寤寐間。"]'),
('yuding-20','良田無晚歲','丁澤','唐','御定全唐诗','yuding','','[]','人功雖未及，地力信非常。不任耕耘早，偏宜黍稷良。',72,'御定全唐詩/json/281.json','["人功雖未及，地力信非常。不任耕耘早，偏宜黍稷良。", "無年皆有獲，後種亦先芳。膴膴盈千畝，青青保萬箱。", "何須祭田祖，詎要察農祥。況是春三月，和風日又長。"]'),
('yuding-21','下第獻座主張謂','閻濟美','唐','御定全唐诗','yuding','','[]','謇諤王臣直，文明雅量全。望爐金自躍，應物鏡何偏。',72,'御定全唐詩/json/281.json','["謇諤王臣直，文明雅量全。望爐金自躍，應物鏡何偏。", "南國幽沉盡，東堂禮樂宣。轉令遊藝士，更惜至公年。", "芳樹歡新景，青雲泣暮天。唯愁鳳池拜，孤賤更誰憐。"]'),
('yuding-22','天津橋望洛城殘雪','閻濟美','唐','御定全唐诗','yuding','','[]','新霽洛城端，千家積雪寒。未收清禁色，偏向上陽殘。',24,'御定全唐詩/json/281.json','["新霽洛城端，千家積雪寒。未收清禁色，偏向上陽殘。"]'),
('yuding-23','尚書郎上直聞春漏','張少博','唐','御定全唐诗','yuding','','[]','建禮含香處，重城待漏辰。徐聲傳鳳闕，曉唱辨雞人。',72,'御定全唐詩/json/281.json','["建禮含香處，重城待漏辰。徐聲傳鳳闕，曉唱辨雞人。", "銀箭聽將盡，銅壺滴更新。催籌當五夜，移刻及三春。", "杳杳從天遠，泠泠出禁頻。直廬殘響曙，肅穆對鉤陳。"]'),
('yuding-24','雪夜觀象闕待漏','張少博','唐','御定全唐诗','yuding','','[]','殘雪初晴後，鳴珂奉闕庭。九門傳曉漏，五夜候晨扃。',72,'御定全唐詩/json/281.json','["殘雪初晴後，鳴珂奉闕庭。九門傳曉漏，五夜候晨扃。", "北斗橫斜漢，東方落曙星。煙氛初動色，簪佩未分形。", "雪重猶垂白，山遙不辨青。雞人更唱處，偏入此時聽。"]'),
('yuding-25','尚書郎上直聞春漏','周徹','唐','御定全唐诗','yuding','','[]','建禮通華省，含香直紫宸。靜聞銅史漏，暗識桂宮春。',72,'御定全唐詩/json/281.json','["建禮通華省，含香直紫宸。靜聞銅史漏，暗識桂宮春。", "滴瀝疑將絕，清泠發更新。寒聲臨雁沼，疏韻應雞人。", "迥入千門徹，行催五夜頻。高臺閑自聽，非是駐征輪。"]'),
('yuding-26','及第後贈試官','高拯','唐','御定全唐诗','yuding','','[]','公子求賢未識真，欲將毛遂比常倫。',32,'御定全唐詩/json/281.json','["公子求賢未識真，欲將毛遂比常倫。", "當時不及三千客，今日何如十九人。"]'),
('yuding-27','賦得花發上林','王表','唐','御定全唐诗','yuding','','[]','御苑春何早，繁花已繡林。笑迎明主仗，香拂美人簪。',72,'御定全唐詩/json/281.json','["御苑春何早，繁花已繡林。笑迎明主仗，香拂美人簪。", "地接樓臺近，天垂雨露深。晴光來戲蝶，夕景動棲禽。", "欲托淩雲勢，先開捧日心。方知桃李樹，從此別成陰。"]'),
('yuding-28','清明日登城春望寄大夫使君','王表','唐','御定全唐诗','yuding','','[]','春城閑望愛晴天，何處風光不眼前。寒食花開千樹雪，',40,'御定全唐詩/json/281.json','["春城閑望愛晴天，何處風光不眼前。寒食花開千樹雪，", "聞說鶯啼卻惆悵，詩成不見謝臨川。"]'),
('yuding-29','成德樂','王表','唐','御定全唐诗','yuding','','[]','趙女乘春上畫樓，一聲歌發滿城秋。',32,'御定全唐詩/json/281.json','["趙女乘春上畫樓，一聲歌發滿城秋。", "無端更唱關山曲，不是征人亦淚流。"]'),
('yuding-30','花發上林','獨孤授','唐','御定全唐诗','yuding','','[]','上苑韶容早，芳菲正吐花。無言向春日，閑笑任年華。',72,'御定全唐詩/json/281.json','["上苑韶容早，芳菲正吐花。無言向春日，閑笑任年華。", "潤色籠輕靄，晴光豔晚霞。影連千戶竹，香散萬人家。", "幸繞樓臺近，仍懷雨露賒。願君垂採摘，不使落風沙。"]'),
('yuding-31','賦得花發上林','王儲','唐','御定全唐诗','yuding','','[]','東陸和風至，先開上苑花。穠枝藏宿鳥，香蕊拂行車。',72,'御定全唐詩/json/281.json','["東陸和風至，先開上苑花。穠枝藏宿鳥，香蕊拂行車。", "散白憐晴日，舒紅愛晚霞。桃間留禦馬，梅處入胡笳。", "城郭連增媚，樓臺映轉華。豈同幽谷草，春至發猶賒。"]'),
('yuding-32','賦得花發上林','周渭','唐','御定全唐诗','yuding','','[]','灼灼花凝雪，春來發上林。向風初散蕊，垂葉欲成陰。',72,'御定全唐詩/json/281.json','["灼灼花凝雪，春來發上林。向風初散蕊，垂葉欲成陰。", "人過香隨遠，煙晴色自深。淨時空結霧，疏處未藏禽。", "菶茸何年值，間關幾日吟。一枝如可冀，不負折芳心。"]'),
('yuding-33','贈龍興觀主吳崇岳','周渭','唐','御定全唐诗','yuding','','[]','楮為冠子布為裳，吞得丹霞壽最長。混俗性靈常樂道，',40,'御定全唐詩/json/281.json','["楮為冠子布為裳，吞得丹霞壽最長。混俗性靈常樂道，", "百尺松梢幾飛步，鶴棲板上禮虛皇。"]'),
('yuding-0','從軍有苦樂行','李益','唐','御定全唐诗','yuding','','[]','勞者且莫歌，我欲送君觴。從軍有苦樂，此曲樂未央。',216,'御定全唐詩/json/282.json','["勞者且莫歌，我欲送君觴。從軍有苦樂，此曲樂未央。", "僕居在隴上，隴水斷人腸。東過秦宮路，宮路入咸陽。", "時逢漢帝出，諫獵至長楊。詎馳遊俠窟，非結少年場。", "一旦承嘉惠，輕身重恩光。秉筆參帷帟，從軍至朔方。", "邊地多陰風，草木自淒涼。斷絕海雲去，出沒胡沙長。", "參差引雁翼，隱轔騰軍裝。劍文夜如水，馬汗凍成霜。", "俠氣五都少，矜功六郡良。山河起目前，睚眥死路傍。", "北逐驅獯虜，西臨復舊疆。昔還賦餘資，今出乃贏糧。", "一矢弢夏服，我弓不再張。寄語丈夫雄，若樂身自當。"]'),
('yuding-1','登長城','李益','唐','御定全唐诗','yuding','','[]','漢家今上郡，秦塞古長城。有日雲長慘，無風沙自驚。',36,'御定全唐詩/json/282.json','["漢家今上郡，秦塞古長城。有日雲長慘，無風沙自驚。", "當今聖天子，不戰四夷平。"]'),
('yuding-2','雜曲','李益','唐','御定全唐诗','yuding','','[]','妾本蠶家女，不識貴門儀。槁砧持玉斧，交結五陵兒。',348,'御定全唐詩/json/282.json','["妾本蠶家女，不識貴門儀。槁砧持玉斧，交結五陵兒。", "十日或一見，九日在路岐。人生此夫婿，富貴欲何為。", "楊柳徒可折，南山不可移。婦人貴結髮，寧有再嫁資。", "嫁女莫望高，女心願所宜。寧從賤相守，不願貴相離。", "藍葉郁重重，藍花若榴色。少婦歸少年，華光自相得。", "誰言配君子，以奉百年身。有義即夫婿，無義還他人。", "愛如寒爐火，棄若秋風扇。山嶽起面前，相看不相見。", "丈夫非小兒，何用強相知。不見朝生菌，易成還易衰。", "征客欲臨路，居人還出門。北風河梁上，四野愁雲繁。", "豈不戀我家，夫婿多感恩。前程有日月，勳績在河源。", "少婦馬前立，請君聽一言。春至草亦生，誰能無別情。", "殷勤展心素，見新莫忘故。遙望孟門山，殷勤報君子。", "既為隨陽雁，勿學西流水。嘗聞生別離，悲莫悲於此。", "同器不同榮，堂下即千里。與君貧賤交，何異萍上水。", "托身天使然，同生複同死。"]'),
('yuding-3','送遼陽使還軍','李益','唐','御定全唐诗','yuding','','[]','征人歌且行，北上遼陽城。二月戎馬息，悠悠邊草生。',72,'御定全唐詩/json/282.json','["征人歌且行，北上遼陽城。二月戎馬息，悠悠邊草生。", "青山出塞斷，代地入雲平。昔者匈奴戰，多聞殺漢兵。", "平生報國憤，日夜角弓鳴。勉君萬里去，勿使虜塵驚。"]'),
('yuding-4','賦得早燕送別','李益','唐','御定全唐诗','yuding','','[]','碧草縵如線，去來雙飛燕。長門未有春，先入班姬殿。',60,'御定全唐詩/json/282.json','["碧草縵如線，去來雙飛燕。長門未有春，先入班姬殿。", "梁空繞不息，簷寒窺欲遍。今至隨紅萼，昔還悲素扇。", "一別與秋鴻，差池詎相見。"]'),
('yuding-5','秋晚溪中寄懷大理齊司直','李益','唐','御定全唐诗','yuding','','[]','鳳翔屬明代，羽翼文葳蕤。昆侖進琪樹，飛舞下瑤池。',120,'御定全唐詩/json/282.json','["鳳翔屬明代，羽翼文葳蕤。昆侖進琪樹，飛舞下瑤池。", "振儀自西眷，東夏複分厘。國典唯平法，伊人方在斯。", "荒甯桁楊肅，芳輝蘭玉滋。明質鶩高景，飄颻服纓綏。", "天寒清洛苑，秋夕白雲司。況複空岩側，蒼蒼幽桂期。", "歲寒坐流霰，山川猶別離。浩思憑尊酒，氛氳獨含辭。"]'),
('yuding-6','溪中月下寄楊子尉封亮','李益','唐','御定全唐诗','yuding','','[]','蘅若奪幽色，銜思恍無悰。宵長霜霧多，歲晏淮海風。',96,'御定全唐詩/json/282.json','["蘅若奪幽色，銜思恍無悰。宵長霜霧多，歲晏淮海風。", "團團山中月，三五離夕同。露凝朱弦絕，觴至蘭玉空。", "清光液流波，盛明難再逢。嘗恐河漢遠，坐窺煙景窮。", "小人諒處陰，君子樹大功。永願厲高翼，慰我丹桂叢。"]'),
('yuding-7','春晚賦得餘花落','李益','唐','御定全唐诗','yuding','','[]','留春春竟去，春去花如此。蝶舞繞應稀，鳥驚飛詎已。',48,'御定全唐詩/json/282.json','["留春春竟去，春去花如此。蝶舞繞應稀，鳥驚飛詎已。", "衰紅辭故萼，繁綠扶雕蕊。自委不勝愁，庭風那更起。"]'),
('yuding-8','聞亡友王七嘉禾寺得素琴','李益','唐','御定全唐诗','yuding','','[]','故人惜此去，留琴明月前。今來我訪舊，淚灑白雲天。',60,'御定全唐詩/json/282.json','["故人惜此去，留琴明月前。今來我訪舊，淚灑白雲天。", "詎欲匣孤響，送君歸夜泉。撫琴猶可絕，況此故無弦。", "何必雍門奏，然後淚潺湲。"]'),
('yuding-9','校書郎楊凝往年以古鏡貺別今追贈以詩','李益','唐','御定全唐诗','yuding','','[]','明鏡出匣時，明如雲間月。一別青春鑒，回光照華髮。',48,'御定全唐詩/json/282.json','["明鏡出匣時，明如雲間月。一別青春鑒，回光照華髮。", "美人昔自愛，鞶帶手中結。願以三五期，經天無玷缺。"]'),
('yuding-10','置酒行','李益','唐','御定全唐诗','yuding','','[]','置酒命所歡，憑觴遂為戚。日往不再來，茲辰坐成昔。',96,'御定全唐詩/json/282.json','["置酒命所歡，憑觴遂為戚。日往不再來，茲辰坐成昔。", "百齡非久長，五十將半百。胡為勞我形，己須還複白。", "西山鸞鶴群，矯矯煙霧翮。明霞發金丹，陰洞潛水碧。", "安得淩風羽，崦嵫駐靈魄。無然坐衰老，慚歎東陵柏。"]'),
('yuding-11','長社竇明府宅夜送王屋道士常究子','李益','唐','御定全唐诗','yuding','','[]','旦隨三鳥去，羽節淩霞光。暮與雙鳧宿，雲車下紫陽。',48,'御定全唐詩/json/282.json','["旦隨三鳥去，羽節淩霞光。暮與雙鳧宿，雲車下紫陽。", "天壇臨月近，洞水出山長。海嶠年年別，丘陵徒自傷。"]'),
('yuding-12','觀回軍三韻','李益','唐','御定全唐诗','yuding','','[]','行行上隴頭，隴月暗悠悠。萬里將軍沒，回旌隴戍秋。',36,'御定全唐詩/json/282.json','["行行上隴頭，隴月暗悠悠。萬里將軍沒，回旌隴戍秋。", "誰令嗚咽水，重入故營流。"]'),
('yuding-13','華山南廟','李益','唐','御定全唐诗','yuding','','[]','陰山臨古道，古廟閉山碧。落日春草中，搴芳薦瑤席。',72,'御定全唐詩/json/282.json','["陰山臨古道，古廟閉山碧。落日春草中，搴芳薦瑤席。", "明靈達精意，仿佛如不隔。岩雨神降時，回飆入松柏。", "常聞坑儒後，此地返秦璧。自古害忠良，神其輔宗祏。"]'),
('yuding-14','喜邢校書遠至對雨同賦遠晚飯阮返五韻','李益','唐','御定全唐诗','yuding','','[]','雀噪空城陰，木衰羈思遠。已蔽青山望，徒悲白雲晚。',60,'御定全唐詩/json/282.json','["雀噪空城陰，木衰羈思遠。已蔽青山望，徒悲白雲晚。", "別離千里風，雨中同一飯。開徑說逢康，臨觴方接阮。", "旅宦竟何如，勞飛思自返。"]'),
('yuding-15','城西竹園送裴佶王達','李益','唐','御定全唐诗','yuding','','[]','葳蕤淩風竹，寂寞離人觴。愴懷非外至，沉鬱自中腸。',36,'御定全唐詩/json/282.json','["葳蕤淩風竹，寂寞離人觴。愴懷非外至，沉鬱自中腸。", "遠行從此始，別袂重淒霜。"]'),
('yuding-16','月下喜邢校書至自洛','李益','唐','御定全唐诗','yuding','','[]','天河夜未央，漫漫複蒼蒼。重君遠行至，及此明月光。',48,'御定全唐詩/json/282.json','["天河夜未央，漫漫複蒼蒼。重君遠行至，及此明月光。", "華星映衰柳，暗水入寒塘。客心定何似，餘歡方自長。"]'),
('yuding-17','北至太原','李益','唐','御定全唐诗','yuding','','[]','炎祚昔昏替，皇基此鬱盤。玄命久已集，撫運良乃艱。',96,'御定全唐詩/json/282.json','["炎祚昔昏替，皇基此鬱盤。玄命久已集，撫運良乃艱。", "南厄羊腸險，北走雁門寒。始於一戎定，垂此億世安。", "唐風本憂思，王業實艱難。中曆雖橫潰，天紀未可幹。", "聖明所興國，靈嶽固不殫。咄咄薄遊客，斯言殊不刊。"]'),
('yuding-18','入華山訪隱者經仙人石壇','李益','唐','御定全唐诗','yuding','','[]','三考四嶽下，官曹少休沐。久負青山諾，今還獲所欲。',204,'御定全唐詩/json/282.json','["三考四嶽下，官曹少休沐。久負青山諾，今還獲所欲。", "嘗聞玉清洞，金簡受玄籙。夙駕升天行，雲遊恣霞宿。", "平明矯輕策，捫石入空曲。仙人古石壇，苔繞青瑤局。", "陽桂淩煙紫，陰羅冒水綠。隔世聞丹經，懸泉注明玉。", "前驚羽人會，白日天居肅。問我將致辭，笑之自相目。", "竦身雲遂起，仰見雙白鵠。墮其一紙書，文字類鳥足。", "視之了不識，三返又三複。歸來問方士，舉世莫解讀。", "何必若蜉蝣，然後為局促。鄙哉宦遊子，身志俱降辱。", "再往不及期，勞歌叩山木。"]'),
('yuding-19','罷鏡','李益','唐','御定全唐诗','yuding','','[]','手中青銅鏡，照我少年時。衰颯一如此，清光難複持。',48,'御定全唐詩/json/282.json','["手中青銅鏡，照我少年時。衰颯一如此，清光難複持。", "欲令孤月掩，從遣半心疑。縱使逢人見，猶勝自見悲。"]'),
('yuding-20','華陰東泉同張處士詣藏律師兼簡縣內同官因寄齊中書','李益','唐','御定全唐诗','yuding','','[]','蒼崖抱寒泉，淪照洞金碧。潛鱗孕明晦，山靈閟幽賾。',192,'御定全唐詩/json/282.json','["蒼崖抱寒泉，淪照洞金碧。潛鱗孕明晦，山靈閟幽賾。", "前峰何其詭，萬變窮日夕。松老風易悲，山秋雲更白。", "故人邑中吏，五裏仙霧隔。美質簡瓊瑤，英聲鏗金石。", "煩君竟相問，問我此何適。我因贊時理，書寄西飛翮。", "哲匠熙百工，日月被光澤。大國本多士，荊岑無遺璧。", "高網彌八紘，皇圖明四辟。群材既兼暢，顧我在草澤。", "貴無身外名，賤有區中役。忽忽百齡內，殷殷千慮迫。", "人生已如寄，在寄複為客。舊國不得歸，風塵滿阡陌。"]'),
('yuding-21','答郭黃中孤雲首章見贈','李益','唐','御定全唐诗','yuding','','[]','孤雲生西北，從風東南飄。帝鄉日已遠，蒼梧無還飆。',48,'御定全唐詩/json/282.json','["孤雲生西北，從風東南飄。帝鄉日已遠，蒼梧無還飆。", "已矣玄鳳歎，嚴霜集靈苕。君其勉我懷，歲暮孰不凋。"]'),
('yuding-22','合源溪期張計不至','李益','唐','御定全唐诗','yuding','','[]','霜露肅時序，緬然方獨尋。暗溪遲仙侶，寒澗聞松禽。',60,'御定全唐詩/json/282.json','["霜露肅時序，緬然方獨尋。暗溪遲仙侶，寒澗聞松禽。", "寂曆茲夜永，清明秋序深。微波澹澄夕，煙景含虛林。", "素志久淪否，幽懷方自吟。"]'),
('yuding-23','竹溪','李益','唐','御定全唐诗','yuding','','[]','訪竹越雲崖，即林若溪絕。甯知修幹下，漠漠秋苔潔。',48,'御定全唐詩/json/282.json','["訪竹越雲崖，即林若溪絕。甯知修幹下，漠漠秋苔潔。", "清光溢空曲，茂色臨幽澈。採摘愧芳鮮，奉君歲暮節。"]'),
('yuding-24','送諸暨王主簿之任','李益','唐','御定全唐诗','yuding','','[]','別愁已萬緒，離曲方三奏。遠宦一辭鄉，南天異風候。',60,'御定全唐詩/json/282.json','["別愁已萬緒，離曲方三奏。遠宦一辭鄉，南天異風候。", "秦城歲芳老，越國春山秀。落日望寒濤，公門閉清晝。", "何用慰相思，裁書寄關右。"]'),
('yuding-25','罷秩後入華山采茯苓逢道者','李益','唐','御定全唐诗','yuding','','[]','委綬來名山，觀奇恣所停。山中若有聞，言此不死庭。',204,'御定全唐詩/json/282.json','["委綬來名山，觀奇恣所停。山中若有聞，言此不死庭。", "遂逢五老人，一謂西嶽靈。或聞樵人語，飛去入昴星。", "授我出雲路，蒼然淩石屏。視之有文字，乃古黃庭經。", "左右長松列，動搖風露零。上蟠千年枝，陰虯負青冥。", "下結九秋霰，流膏為茯苓。取之砂石間，異若龜鶴形。", "況聞秦宮女，華髮變已青。有如上帝心，與我千萬齡。", "始疑有仙骨，煉魂可永寧。何事逐豪遊，飲啄以膻腥。", "神物亦自閟，風雷護此扃。欲傳山中寶，回策忽已暝。", "乃悲世上人，求醒終不醒。"]'),
('yuding-26','自朔方還與鄭式瞻崔稱鄭子周岑贊同會法雲寺三門避暑','李益','唐','御定全唐诗','yuding','','[]','予本疏放士，朅來非外矯。誤落邊塵中，愛山見山少。',96,'御定全唐詩/json/282.json','["予本疏放士，朅來非外矯。誤落邊塵中，愛山見山少。", "始投清涼宇，門值煙岫表。參差互明滅，彩翠竟昏曉。", "泠泠遠風來，過此群木杪。英英二三彥，襟曠去煩擾。", "遊川出潛魚，息陰倦飛鳥。徇物不可窮，唯於此心了。"]'),
('yuding-27','來從竇車騎行','李益','唐','御定全唐诗','yuding','','[]','束發逢世屯，懷恩抱明義。讀書良有感，學劍慚非智。',228,'御定全唐詩/json/282.json','["束發逢世屯，懷恩抱明義。讀書良有感，學劍慚非智。", "遂別魯諸生，來從竇車騎。追兵赴邊急，絡馬黃金轡。", "出入燕南陲，由來重意氣。自經皋蘭戰，又破樓煩地。", "西北護三邊，東南留一尉。時過欻如雲，參差不自意。", "將軍失恩澤，萬事從此異。置酒高臺上，薄暮秋風至。", "長戟與我歸，歸來同棄置。自酌還自飲，非名又非利。", "歌出易水寒，琴下雍門淚。出逢平樂舊，言在天階侍。", "問我從軍苦，自陳少年貴。丈夫交四海，徒論身自致。", "漢將不封侯，蘇卿勞遠使。今我終此曲，此曲誠不易。", "貴人難識心，何由知忌諱。"]'),
('yuding-28','夜發軍中','李益','唐','御定全唐诗','yuding','','[]','邊馬櫪上驚，雄劍匣中鳴。半夜軍書至，匈奴寇六城。',60,'御定全唐詩/json/282.json','["邊馬櫪上驚，雄劍匣中鳴。半夜軍書至，匈奴寇六城。", "中堅分暗陣，太乙起神兵。出沒風雲合，蒼黃豺虎爭。", "今日邊庭戰，緣賞不緣名。"]'),
('yuding-29','將赴朔方早發漢武泉','李益','唐','御定全唐诗','yuding','','[]','弭蓋出故關，窮秋首邊路。問我此何為，平生重一顧。',84,'御定全唐詩/json/282.json','["弭蓋出故關，窮秋首邊路。問我此何為，平生重一顧。", "風吹山下草，系馬河邊樹。奉役良有期，回瞻終未屢。", "去鄉幸未遠，戎衣今已故。豈惟幽朔寒，念我機中素。", "去矣勿複言，所酬知音遇。"]'),
('yuding-30','城傍少年','李益','唐','御定全唐诗','yuding','','[]','生長邊城傍，出身事弓馬。少年有膽氣，獨獵陰山下。',48,'御定全唐詩/json/282.json','["生長邊城傍，出身事弓馬。少年有膽氣，獨獵陰山下。", "偶與匈奴逢，曾擒射雕者。名懸壯士籍，請君少相假。"]'),
('yuding-31','遊子吟','李益','唐','御定全唐诗','yuding','','[]','女羞夫婿薄，客恥主人賤。遭遇同眾流，低回愧相見。',72,'御定全唐詩/json/282.json','["女羞夫婿薄，客恥主人賤。遭遇同眾流，低回愧相見。", "君非青銅鏡，何事空照面。莫以衣上塵，不謂心如練。", "人生當榮盛，待士勿言倦。君看白日馳，何異弦上箭。"]'),
('yuding-32','飲馬歌','李益','唐','御定全唐诗','yuding','','[]','百馬飲一泉，一馬爭上游。一馬噴成泥，百馬飲濁流。',60,'御定全唐詩/json/282.json','["百馬飲一泉，一馬爭上游。一馬噴成泥，百馬飲濁流。", "上有滄浪客，對之空歎息。自顧纓上塵，裴回終日夕。", "為問泉上翁，何時見沙石。"]'),
('yuding-33','蓮塘驛','李益','唐','御定全唐诗','yuding','','[]','五月渡淮水，南行繞山陂。江村遠雞應，竹裏聞繰絲。',96,'御定全唐詩/json/282.json','["五月渡淮水，南行繞山陂。江村遠雞應，竹裏聞繰絲。", "楚女肌發美，蓮塘煙露滋。菱花覆碧渚，黃鳥雙飛時。", "渺渺溯洄遠，憑風托微詞。斜光動流睇，此意難自持。", "女歌本輕豔，客行多怨思。女蘿蒙幽蔓，擬上青桐枝。"]'),
('yuding-34','五城道中','李益','唐','御定全唐诗','yuding','','[]','金鐃隨玉節，落日河邊路。沙鳴後騎來，雁起前軍度。',108,'御定全唐詩/json/282.json','["金鐃隨玉節，落日河邊路。沙鳴後騎來，雁起前軍度。", "五城鳴斥堠，三秦新召募。天寒白登道，塞濁陰山霧。", "仍聞舊兵老，尚在烏蘭戍。笳簫漢思繁，旌旗邊色故。", "寢興倦弓甲，勤役傷風露。來遠賞不行，鋒交勳乃茂。", "未知朔方道，何年罷兵賦。"]'),
('yuding-35','與王楚同登青龍寺上方','李益','唐','御定全唐诗','yuding','','[]','連岡出古寺，流睇移芳宴。鳥沒漢諸陵，草平秦故殿。',60,'御定全唐詩/json/282.json','["連岡出古寺，流睇移芳宴。鳥沒漢諸陵，草平秦故殿。", "搖光淺深樹，拂木參差燕。春心斷易迷，遠目傷難遍。", "壯日各輕年，暮年方自見。"]'),
('yuding-36','登夏州城觀送行人賦得六州胡兒歌','李益','唐','御定全唐诗','yuding','','[]','六州胡兒六蕃語，十歲騎羊逐沙鼠。沙頭牧馬孤雁飛，',88,'御定全唐詩/json/282.json','["六州胡兒六蕃語，十歲騎羊逐沙鼠。沙頭牧馬孤雁飛，", "無定河邊數株柳，共送行人一杯酒。胡兒起作和蕃歌，", "回頭忽作異方聲，一聲回盡征人首。蕃音虜曲一難分，", "不見天邊青作塚，古來愁殺漢昭君。"]'),
('yuding-37','從軍夜次六胡北飲馬磨劍石為祝殤辭','李益','唐','御定全唐诗','yuding','','[]','我行空磧，見沙之磷磷，與草之冪冪，半沒胡兒磨劍石。',165,'御定全唐詩/json/282.json','["我行空磧，見沙之磷磷，與草之冪冪，半沒胡兒磨劍石。", "當時洗劍血成川，至今草與沙皆赤。我因扣石問以言，", "請君先問湘江水，然我此恨乃可論。秦亡漢絕三十國，", "為之彈劍作哀吟，風沙四起雲沉沉。滿營戰馬嘶欲盡，", "年移代去感精魂，空山月暗聞鼙鼓。秦坑趙卒四十萬，", "韓公三城斷胡路，漢甲百萬屯邊秋。乃分司空授朔土，", "殤為魂兮，可以歸還故鄉些；沙場地無人兮，"]'),
('yuding-38','登天壇夜見海','李益','唐','御定全唐诗','yuding','','[]','朝遊碧峰三十六，夜上天壇月邊宿。仙人攜我搴玉英，',72,'御定全唐詩/json/282.json','["朝遊碧峰三十六，夜上天壇月邊宿。仙人攜我搴玉英，", "霞梯赤城遙可分，霓旌絳節倚彤雲。八鸞五鳳紛在禦，", "竦身別我期丹宮，空山處處遺清風。九州下視杳未旦，"]'),
('yuding-39','大禮畢皇帝禦丹鳳門改元建中大赦','李益','唐','御定全唐诗','yuding','','[]','大明曈曈天地分，六龍負日升天門。鳳凰飛來銜帝籙，',72,'御定全唐詩/json/282.json','["大明曈曈天地分，六龍負日升天門。鳳凰飛來銜帝籙，", "宸居穆清受天曆，建中甲子合上元。昊穹景命即已至，", "雲亭之事略可記，七十二君寧獨尊。小臣欲上封禪表，"]'),
('yuding-40','輕薄篇','李益','唐','御定全唐诗','yuding','','[]','豪不必馳千騎，雄不在垂雙鞬。天生俊氣自相逐，',70,'御定全唐詩/json/282.json','["豪不必馳千騎，雄不在垂雙鞬。天生俊氣自相逐，", "忽聞燕雁一聲去，回鞍挾彈平陵園。歸來青樓曲未半，", "安知我有不平色，白日欲落紅塵昏。死生容易如反掌，"]'),
('yuding-41','野田行','李益','唐','御定全唐诗','yuding','','[]','日沒出古城，野田何茫茫。寒狐嘯青塚，鬼火燒白楊。',40,'御定全唐詩/json/282.json','["日沒出古城，野田何茫茫。寒狐嘯青塚，鬼火燒白楊。", "昔人未為泉下客，行到此中曾斷腸。"]'),
('yuding-42','古別離','李益','唐','御定全唐诗','yuding','','[]','雙劍欲別風淒然，雌沉水底雄上天。江回漢轉兩不見，',24,'御定全唐詩/json/282.json','["雙劍欲別風淒然，雌沉水底雄上天。江回漢轉兩不見，"]'),
('yuding-43','效古促促曲為河上思婦作','李益','唐','御定全唐诗','yuding','','[]','促促何促促，黃河九回曲。嫁與棹船郎，空床將影宿。',40,'御定全唐詩/json/282.json','["促促何促促，黃河九回曲。嫁與棹船郎，空床將影宿。", "不道君心不如石，那教妾貌長如玉。"]'),
('yuding-44','漢宮少年行','李益','唐','御定全唐诗','yuding','','[]','君不見上宮警夜營八屯，冬冬街鼓朝朱軒。',139,'御定全唐詩/json/282.json','["君不見上宮警夜營八屯，冬冬街鼓朝朱軒。", "玉階霜仗擁未合，少年排入銅龍門。暗聞弦管九天上，", "玉籠金鎖養黃口，探雛取卵伴王孫。分曹陸博快一擲，", "晚來香街經柳市，行過倡舍宿桃根。相逢杯酒一言失，", "豈知人事無定勢，朝歡暮戚如掌翻。椒房寵移子愛奪，", "持杯收水水已覆，徙薪避火火更燔。欲求四老張丞相，"]'),
('yuding-0','竹窗聞風寄苗發司空曙','李益','唐','御定全唐诗','yuding','','[]','微風驚暮坐，臨牖思悠哉。開門複動竹，疑是故人來。',48,'御定全唐詩/json/283.json','["微風驚暮坐，臨牖思悠哉。開門複動竹，疑是故人來。", "時滴枝上露，稍沾階下苔。何當一入幌，為拂綠琴埃。"]'),
('yuding-1','賦得垣衣','李益','唐','御定全唐诗','yuding','','[]','漠漠複霏霏，為君垣上衣。昭陽輦下草，應笑此生非。',48,'御定全唐詩/json/283.json','["漠漠複霏霏，為君垣上衣。昭陽輦下草，應笑此生非。", "掩藹青春去，蒼茫白露稀。猶勝萍逐水，流浪不相依。"]'),
('yuding-2','送人流貶','李益','唐','御定全唐诗','yuding','','[]','漢章雖約法，秦律已除名。謗遠人多惑，官微不自明。',48,'御定全唐詩/json/283.json','["漢章雖約法，秦律已除名。謗遠人多惑，官微不自明。", "霜風先獨樹，瘴雨失荒城。疇昔長沙事，三年召賈生。"]'),
('yuding-3','送人南歸','李益','唐','御定全唐诗','yuding','','[]','人言下江疾，君道下江遲。五月江路惡，南風驚浪時。',48,'御定全唐詩/json/283.json','["人言下江疾，君道下江遲。五月江路惡，南風驚浪時。", "應知近家喜，還有異鄉悲。無奈孤舟夕，山歌聞竹枝。"]'),
('yuding-4','水亭夜坐賦得曉霧','李益','唐','御定全唐诗','yuding','','[]','月落寒霧起，沈思浩通川。宿禽囀木散，山澤一蒼然。',48,'御定全唐詩/json/283.json','["月落寒霧起，沈思浩通川。宿禽囀木散，山澤一蒼然。", "漠漠沙上路，沄沄洲外田。猶當依遠樹，斷續欲窮天。"]'),
('yuding-5','送常曾侍禦使西蕃寄題西川','李益','唐','御定全唐诗','yuding','','[]','涼王宮殿盡，蕪沒隴雲西。今日聞君使，雄心逐鼓鼙。',48,'御定全唐詩/json/283.json','["涼王宮殿盡，蕪沒隴雲西。今日聞君使，雄心逐鼓鼙。", "行當收漢壘，直可取蒲泥。舊國無由到，煩君下馬題。"]'),
('yuding-6','入南山至全師蘭若','李益','唐','御定全唐诗','yuding','','[]','木隕水歸壑，寂然無念心。南行有真子，被褐息山陰。',48,'御定全唐詩/json/283.json','["木隕水歸壑，寂然無念心。南行有真子，被褐息山陰。", "石路瑤草散，松門寒景深。吾師亦何愛，自起定中吟。"]'),
('yuding-7','送韓將軍還邊','李益','唐','御定全唐诗','yuding','','[]','白馬羽林兒，揚鞭薄暮時。獨將輕騎出，暗與伏兵期。',48,'御定全唐詩/json/283.json','["白馬羽林兒，揚鞭薄暮時。獨將輕騎出，暗與伏兵期。", "雨雪移軍遠，旌旗上壟遲。聖心戎寄重，未許讓恩私。"]'),
('yuding-8','晚春臥病喜振上人見訪','李益','唐','御定全唐诗','yuding','','[]','臥床如舊日，窺戶易傷春。靈壽扶衰力，芭蕉對病身。',48,'御定全唐詩/json/283.json','["臥床如舊日，窺戶易傷春。靈壽扶衰力，芭蕉對病身。", "道心空寂寞，時物自芳新。旦夕誰相訪，唯當攝上人。"]'),
('yuding-9','春行','李益','唐','御定全唐诗','yuding','','[]','侍臣朝謁罷，戚裏自相過。落日青絲騎，春風白紵歌。',48,'御定全唐詩/json/283.json','["侍臣朝謁罷，戚裏自相過。落日青絲騎，春風白紵歌。", "恩承三殿近，獵向五陵多。歸路南橋望，垂楊拂細波。"]'),
('yuding-10','洛陽河亭奉酬留守群公追送','李益','唐','御定全唐诗','yuding','','[]','離亭餞落暉，臘酒減春衣。歲晚煙霞重，川寒雲樹微。',48,'御定全唐詩/json/283.json','["離亭餞落暉，臘酒減春衣。歲晚煙霞重，川寒雲樹微。", "戎裝千里至，舊路十年歸。還似汀洲雁，相逢又背飛。"]'),
('yuding-11','尋紀道士偶會諸叟','李益','唐','御定全唐诗','yuding','','[]','山陰尋道士，映竹羽衣新。侍坐雙童子，陪游五老人。',48,'御定全唐詩/json/283.json','["山陰尋道士，映竹羽衣新。侍坐雙童子，陪游五老人。", "水花松下靜，壇草雪中春。見說桃源洞，如今猶避秦。"]'),
('yuding-12','同蕭煉師宿太乙廟','李益','唐','御定全唐诗','yuding','','[]','微月空山曙，春祠謁少君。落花壇上拂，流水洞中聞。',48,'御定全唐詩/json/283.json','["微月空山曙，春祠謁少君。落花壇上拂，流水洞中聞。", "酒引芝童奠，香餘桂子焚。鶴飛將羽節，遙向赤城分。"]'),
('yuding-13','送同落第者東歸','李益','唐','御定全唐诗','yuding','','[]','東門有行客，落日滿前山。聖代誰知者，滄洲今獨還。',48,'御定全唐詩/json/283.json','["東門有行客，落日滿前山。聖代誰知者，滄洲今獨還。", "片雲歸海暮，流水背城閑。餘亦依嵩潁，松花深閉關。"]'),
('yuding-14','送柳判官赴振武','李益','唐','御定全唐诗','yuding','','[]','邊庭漢儀重，旌甲似雲中。虜地山川壯，單于鼓角雄。',48,'御定全唐詩/json/283.json','["邊庭漢儀重，旌甲似雲中。虜地山川壯，單于鼓角雄。", "關寒塞榆落，月白胡天風。君逐嫖姚將，麒麟有戰功。"]'),
('yuding-15','述懷寄衡州令狐相公','李益','唐','御定全唐诗','yuding','','[]','調元方翼聖，軒蓋忽言東。道以中樞密，心將外理同。',48,'御定全唐詩/json/283.json','["調元方翼聖，軒蓋忽言東。道以中樞密，心將外理同。", "白頭生遠浪，丹葉下高楓。江上蕭疏雨，何人對謝公。"]'),
('yuding-16','喜入蘭陵望紫閣峰呈宣上人','李益','唐','御定全唐诗','yuding','','[]','薙草開三徑，巢林喜一枝。地寬留種竹，泉淺欲開池。',48,'御定全唐詩/json/283.json','["薙草開三徑，巢林喜一枝。地寬留種竹，泉淺欲開池。", "紫閣當疏牖，青松入壞籬。從今安僻陋，蕭相是吾師。"]'),
('yuding-17','喜見外弟又言別','李益','唐','御定全唐诗','yuding','','[]','十年離亂後，長大一相逢。問姓驚初見，稱名憶舊容。',48,'御定全唐詩/json/283.json','["十年離亂後，長大一相逢。問姓驚初見，稱名憶舊容。", "別來滄海事，語罷暮天鐘。明日巴陵道，秋山又幾重。"]'),
('yuding-18','立春日寧州行營因賦朔風吹飛雪','李益','唐','御定全唐诗','yuding','','[]','邊聲日夜合，朔風驚複來。龍山不可望，千里一裴回。',48,'御定全唐詩/json/283.json','["邊聲日夜合，朔風驚複來。龍山不可望，千里一裴回。", "捐扇破誰執，素紈輕欲裁。非時妒桃李，自是舞陽臺。"]'),
('yuding-19','獻劉濟','李益','唐','御定全唐诗','yuding','','[]','草綠古燕州，鶯聲引獨遊。雁歸天北畔，春盡海西頭。',48,'御定全唐詩/json/283.json','["草綠古燕州，鶯聲引獨遊。雁歸天北畔，春盡海西頭。", "向日花偏落，馳年水自流。感恩知有地，不上望京樓。"]'),
('yuding-20','哭柏岩禪師','李益','唐','御定全唐诗','yuding','','[]','遍與傍人別，臨終盡不愁。影堂誰為掃，坐塔自看修。',48,'御定全唐詩/json/283.json','["遍與傍人別，臨終盡不愁。影堂誰為掃，坐塔自看修。", "白日鐘邊晚，青苔缽上秋。天涯禪弟子，空到柏岩遊。"]'),
('yuding-21','赴邠甯留別','李益','唐','御定全唐诗','yuding','','[]','身承漢飛將，束發即言兵。俠少何相問，從來事不平。',48,'御定全唐詩/json/283.json','["身承漢飛將，束發即言兵。俠少何相問，從來事不平。", "黃雲斷朔吹，白雪擁沙城。幸應邊書募，橫戈會取名。"]'),
('yuding-22','紫騮馬','李益','唐','御定全唐诗','yuding','','[]','爭場看鬥雞，白鼻紫騮嘶。漳水春閨晚，叢台日向低。',48,'御定全唐詩/json/283.json','["爭場看鬥雞，白鼻紫騮嘶。漳水春閨晚，叢台日向低。", "歇鞍珠作汗，試劍玉如泥。為謝紅梁燕，年年妾獨棲。"]'),
('yuding-23','夜上受降城聞笛','李益','唐','御定全唐诗','yuding','','[]','入夜思歸切，笛聲清更哀。愁人不願聽，自到枕前來。',48,'御定全唐詩/json/283.json','["入夜思歸切，笛聲清更哀。愁人不願聽，自到枕前來。", "風起塞雲斷，夜深關月開。平明獨惆悵，落盡一庭梅。"]'),
('yuding-24','同崔邠登鸛雀樓','李益','唐','御定全唐诗','yuding','','[]','鸛雀樓西百尺檣，汀洲雲樹共茫茫。漢家蕭鼓空流水，',40,'御定全唐詩/json/283.json','["鸛雀樓西百尺檣，汀洲雲樹共茫茫。漢家蕭鼓空流水，", "風煙並起思歸望，遠目非春亦自傷。"]'),
('yuding-25','奉酬崔員外副使攜琴宿使院見示','李益','唐','御定全唐诗','yuding','','[]','忽聞此夜攜琴宿，遂歎常時塵吏喧。庭木已衰空月亮，',40,'御定全唐詩/json/283.json','["忽聞此夜攜琴宿，遂歎常時塵吏喧。庭木已衰空月亮，", "誰問南飛長繞樹，官微同在謝公門。"]'),
('yuding-26','送賈校書東歸寄振上人','李益','唐','御定全唐诗','yuding','','[]','北風吹雁數聲悲，況指前林是別時。秋草不堪頻送遠，',40,'御定全唐詩/json/283.json','["北風吹雁數聲悲，況指前林是別時。秋草不堪頻送遠，", "為向東州故人道，江淹已擬惠休詩。"]'),
('yuding-27','過馬嵬二首','李益','唐','御定全唐诗','yuding','','[]','路至牆垣問樵者，顧予雲是太真宮。太真血染馬蹄盡，',80,'御定全唐詩/json/283.json','["路至牆垣問樵者，顧予雲是太真宮。太真血染馬蹄盡，", "世人莫重霓裳曲，曾致干戈是此中。", "金甲銀旌盡已回，蒼茫羅袖隔風埃。濃香猶自隨鸞輅，", "唯留坡畔彎環月，時送殘輝入夜台。"]'),
('yuding-28','鹽州過胡兒飲馬泉','李益','唐','御定全唐诗','yuding','','[]','綠楊著水草如煙，舊是胡兒飲馬泉。幾處吹笳明月夜，',40,'御定全唐詩/json/283.json','["綠楊著水草如煙，舊是胡兒飲馬泉。幾處吹笳明月夜，", "莫遣行人照容鬢，恐驚憔悴入新年。"]'),
('yuding-29','宿馮翊夜雨贈主人','李益','唐','御定全唐诗','yuding','','[]','危心驚夜雨，起望漫悠悠。氣耿殘燈暗，聲繁高樹秋。',72,'御定全唐詩/json/283.json','["危心驚夜雨，起望漫悠悠。氣耿殘燈暗，聲繁高樹秋。", "涼軒辭夏扇，風幌攬輕裯。思緒蓬初斷，歸期燕暫留。", "關山藹已失，臉淚迸難收。賴君時一笑，方能解四愁。"]'),
('yuding-30','送襄陽李尚書','李益','唐','御定全唐诗','yuding','','[]','天寒發梅柳，憶昔到襄州。樹暖然紅燭，江清展碧油。',96,'御定全唐詩/json/283.json','["天寒發梅柳，憶昔到襄州。樹暖然紅燭，江清展碧油。", "風煙臨峴首，雲水接昭丘。俗尚春秋學，詞稱文選樓。", "都門送旌節，符竹領諸侯。漢沔分戎寄，黎元減聖憂。", "時追山簡興，本自習家流。莫廢思康樂，詩情滿沃洲。"]'),
('yuding-31','春日晉祠同聲會集得疏字韻','李益','唐','御定全唐诗','yuding','','[]','風壤瞻唐本，山祠閱晉餘。水亭開帟幕，岩榭引簪裾。',72,'御定全唐詩/json/283.json','["風壤瞻唐本，山祠閱晉餘。水亭開帟幕，岩榭引簪裾。", "地綠苔猶少，林黃柳尚疏。菱苕生皎鏡，金碧照澄虛。", "翰苑聲何舊，賓筵醉止初。中州有遼雁，好為系邊書。"]'),
('yuding-32','再赴渭北使府留別','李益','唐','御定全唐诗','yuding','','[]','結髮逐鳴鼙，連兵追穀蠡。山川搜伏虜，鎧甲被重犀。',96,'御定全唐詩/json/283.json','["結髮逐鳴鼙，連兵追穀蠡。山川搜伏虜，鎧甲被重犀。", "故府旌旗在，新軍羽校齊。報恩身未死，識路馬還嘶。", "列嶂高烽舉，當營太白低。平戎七尺劍，封檢一丸泥。", "截海取蒲類，跑泉飲鸊鵜。漢庭中選重，更事五原西。"]'),
('yuding-33','送歸中丞使新羅冊立弔祭','李益','唐','御定全唐诗','yuding','','[]','東望扶桑日，何年是到時。片帆通雨露，積水隔華夷。',72,'御定全唐詩/json/283.json','["東望扶桑日，何年是到時。片帆通雨露，積水隔華夷。", "浩渺風來遠，虛明鳥去遲。長波靜雲月，孤島宿旌旗。", "別葉傳秋意，回潮動客思。滄溟無舊路，何處問前期。"]'),
('yuding-34','賦得路傍一株柳送邢校書赴延州使府','李益','唐','御定全唐诗','yuding','','[]','路傍一株柳，此路向延州。延州在何處，此路起悠悠。',24,'御定全唐詩/json/283.json','["路傍一株柳，此路向延州。延州在何處，此路起悠悠。"]'),
('yuding-35','重贈邢校書','李益','唐','御定全唐诗','yuding','','[]','俱從四方事，共會九秋中。斷蓬與落葉，相值各因風。',24,'御定全唐詩/json/283.json','["俱從四方事，共會九秋中。斷蓬與落葉，相值各因風。"]'),
('yuding-36','照鏡','李益','唐','御定全唐诗','yuding','','[]','衰鬢朝臨鏡，將看卻自疑。慚君明似月，照我白如絲。',24,'御定全唐詩/json/283.json','["衰鬢朝臨鏡，將看卻自疑。慚君明似月，照我白如絲。"]'),
('yuding-37','書院無曆日，以詩代書，問路侍禦六月大小','李益','唐','御定全唐诗','yuding','','[]','野性迷堯曆，松窗有道經。故人為柱史，為我數階蓂。',24,'御定全唐詩/json/283.json','["野性迷堯曆，松窗有道經。故人為柱史，為我數階蓂。"]'),
('yuding-38','聞雞贈主人','李益','唐','御定全唐诗','yuding','','[]','膠膠司晨鳴，報爾東方旭。無事戀君軒，今君重鳧鵠。',24,'御定全唐詩/json/283.json','["膠膠司晨鳴，報爾東方旭。無事戀君軒，今君重鳧鵠。"]'),
('yuding-39','登白樓見白鳥席上命鷓鴣辭','李益','唐','御定全唐诗','yuding','','[]','一鳥如霜雪，飛向白樓前。問君何以至，天子太平年。',24,'御定全唐詩/json/283.json','["一鳥如霜雪，飛向白樓前。問君何以至，天子太平年。"]'),
('yuding-40','石樓山見月','李益','唐','御定全唐诗','yuding','','[]','紫塞連年戍，黃砂磧路窮。故人今夜宿，見月石樓中。',24,'御定全唐詩/json/283.json','["紫塞連年戍，黃砂磧路窮。故人今夜宿，見月石樓中。"]'),
('yuding-41','惜春傷同幕故人孟郎中兼呈去年看花友','李益','唐','御定全唐诗','yuding','','[]','畏老身全老，逢春解惜春。今年看花伴，已少去年人。',24,'御定全唐詩/json/283.json','["畏老身全老，逢春解惜春。今年看花伴，已少去年人。"]'),
('yuding-42','嘉禾寺見亡友王七題壁','李益','唐','御定全唐诗','yuding','','[]','今日憶君處，憶君君豈知。空餘暗塵字，讀罷淚仍垂。',24,'御定全唐詩/json/283.json','["今日憶君處，憶君君豈知。空餘暗塵字，讀罷淚仍垂。"]'),
('yuding-43','聽唱赤白桃李花','李益','唐','御定全唐诗','yuding','','[]','赤白桃李花，先皇在時曲。欲向西宮唱，西宮宮樹綠。',24,'御定全唐詩/json/283.json','["赤白桃李花，先皇在時曲。欲向西宮唱，西宮宮樹綠。"]'),
('yuding-44','江南詞','李益','唐','御定全唐诗','yuding','','[]','嫁得瞿塘賈，朝朝誤妾期。早知潮有信，嫁與弄潮兒。',24,'御定全唐詩/json/283.json','["嫁得瞿塘賈，朝朝誤妾期。早知潮有信，嫁與弄潮兒。"]'),
('yuding-45','贈內兄盧綸','李益','唐','御定全唐诗','yuding','','[]','世故中年別，餘生此會同。卻將悲與病，來對朗陵翁。',24,'御定全唐詩/json/283.json','["世故中年別，餘生此會同。卻將悲與病，來對朗陵翁。"]'),
('yuding-46','答竇二曹長留酒還榼','李益','唐','御定全唐诗','yuding','','[]','榼小非由榼，星郎是酒星。解酲元有數，不用嚇劉伶。',24,'御定全唐詩/json/283.json','["榼小非由榼，星郎是酒星。解酲元有數，不用嚇劉伶。"]'),
('yuding-47','答廣宣供奉問蘭陵居','李益','唐','御定全唐诗','yuding','','[]','居北有朝路，居南無住人。勞師問家第，山色是南鄰。',24,'御定全唐詩/json/283.json','["居北有朝路，居南無住人。勞師問家第，山色是南鄰。"]'),
('yuding-48','乞寬禪師癭山罍呈宣供奉','李益','唐','御定全唐诗','yuding','','[]','石色凝秋蘚，峰形若夏雲。誰留秦苑地，好贈杏溪君。',24,'御定全唐詩/json/283.json','["石色凝秋蘚，峰形若夏雲。誰留秦苑地，好贈杏溪君。"]'),
('yuding-49','觀騎射','李益','唐','御定全唐诗','yuding','','[]','邊頭射雕將，走馬出中軍。遠見平原上，翻身向暮雲。',24,'御定全唐詩/json/283.json','["邊頭射雕將，走馬出中軍。遠見平原上，翻身向暮雲。"]'),
('yuding-50','幽州賦詩見意時佐劉幕','李益','唐','御定全唐诗','yuding','','[]','征戍在桑幹，年年薊水寒。殷勤驛西路，北去向長安。',24,'御定全唐詩/json/283.json','["征戍在桑幹，年年薊水寒。殷勤驛西路，北去向長安。"]'),
('yuding-51','軍次陽城烽舍北流泉','李益','唐','御定全唐诗','yuding','','[]','何地可潸然，陽城烽樹邊。今朝望鄉客，不飲北流泉。',24,'御定全唐詩/json/283.json','["何地可潸然，陽城烽樹邊。今朝望鄉客，不飲北流泉。"]'),
('yuding-52','金吾子','李益','唐','御定全唐诗','yuding','','[]','繡帳博山爐，銀鞍馮子都。黃昏莫攀折，驚起欲棲烏。',24,'御定全唐詩/json/283.json','["繡帳博山爐，銀鞍馮子都。黃昏莫攀折，驚起欲棲烏。"]'),
('yuding-53','山鷓鴣詞','李益','唐','御定全唐诗','yuding','','[]','湘江斑竹枝，錦翅鷓鴣飛。處處湘雲合，郎從何處歸。',24,'御定全唐詩/json/283.json','["湘江斑竹枝，錦翅鷓鴣飛。處處湘雲合，郎從何處歸。"]'),
('yuding-54','立秋前一日覽鏡','李益','唐','御定全唐诗','yuding','','[]','萬事銷身外，生涯在鏡中。唯將滿鬢雪，明日對秋風。',24,'御定全唐詩/json/283.json','["萬事銷身外，生涯在鏡中。唯將滿鬢雪，明日對秋風。"]'),
('yuding-55','代人乞花','李益','唐','御定全唐诗','yuding','','[]','繡戶朝眠起，開簾滿地花。春風解人意，欲落妾西家。',24,'御定全唐詩/json/283.json','["繡戶朝眠起，開簾滿地花。春風解人意，欲落妾西家。"]'),
('yuding-56','上洛橋','李益','唐','御定全唐诗','yuding','','[]','金谷園中柳，春來似舞腰。何堪好風景，獨上洛陽橋。',24,'御定全唐詩/json/283.json','["金谷園中柳，春來似舞腰。何堪好風景，獨上洛陽橋。"]'),
('yuding-57','揚州懷古','李益','唐','御定全唐诗','yuding','','[]','故國歌鐘地，長橋車馬塵。彭城閣邊柳，偏似不勝春。',24,'御定全唐詩/json/283.json','["故國歌鐘地，長橋車馬塵。彭城閣邊柳，偏似不勝春。"]'),
('yuding-58','水宿聞雁','李益','唐','御定全唐诗','yuding','','[]','早雁忽為雙，驚秋風水窗。夜長人自起，星月滿空江。',24,'御定全唐詩/json/283.json','["早雁忽為雙，驚秋風水窗。夜長人自起，星月滿空江。"]'),
('yuding-59','揚州早雁','李益','唐','御定全唐诗','yuding','','[]','江上三千雁，年年過故宮。可憐江上月，偏照斷根蓬。',24,'御定全唐詩/json/283.json','["江上三千雁，年年過故宮。可憐江上月，偏照斷根蓬。"]'),
('yuding-60','下樓','李益','唐','御定全唐诗','yuding','','[]','話舊全應老，逢春喜又悲。看花行拭淚，倍覺下樓遲。',24,'御定全唐詩/json/283.json','["話舊全應老，逢春喜又悲。看花行拭淚，倍覺下樓遲。"]'),
('yuding-61','度破訥沙二首','李益','唐','御定全唐诗','yuding','','[]','眼見風來沙旋移，經年不省草生時。',64,'御定全唐詩/json/283.json','["眼見風來沙旋移，經年不省草生時。", "莫言塞北無春到，總有春來何處知。", "破訥沙頭雁正飛，鸊鵜泉上戰初歸。", "平明日出東南地，滿磧寒光生鐵衣。"]'),
('yuding-62','拂雲堆','李益','唐','御定全唐诗','yuding','','[]','漢將新從虜地來，旌旗半上拂雲堆。',32,'御定全唐詩/json/283.json','["漢將新從虜地來，旌旗半上拂雲堆。", "單于每近沙場獵，南望陰山哭始回。"]'),
('yuding-63','中橋北送穆質兄弟應制，戲贈蕭二策','李益','唐','御定全唐诗','yuding','','[]','洛水橋邊雁影疏，陸機兄弟駐行車。',32,'御定全唐詩/json/283.json','["洛水橋邊雁影疏，陸機兄弟駐行車。", "欲陳漢帝登封草，猶待蕭郎寄內書。"]'),
('yuding-64','九月十日雨中過張伯佳期柳鎮未至以詩招之','李益','唐','御定全唐诗','yuding','','[]','柳吳興近無消息，張長公貧苦寂寥。',32,'御定全唐詩/json/283.json','["柳吳興近無消息，張長公貧苦寂寥。", "唯有角巾沾雨至，手持殘菊向西招。"]'),
('yuding-65','汴河曲','李益','唐','御定全唐诗','yuding','','[]','汴水東流無限春，隋家宮闕已成塵。',32,'御定全唐詩/json/283.json','["汴水東流無限春，隋家宮闕已成塵。", "行人莫上長堤望，風起楊花愁殺人。"]'),
('yuding-66','塞下曲','李益','唐','御定全唐诗','yuding','','[]','蕃州部落能結束，朝暮馳獵黃河曲。',128,'御定全唐詩/json/283.json','["蕃州部落能結束，朝暮馳獵黃河曲。", "燕歌未斷塞鴻飛，牧馬群嘶邊草綠。", "秦築長城城已摧，漢武北上單于台。", "古來征戰虜不盡，今日還複天兵來。", "黃河東流流九折，沙場埋恨何時絕。", "蔡琰沒去造胡笳，蘇武歸來持漢節。", "為報如今都護雄，匈奴且莫下雲中。", "請書塞北陰山石，願比燕然車騎功。"]'),
('yuding-67','夜上西城聽梁州曲二首','李益','唐','御定全唐诗','yuding','','[]','行人夜上西城宿，聽唱梁州雙管逐。',64,'御定全唐詩/json/283.json','["行人夜上西城宿，聽唱梁州雙管逐。", "此時秋月滿關山，何處關山無此曲。", "鴻雁新從北地來，聞聲一半卻飛回。", "金河戍客腸應斷，更在秋風百尺台。"]'),
('yuding-68','暖川','李益','唐','御定全唐诗','yuding','','[]','胡風凍合鸊鵜泉，牧馬千群逐暖川。',32,'御定全唐詩/json/283.json','["胡風凍合鸊鵜泉，牧馬千群逐暖川。", "塞外征行無盡日，年年移帳雪中天。"]'),
('yuding-69','過馬嵬','李益','唐','御定全唐诗','yuding','','[]','漢將如雲不直言，寇來翻罪綺羅恩。',32,'御定全唐詩/json/283.json','["漢將如雲不直言，寇來翻罪綺羅恩。", "托君休洗蓮花血，留記千年妾淚痕。"]'),
('yuding-70','答許五端公馬上口號','李益','唐','御定全唐诗','yuding','','[]','晚逐旌旗俱白首，少遊京洛共緇塵。',32,'御定全唐詩/json/283.json','["晚逐旌旗俱白首，少遊京洛共緇塵。", "不堪身外悲前事，強向杯中覓舊春。"]'),
('yuding-71','牡丹','李益','唐','御定全唐诗','yuding','','[]','紫蕊叢開未到家，卻教遊客賞繁華。',32,'御定全唐詩/json/283.json','["紫蕊叢開未到家，卻教遊客賞繁華。", "始知年少求名處，滿眼空中別有花。"]'),
('yuding-72','邊思','李益','唐','御定全唐诗','yuding','','[]','腰懸錦帶佩吳鉤，走馬曾防玉塞秋。',32,'御定全唐詩/json/283.json','["腰懸錦帶佩吳鉤，走馬曾防玉塞秋。", "莫笑關西將家子，只將詩思入涼州。"]'),
('yuding-73','奉和武相公春曉聞鶯','李益','唐','御定全唐诗','yuding','','[]','蜀道山川心易驚，綠窗殘夢曉聞鶯。',32,'御定全唐詩/json/283.json','["蜀道山川心易驚，綠窗殘夢曉聞鶯。", "分明似寫文君恨，萬怨千愁弦上聲。"]'),
('yuding-74','送客還幽州','李益','唐','御定全唐诗','yuding','','[]','惆悵秦城送獨歸，薊門雲樹遠依依。',32,'御定全唐詩/json/283.json','["惆悵秦城送獨歸，薊門雲樹遠依依。", "秋來莫射南飛雁，從遣乘春更北飛。"]'),
('yuding-75','柳楊送客','李益','唐','御定全唐诗','yuding','','[]','青楓江畔白蘋洲，楚客傷離不待秋。',32,'御定全唐詩/json/283.json','["青楓江畔白蘋洲，楚客傷離不待秋。", "君見隋朝更何事，柳楊南渡水悠悠。"]'),
('yuding-76','從軍北征','李益','唐','御定全唐诗','yuding','','[]','天山雪後海風寒，橫笛偏吹行路難。',32,'御定全唐詩/json/283.json','["天山雪後海風寒，橫笛偏吹行路難。", "磧裏征人三十萬，一時回向月明看。"]'),
('yuding-77','聽曉角','李益','唐','御定全唐诗','yuding','','[]','邊霜昨夜墮關榆，吹角當城漢月孤。',32,'御定全唐詩/json/283.json','["邊霜昨夜墮關榆，吹角當城漢月孤。", "無限塞鴻飛不度，秋風捲入小單于。"]'),
('yuding-78','宮怨','李益','唐','御定全唐诗','yuding','','[]','露濕晴花春殿香，月明歌吹在昭陽。',32,'御定全唐詩/json/283.json','["露濕晴花春殿香，月明歌吹在昭陽。", "似將海水添宮漏，共滴長門一夜長。"]'),
('yuding-79','暮過回樂烽','李益','唐','御定全唐诗','yuding','','[]','烽火高飛百尺台，黃昏遙自磧西來。',32,'御定全唐詩/json/283.json','["烽火高飛百尺台，黃昏遙自磧西來。", "昔時征戰回應樂，今日從軍樂未回。"]'),
('yuding-80','奉和武相公郊居寓目','李益','唐','御定全唐诗','yuding','','[]','黃扉晚下禁垣鐘，歸坐南闈山萬重。',32,'御定全唐詩/json/283.json','["黃扉晚下禁垣鐘，歸坐南闈山萬重。", "獨有月中高興盡，雪峰明處見寒松。"]'),
('yuding-81','詣紅樓院尋廣宣不遇留題','李益','唐','御定全唐诗','yuding','','[]','柿葉翻紅霜景秋，碧天如水倚紅樓。',32,'御定全唐詩/json/283.json','["柿葉翻紅霜景秋，碧天如水倚紅樓。", "隔窗愛竹有人問，遣向鄰房覓戶鉤。"]'),
('yuding-82','回軍行','李益','唐','御定全唐诗','yuding','','[]','關城榆葉早疏黃，日暮沙雲古戰場。',32,'御定全唐詩/json/283.json','["關城榆葉早疏黃，日暮沙雲古戰場。", "表請回軍掩塵骨，莫教士卒哭龍荒。"]'),
('yuding-83','邠寧春日','李益','唐','御定全唐诗','yuding','','[]','桃李年年上國新，風沙日日塞垣人。',32,'御定全唐詩/json/283.json','["桃李年年上國新，風沙日日塞垣人。", "傷心更見庭前柳，忽有千條欲占春。"]'),
('yuding-84','古瑟怨','李益','唐','御定全唐诗','yuding','','[]','破瑟悲秋已減弦，湘靈沈怨不知年。',32,'御定全唐詩/json/283.json','["破瑟悲秋已減弦，湘靈沈怨不知年。", "感君拂拭遺音在，更奏新聲明月天。"]'),
('yuding-85','夜宴觀石將軍舞','李益','唐','御定全唐诗','yuding','','[]','微月東南上戍樓，琵琶起舞錦纏頭。',32,'御定全唐詩/json/283.json','["微月東南上戍樓，琵琶起舞錦纏頭。", "更聞橫笛關山遠，白草胡沙西塞秋。"]'),
('yuding-86','春夜聞笛','李益','唐','御定全唐诗','yuding','','[]','寒山吹笛喚春歸，遷客相看淚滿衣。',32,'御定全唐詩/json/283.json','["寒山吹笛喚春歸，遷客相看淚滿衣。", "洞庭一夜無窮雁，不待天明盡北飛。"]'),
('yuding-87','揚州送客','李益','唐','御定全唐诗','yuding','','[]','南行直入鷓鴣群，萬歲橋邊一送君。',32,'御定全唐詩/json/283.json','["南行直入鷓鴣群，萬歲橋邊一送君。", "聞道望鄉聞不得，梅花暗落嶺頭雲。"]'),
('yuding-88','統漢峰下','李益','唐','御定全唐诗','yuding','','[]','統漢峰西降戶營，黃河戰骨擁長城。',32,'御定全唐詩/json/283.json','["統漢峰西降戶營，黃河戰骨擁長城。", "只今已勒燕然石，北地無人空月明。"]'),
('yuding-89','避暑女冠','李益','唐','御定全唐诗','yuding','','[]','霧袖煙裾雲母冠，碧琉璃簟井冰寒。',32,'御定全唐詩/json/283.json','["霧袖煙裾雲母冠，碧琉璃簟井冰寒。", "焚香欲使三清鳥，靜拂桐陰上玉壇。"]'),
('yuding-90','行舟','李益','唐','御定全唐诗','yuding','','[]','柳花飛入正行舟，臥引菱花信碧流。',32,'御定全唐詩/json/283.json','["柳花飛入正行舟，臥引菱花信碧流。", "聞道風光滿揚子，天晴共上望鄉樓。"]'),
('yuding-91','隋宮燕','李益','唐','御定全唐诗','yuding','','[]','燕語如傷舊國春，宮花一落已成塵。',32,'御定全唐詩/json/283.json','["燕語如傷舊國春，宮花一落已成塵。", "自從一閉風光後，幾度飛來不見人。"]'),
('yuding-92','送人歸岳陽','李益','唐','御定全唐诗','yuding','','[]','煙草連天楓樹齊，岳陽歸路子規啼。',32,'御定全唐詩/json/283.json','["煙草連天楓樹齊，岳陽歸路子規啼。", "春江萬里巴陵戍，落日看沈碧水西。"]'),
('yuding-93','上汝州郡樓','李益','唐','御定全唐诗','yuding','','[]','黃昏鼓角似邊州，三十年前上此樓。',32,'御定全唐詩/json/283.json','["黃昏鼓角似邊州，三十年前上此樓。", "今日山城對垂淚，傷心不獨為悲秋。"]'),
('yuding-94','臨滹沱見蕃使列名','李益','唐','御定全唐诗','yuding','','[]','漠南春色到滹沱，碧柳青青塞馬多。',32,'御定全唐詩/json/283.json','["漠南春色到滹沱，碧柳青青塞馬多。", "萬里關山今不閉，漢家頻許郅支和。"]'),
('yuding-95','寫情','李益','唐','御定全唐诗','yuding','','[]','水紋珍簟思悠悠，千里佳期一夕休。',32,'御定全唐詩/json/283.json','["水紋珍簟思悠悠，千里佳期一夕休。", "從此無心愛良夜，任他明月下西樓。"]'),
('yuding-96','夜上受降城聞笛','李益','唐','御定全唐诗','yuding','','[]','回樂峰前沙似雪，受降城下月如霜。',32,'御定全唐詩/json/283.json','["回樂峰前沙似雪，受降城下月如霜。", "不知何處吹蘆管，一夜征人盡望鄉。"]'),
('yuding-97','赴渭北宿石泉驛南望黃堆烽','李益','唐','御定全唐诗','yuding','','[]','邊城已在虜城中，烽火南飛入漢宮。',32,'御定全唐詩/json/283.json','["邊城已在虜城中，烽火南飛入漢宮。", "漢庭議事先黃老，麟閣何人定戰功。"]'),
('yuding-98','逢歸信偶寄','李益','唐','御定全唐诗','yuding','','[]','無事將心寄柳條，等閒書字滿芭蕉。',32,'御定全唐詩/json/283.json','["無事將心寄柳條，等閒書字滿芭蕉。", "鄉關若有東流信，遣送揚州近驛橋。"]'),
('yuding-99','贈毛仙翁','李益','唐','御定全唐诗','yuding','','[]','玉樹溶溶仙氣深，含光混俗似無心。',32,'御定全唐詩/json/283.json','["玉樹溶溶仙氣深，含光混俗似無心。", "長愁忽作鶴飛去，一片孤雲何處尋。"]'),
('yuding-100','長幹行','李益','唐','御定全唐诗','yuding','','[]','憶妾深閨裏，煙塵不曾識。嫁與長幹人，沙頭候風色。',144,'御定全唐詩/json/283.json','["憶妾深閨裏，煙塵不曾識。嫁與長幹人，沙頭候風色。", "五月南風興，思君下巴陵。八月西風起，想君發揚子。", "去來悲如何，見少離別多。湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。渺渺暗無邊，行人在何處。", "好乘浮雲驄，佳期蘭渚東。鴛鴦綠浦上，翡翠錦屏中。", "自憐十五餘，顏色桃花紅。那作商人婦，愁水複愁風。"]'),
('yuding-101','和丘員外題湛長史舊居','李益','唐','御定全唐诗','yuding','','[]','昔降英王顧，屏身幽岩曲。靈波結繁笳，爽籟赴鳴玉。',72,'御定全唐詩/json/283.json','["昔降英王顧，屏身幽岩曲。靈波結繁笳，爽籟赴鳴玉。", "運轉春華至，歲來山草綠。青松掩落暉，白雲竟空穀。", "伊人撫遺歎，惻惻芳又縟。雲誰斅美香，分毫寄明牧。"]'),
('yuding-102','送客歸振武','李益','唐','御定全唐诗','yuding','','[]','駿馬事輕車，軍行萬里沙。胡山通嗢落，漢節繞渾邪。',48,'御定全唐詩/json/283.json','["駿馬事輕車，軍行萬里沙。胡山通嗢落，漢節繞渾邪。", "桂滿天西月，蘆吹塞北笳。別離俱報主，路極不為賒。"]'),
('yuding-103','府試古鏡','李益','唐','御定全唐诗','yuding','','[]','舊是秦時鏡，今藏古匣中。龍盤初掛月，鳳舞欲生風。',72,'御定全唐詩/json/283.json','["舊是秦時鏡，今藏古匣中。龍盤初掛月，鳳舞欲生風。", "石黛曾留殿，朱光適在宮。應祥知道泰，鑒物覺神通。", "肝膽誠難隱，妍媸信易窮。幸居君子室，長願免塵蒙。"]'),
('yuding-104','贈宣大師','李益','唐','御定全唐诗','yuding','','[]','一國沙彌獨解詩，人人道勝惠林師。先皇詔下征還日，',40,'御定全唐詩/json/283.json','["一國沙彌獨解詩，人人道勝惠林師。先皇詔下征還日，", "因論佛地求心地，只說常吟是住持。"]'),
('yuding-105','漢宮詞','李益','唐','御定全唐诗','yuding','','[]','漢室長陵小市東，珠簾繡戶對春風。',32,'御定全唐詩/json/283.json','["漢室長陵小市東，珠簾繡戶對春風。", "君王昨日移仙仗，玉輦將迎入漢中。"]'),
('yuding-106','江南曲','李益','唐','御定全唐诗','yuding','','[]','長樂花枝雨點銷，江城日暮好相邀。',32,'御定全唐詩/json/283.json','["長樂花枝雨點銷，江城日暮好相邀。", "春樓不閉葳蕤鎖，綠水回連宛轉橋。"]'),
('yuding-107','宿石邑山中','李益','唐','御定全唐诗','yuding','','[]','浮雲不共此山齊，山靄蒼蒼望轉迷。',32,'御定全唐詩/json/283.json','["浮雲不共此山齊，山靄蒼蒼望轉迷。", "曉月暫飛高樹裏，秋河隔在數峰西。"]'),
('yuding-108','寄贈衡州楊使君','李益','唐','御定全唐诗','yuding','','[]','湘竹斑斑湘水春，衡陽太守虎符新。',32,'御定全唐詩/json/283.json','["湘竹斑斑湘水春，衡陽太守虎符新。", "朝來笑向歸鴻道，早晚南飛見主人。"]'),
('yuding-109','途中寄李二','李益','唐','御定全唐诗','yuding','','[]','楊柳含煙灞岸春，年年攀折為行人。',32,'御定全唐詩/json/283.json','["楊柳含煙灞岸春，年年攀折為行人。", "好風若借低枝便，莫遣青絲掃路塵。"]'),
('yuding-110','寄許煉師','李益','唐','御定全唐诗','yuding','','[]','掃石焚香禮碧空，露華偏濕蕊珠宮。',32,'御定全唐詩/json/283.json','["掃石焚香禮碧空，露華偏濕蕊珠宮。", "如何說得天壇上，萬里無雲月在中。"]'),
('yuding-111','失題','李益','唐','御定全唐诗','yuding','','[]','世故相逢各未閑，百年多在別離間。',32,'御定全唐詩/json/283.json','["世故相逢各未閑，百年多在別離間。", "昨夜秋風今夜雨，不知何處入空山。"]'),
('yuding-112','塞下曲','李益','唐','御定全唐诗','yuding','','[]','伏波惟願裹屍還，定遠何須生入關。',32,'御定全唐詩/json/283.json','["伏波惟願裹屍還，定遠何須生入關。", "莫遣只輪歸海窟，仍留一箭射天山。"]'),
('yuding-113','上黃堆烽','李益','唐','御定全唐诗','yuding','','[]','心期紫閣山中月，身過黃堆烽上雲。',32,'御定全唐詩/json/283.json','["心期紫閣山中月，身過黃堆烽上雲。", "年發已從書劍老，戎衣更逐霍將軍。"]'),
('yuding-114','句','李益','唐','御定全唐诗','yuding','','[]','閒庭草色能留馬，當路楊花不避人。',16,'御定全唐詩/json/283.json','["閒庭草色能留馬，當路楊花不避人。"]'),
('yuding-0','古別離二首','李端','唐','御定全唐诗','yuding','','[]','水國葉黃時，洞庭霜落夜。行舟聞商估，宿在楓林下。',228,'御定全唐詩/json/284.json','["水國葉黃時，洞庭霜落夜。行舟聞商估，宿在楓林下。", "此地送君還，茫茫似夢間。後期知幾日，前路轉多山。", "巫峽通湘浦，迢迢隔雲雨。天晴見海檣，月落聞津鼓。", "人老自多愁，水深難急流。清宵歌一曲，白首對汀洲。", "與君桂陽別，令君岳陽待。後事忽差池，前期日空在。", "木落雁嗷嗷，洞庭波浪高。遠山雲似蓋，極浦樹如毫。", "朝發能幾裏，暮來風又起。如何兩處愁，皆在孤舟裏。", "昨夜天月明，長川寒且清。菊花開欲盡，薺菜泊來生。", "下江帆勢速，五兩遙相逐。欲問去時人，知投何處宿。", "空令猿嘯時，泣對湘簟竹。"]'),
('yuding-1','折楊柳','李端','唐','御定全唐诗','yuding','','[]','東城攀柳葉，柳葉低著草。少壯莫輕年，輕年有衰老。',120,'御定全唐詩/json/284.json','["東城攀柳葉，柳葉低著草。少壯莫輕年，輕年有衰老。", "柳發遍川岡，登高堪斷腸。雨煙輕漠漠，何樹近君鄉。", "贈君折楊柳，顏色豈能久。上客莫沾巾，佳人正回首。", "新柳送君行，古柳傷君情。突兀臨荒渡，婆娑出舊營。", "隋家兩岸盡，陶宅五株榮。日暮偏愁望，春山有鳥聲。"]'),
('yuding-2','留別柳中庸','李端','唐','御定全唐诗','yuding','','[]','惆悵流水時，蕭條背城路。離人出古亭，嘶馬入寒樹。',36,'御定全唐詩/json/284.json','["惆悵流水時，蕭條背城路。離人出古亭，嘶馬入寒樹。", "江海正風波，相逢在何處。"]'),
('yuding-3','野亭三韻送錢員外','李端','唐','御定全唐诗','yuding','','[]','野菊開欲稀，寒泉流漸淺。幽人步林後，歎此年華晚。',36,'御定全唐詩/json/284.json','["野菊開欲稀，寒泉流漸淺。幽人步林後，歎此年華晚。", "倚杖送行雲，尋思故山遠。"]'),
('yuding-4','歸山招王逵','李端','唐','御定全唐诗','yuding','','[]','日長原野靜，杖策步幽巘。雉雊麥苗陰，蝶飛溪草晚。',48,'御定全唐詩/json/284.json','["日長原野靜，杖策步幽巘。雉雊麥苗陰，蝶飛溪草晚。", "我生好閑放，此去殊未返。自是君不來，非關故山遠。"]'),
('yuding-5','過穀口元贊善所居','李端','唐','御定全唐诗','yuding','','[]','入穀訪君來，秋泉已堪涉。林間人獨坐，月下山相接。',48,'御定全唐詩/json/284.json','["入穀訪君來，秋泉已堪涉。林間人獨坐，月下山相接。", "重露濕蒼苔，明燈照黃葉。故交一不見，素發何稠疊。"]'),
('yuding-6','旅次岐山得山友書卻寄鳳翔張尹','李端','唐','御定全唐诗','yuding','','[]','本與戴征君，同師竹上坐。偶為名利引，久廢論真果。',36,'御定全唐詩/json/284.json','["本與戴征君，同師竹上坐。偶為名利引，久廢論真果。", "昨日山信回，寄書來責我。"]'),
('yuding-7','九日贈司空文明','李端','唐','御定全唐诗','yuding','','[]','我有惆悵詞，待君醉時說。長來逢九日，難與菊花別。',36,'御定全唐詩/json/284.json','["我有惆悵詞，待君醉時說。長來逢九日，難與菊花別。", "摘卻正開花，暫言花未發。"]'),
('yuding-8','蕪城','李端','唐','御定全唐诗','yuding','','[]','昔人登此地，丘隴已前悲。今日又非昔，春風能幾時。',48,'御定全唐詩/json/284.json','["昔人登此地，丘隴已前悲。今日又非昔，春風能幾時。", "風吹城上樹，草沒城邊路。城裏月明時，精靈自來去。"]'),
('yuding-9','送吉中孚拜官歸楚州','李端','唐','御定全唐诗','yuding','','[]','才子神骨清，虛竦眉眼明。貌應同衛玠，鬢且異潘生。',228,'御定全唐詩/json/284.json','["才子神骨清，虛竦眉眼明。貌應同衛玠，鬢且異潘生。", "初戴莓苔幘，來過丞相宅。滿堂歸道師，眾口宗詩伯。", "須臾裏巷傳，天子亦知賢。出詔升高士，馳聲在少年。", "自為才哲愛，日與侯王會。匡主一言中，榮親千裏外。", "更聞仙士友，往往東回首。驅石不成羊，指丹空斃狗。", "孤帆淮上歸，商估夜相依。海霧寒將盡，天星曉欲稀。", "潮頭來始歇，浦口喧爭發。鄉樹尚和雲，鄰船猶帶月。", "到洞必傷情，巡房見舊名。醮疏壇路澀，汲少井欄傾。", "別我長安道，前期共須老。方隨水向山，肯惜花辭島。", "悵望執君衣，今朝風景好。"]'),
('yuding-10','荊州泊','李端','唐','御定全唐诗','yuding','','[]','南樓西下時，月裏聞來棹。桂水舳艫回，荊州津濟鬧。',48,'御定全唐詩/json/284.json','["南樓西下時，月裏聞來棹。桂水舳艫回，荊州津濟鬧。", "移帷望星漢，引帶思容貌。今夜一江人，唯應妾身覺。"]'),
('yuding-11','春遊樂','李端','唐','御定全唐诗','yuding','','[]','游童蘇合彈，倡女蒲葵扇。初日映城時，相思忽相見。',48,'御定全唐詩/json/284.json','["游童蘇合彈，倡女蒲葵扇。初日映城時，相思忽相見。", "褰裳蹋路草，理鬢回花面。薄暮不同歸，留情此芳甸。"]'),
('yuding-12','千里思','李端','唐','御定全唐诗','yuding','','[]','涼州風月美，遙望居延路。泛泛下天雲，青青緣塞樹。',48,'御定全唐詩/json/284.json','["涼州風月美，遙望居延路。泛泛下天雲，青青緣塞樹。", "燕山蘇武上，海島田橫住。更是草生時，行人出門去。"]'),
('yuding-13','白鷺詠','李端','唐','御定全唐诗','yuding','','[]','迥起來應近，高飛去自遙。映林同落雪，拂水狀翻潮。',36,'御定全唐詩/json/284.json','["迥起來應近，高飛去自遙。映林同落雪，拂水狀翻潮。", "猶有幽人興，相逢到碧霄。"]'),
('yuding-14','冬夜與故友聚送吉校書','李端','唐','御定全唐诗','yuding','','[]','途窮別則怨，何必天涯去。共作出門人，不見歸鄉路。',84,'御定全唐詩/json/284.json','["途窮別則怨，何必天涯去。共作出門人，不見歸鄉路。", "殷勤執杯酒，悵望送親故。月色入閑軒，風聲落高樹。", "雲霄望且遠，齒發行應暮。九日泣黃花，三秋悲白露。", "君行過洛陽，莫向青山度。"]'),
('yuding-15','與苗員外山行','李端','唐','御定全唐诗','yuding','','[]','古人留路去，今日共君行。若待青山盡，應逢白髮生。',36,'御定全唐詩/json/284.json','["古人留路去，今日共君行。若待青山盡，應逢白髮生。", "誰知到蘭若，流落一書名。"]'),
('yuding-16','早春同庾侍郎題青龍上方院','李端','唐','御定全唐诗','yuding','','[]','相見惜餘輝，齊行登古寺。風煙結遠恨，山水含芳意。',36,'御定全唐詩/json/284.json','["相見惜餘輝，齊行登古寺。風煙結遠恨，山水含芳意。", "車馬莫前歸，留看巢鶴至。"]'),
('yuding-17','送從叔赴洪州','李端','唐','御定全唐诗','yuding','','[]','榮家兼佐幕，叔父似還鄉。王粲名雖重，郤超髯未長。',48,'御定全唐詩/json/284.json','["榮家兼佐幕，叔父似還鄉。王粲名雖重，郤超髯未長。", "鳴橈過夏口，斂笏見潯陽。後夜相思處，中庭月一方。"]'),
('yuding-18','送路司諫侍從叔赴洪州','李端','唐','御定全唐诗','yuding','','[]','郤超本絕倫，得意在芳春。勳業耿家盛，風流荀氏均。',168,'御定全唐詩/json/284.json','["郤超本絕倫，得意在芳春。勳業耿家盛，風流荀氏均。", "聲名金作賦，白皙玉為身。斂笏辭天子，乘龜從丈人。", "度關行且獵，鞍馬何躞蹀。猿嘯暮應愁，湖流春好涉。", "潯陽水分送，於越山相接。梅雨細如絲，蒲帆輕似葉。", "逢風燕不定，值石波先疊。樓見遠公廬，船經徐稚業。", "邑人多秉筆，州吏亦負笈。村女解收魚，津童能用楫。", "唯我有荊扉，無成未得歸。見君兄弟出，今日自沾衣。"]'),
('yuding-19','病後遊青龍寺','李端','唐','御定全唐诗','yuding','','[]','病來形貌穢，齋沐入東林。境靜聞神遠，身羸向道深。',36,'御定全唐詩/json/284.json','["病來形貌穢，齋沐入東林。境靜聞神遠，身羸向道深。", "芭蕉高自折，荷葉大先沈。"]'),
('yuding-20','夜尋司空文明逢深上人因寄晉侍禦','李端','唐','御定全唐诗','yuding','','[]','鶴裘筇竹杖，語笑過林中。正是月明夜，陶家見遠公。',36,'御定全唐詩/json/284.json','["鶴裘筇竹杖，語笑過林中。正是月明夜，陶家見遠公。", "自嫌山客務，不與漢官同。"]'),
('yuding-21','長安書事寄薛戴','李端','唐','御定全唐诗','yuding','','[]','朔雁去成行，哀蟬響如昨。時芳一憔悴，暮序何蕭索。',156,'御定全唐詩/json/284.json','["朔雁去成行，哀蟬響如昨。時芳一憔悴，暮序何蕭索。", "笑語且無聊，逢迎多約略。三山不可見，百歲空揮霍。", "故事盡為愁，新知無複樂。夫君又離別，而我加寂寞。", "惠遠縱相尋，陶潛只獨酌。主人恩則厚，客子才自薄。", "委曲見提攜，因循成蹇剝。論邊書未上，招隱詩還作。", "貴者已朝餐，豈能敦宿諾。飛禽雖失樹，流水長思壑。", "千里寄瓊枝，夢寐青山郭。"]'),
('yuding-22','鮮於少府宅看花','李端','唐','御定全唐诗','yuding','','[]','謝家能植藥，萬簇相縈倚。爛熳綠苔前，嬋娟青草裏。',168,'御定全唐詩/json/284.json','["謝家能植藥，萬簇相縈倚。爛熳綠苔前，嬋娟青草裏。", "垂欄複照戶，映竹仍臨水。驟雨發芳香，回風舒錦綺。", "孤光雜新故，眾色更重累。散碧出疏莖，分黃成細蕊。", "游蜂高更下，驚蝶坐還起。玉貌對應慚，霞標方不似。", "春陰憐弱蔓，夏日同短晷。回落報榮衰，交關鬥紅紫。", "花時苟未賞，老至誰能止。上客屢移床，幽僧勞憑幾。", "初合雖薄劣，卻得陪君子。敢問賢主人，何如種桃李。"]'),
('yuding-23','慈恩寺懷舊','李端','唐','御定全唐诗','yuding','','[]','去者不可憶，舊游相見時。淩霄徒更發，非是看花期。',264,'御定全唐詩/json/284.json','["去者不可憶，舊游相見時。淩霄徒更發，非是看花期。", "倚玉交文友，登龍年月久。東閣許聯床，西郊亦攜手。", "彼蒼何曖昧，薄劣翻居後。重入遠師溪，誰嘗陶令酒。", "伊昔會禪宮，容輝在眼中。籃輿來問道，玉柄解談空。", "孔席亡顏子，僧堂失謝公。遺文一書壁，新竹再移叢。", "始聚終成散，朝歡暮不同。春霞方照日，夜燭忽迎風。", "蟻鬥聲猶在，鴞災道已窮。問天應默默，歸宅太匆匆。", "淒其履還路，莽蒼雲林暮。九陌似無人，五陵空有霧。", "緬懷山陽笛，永恨平原賦。錯莫過門欄，分明識行路。", "上智本全真，郤公況重臣。唯應撫靈運，暫是憶嘉賓。", "存信松猶小，緘哀草尚新。鯉庭埋玉樹，那忍見門人。"]'),
('yuding-24','贈薛戴','李端','唐','御定全唐诗','yuding','','[]','曉霧忽為霜，寒蟬還罷響。行人在長道，日暮多歸想。',156,'御定全唐詩/json/284.json','["曉霧忽為霜，寒蟬還罷響。行人在長道，日暮多歸想。", "射策本何功，名登絳帳中。遂矜丘室重，不料阮途窮。", "交結慚時輩，龍鍾似老翁。機非鄙夫正，懶是平生性。", "欹枕鴻雁高，閉關花藥盛。廚煙當雨絕，階竹連窗暝。", "欲賦苦饑行，無如消渴病。舊業曆胡塵，荒原少四鄰。", "田園空有處，兄弟未成人。毛義心長苦，袁安家轉貧。", "今呈胸臆事，當為淚沾巾。"]'),
('yuding-25','東門送客','李端','唐','御定全唐诗','yuding','','[]','綠楊新草路，白髮故鄉人。既壯還應老，游梁複滯秦。',36,'御定全唐詩/json/284.json','["綠楊新草路，白髮故鄉人。既壯還應老，游梁複滯秦。", "逢花莫漫折，能有幾多春。"]'),
('yuding-26','送韓紳卿','李端','唐','御定全唐诗','yuding','','[]','春雨昨開花，秋霜忽沾草。榮枯催日夕，去住皆須老。',36,'御定全唐詩/json/284.json','["春雨昨開花，秋霜忽沾草。榮枯催日夕，去住皆須老。", "君望漢家原，高墳漸成道。"]'),
('yuding-27','襄陽曲','李端','唐','御定全唐诗','yuding','','[]','襄陽堤路長，草碧柳枝黃。誰家女兒臨夜妝，',44,'御定全唐詩/json/284.json','["襄陽堤路長，草碧柳枝黃。誰家女兒臨夜妝，", "同居女伴正衣裳，中庭寒月白如霜。賈生十八稱才子，"]'),
('yuding-28','胡騰兒','李端','唐','御定全唐诗','yuding','','[]','胡騰身是涼州兒，肌膚如玉鼻如錐。桐布輕衫前後卷，',72,'御定全唐詩/json/284.json','["胡騰身是涼州兒，肌膚如玉鼻如錐。桐布輕衫前後卷，", "安西舊牧收淚看，洛下詞人抄曲與。揚眉動目踏花氈，", "環行急蹴皆應節，反手叉腰如卻月。絲桐忽奏一曲終，"]'),
('yuding-29','贈康洽','李端','唐','御定全唐诗','yuding','','[]','黃須康兄酒泉客，平生出入王侯宅。今朝醉臥又明朝，',112,'御定全唐詩/json/284.json','["黃須康兄酒泉客，平生出入王侯宅。今朝醉臥又明朝，", "聲名恒壓鮑參軍，班位不過揚執戟。邇來七十遂無機，", "自言萬物有移改，始信桑田變成海。同時獻賦人皆盡，", "漢家尚壯今則老，發短心長知奈何。華堂舉杯白日晚，", "借問朦朧花樹下，誰家畚插築高臺。"]'),
('yuding-30','瘦馬行','李端','唐','御定全唐诗','yuding','','[]','城傍牧馬驅未過，一馬徘徊起還臥。眼中有淚皮有瘡，',72,'御定全唐詩/json/284.json','["城傍牧馬驅未過，一馬徘徊起還臥。眼中有淚皮有瘡，", "往時漢地相馳逐，如雨如風過平陸。豈意今朝驅不前，", "玉勒金鞍既已遠，追奔獲獸有誰知。終身櫪上食君草，"]'),
('yuding-31','雜歌呈鄭錫司空文明','李端','唐','御定全唐诗','yuding','','[]','昨宵夢到亡何鄉，忽見一人山之陽。高冠長劍立石堂，',88,'御定全唐詩/json/284.json','["昨宵夢到亡何鄉，忽見一人山之陽。高冠長劍立石堂，", "啖我還丹拍我背，令我延年在人代。乃書數字與我持，", "東嶺啼猿三四聲，捲簾一望心堪碎。蓬萊有梯不可躡，", "學仙去來辭故人，長安道路多風塵。"]'),
('yuding-32','雜歌','李端','唐','御定全唐诗','yuding','','[]','漢水至清泥則濁，松枝至堅蘿則弱。十三女兒事他家，',120,'御定全唐詩/json/284.json','["漢水至清泥則濁，松枝至堅蘿則弱。十三女兒事他家，", "為姑偏忌諸嫂良，作婦翻嫌婿家惡。人生照鏡須自知，", "伯奇掇蜂賢父逐，曾參殺人慈母疑。酒沽千日人不醉，", "山雞錦翼豈鳳凰，隴鳥人言止鸚鵡。向栩非才徒隱灶，", "樂生東去終居趙，陽虎北轅翻適楚。世間反復不易陳，"]'),
('yuding-33','烏棲曲','李端','唐','御定全唐诗','yuding','','[]','白馬逐朱車，黃昏入狹斜。狹斜柳樹烏爭宿，',20,'御定全唐詩/json/284.json','["白馬逐朱車，黃昏入狹斜。狹斜柳樹烏爭宿，"]'),
('yuding-34','送客東歸','李端','唐','御定全唐诗','yuding','','[]','昨夜東風吹盡雪，兩京路上梅花發。行人相見便東西，',24,'御定全唐詩/json/284.json','["昨夜東風吹盡雪，兩京路上梅花發。行人相見便東西，"]'),
('yuding-35','王敬伯歌','李端','唐','御定全唐诗','yuding','','[]','妾本舟中女，聞君江上琴。君初感妾意，妾亦感君心。',108,'御定全唐詩/json/284.json','["妾本舟中女，聞君江上琴。君初感妾意，妾亦感君心。", "遂出合歡被，同為交頸禽。傳杯唯畏淺，接膝猶嫌遠。", "侍婢奏箜篌，女郎歌宛轉。宛轉怨如何，中庭霜漸多。", "霜多葉可惜，昨日非今夕。徒結萬重歡，終成一宵客。", "王敬伯，綠水青山從此隔。"]'),
('yuding-36','救生寺望春寄暢當','李端','唐','御定全唐诗','yuding','','[]','東西南北望，望遠悲潛蓄。紅黃綠紫花，花開看不足。',40,'御定全唐詩/json/284.json','["東西南北望，望遠悲潛蓄。紅黃綠紫花，花開看不足。", "今年與子少相隨，他年與子老相逐。"]'),
('yuding-37','荊門歌送兄赴夔州','李端','唐','御定全唐诗','yuding','','[]','余兄佐郡經西楚，餞行因賦荊門雨。sC々燮燮聲漸繁，',121,'御定全唐詩/json/284.json','["余兄佐郡經西楚，餞行因賦荊門雨。sC々燮燮聲漸繁，", "雲間悵望荊衡路，萬里青山一時暮。琵琶寺裏響空廊。", "熨火陂前濕荒戍。沙尾長檣發漸稀，竹竿草屩涉流歸。", "夷陵已遠半成燒，漢上游倡始濯衣。船門相對多商估，", "曾為江客念江行，腸斷秋荷雨打聲。摩天古木不可見，"]'),
('yuding-38','妾薄命','李端','唐','御定全唐诗','yuding','','[]','憶妾初嫁君，花鬟如綠雲，回燈入綺帳，轉面脫羅裙。',92,'御定全唐詩/json/284.json','["憶妾初嫁君，花鬟如綠雲，回燈入綺帳，轉面脫羅裙。", "折步教人學，偷香與客熏。容顏南國重，名字北方聞。", "一從失恩意，轉覺身憔悴。對鏡不梳頭，倚窗空落淚。", "新人莫恃新，秋至會無春。從來閉在長門者，"]'),
('yuding-0','關山月','李端','唐','御定全唐诗','yuding','','[]','露濕月蒼蒼，關頭榆葉黃。回輪照海遠，分彩上樓長。',48,'御定全唐詩/json/285.json','["露濕月蒼蒼，關頭榆葉黃。回輪照海遠，分彩上樓長。", "水凍頻移幕，兵疲數望鄉。只應城影外，萬里共胡霜。"]'),
('yuding-1','度關山','李端','唐','御定全唐诗','yuding','','[]','雁塞日初晴，狐關雪複平。危樓緣廣漠，古竇傍長城。',48,'御定全唐詩/json/285.json','["雁塞日初晴，狐關雪複平。危樓緣廣漠，古竇傍長城。", "拂劍金星出，彎弧玉羽鳴。誰知系虜者，賈誼是書生。"]'),
('yuding-2','巫山高','李端','唐','御定全唐诗','yuding','','[]','巫山十二峰，皆在碧虛中。回合雲藏月，霏微雨帶風。',48,'御定全唐詩/json/285.json','["巫山十二峰，皆在碧虛中。回合雲藏月，霏微雨帶風。", "猿聲寒過澗，樹色暮連空。愁向高唐望，清秋見楚宮。"]'),
('yuding-3','雨雪曲','李端','唐','御定全唐诗','yuding','','[]','天山一丈雪，雜雨夜霏霏。濕馬胡歌亂，經烽漢火微。',48,'御定全唐詩/json/285.json','["天山一丈雪，雜雨夜霏霏。濕馬胡歌亂，經烽漢火微。", "丁零蘇武別，疏勒範羌歸。若看關頭下，長榆葉定稀。"]'),
('yuding-4','春遊樂','李端','唐','御定全唐诗','yuding','','[]','柘彈連錢馬，銀鉤妥墮鬟。摘桑春陌上，踏草夕陽間。',48,'御定全唐詩/json/285.json','["柘彈連錢馬，銀鉤妥墮鬟。摘桑春陌上，踏草夕陽間。", "意合辭先露，心誠貌卻閑。明朝若相憶，雲雨出巫山。"]'),
('yuding-5','山下泉','李端','唐','御定全唐诗','yuding','','[]','碧水映丹霞，濺濺度淺沙。暗通山下草，流出洞中花。',48,'御定全唐詩/json/285.json','["碧水映丹霞，濺濺度淺沙。暗通山下草，流出洞中花。", "淨色和雲落，喧聲繞石斜。明朝更尋去，應到阮郎家。"]'),
('yuding-6','送客赴洪州','李端','唐','御定全唐诗','yuding','','[]','草色隨驄馬，悠悠共出秦。水傳雲夢曉，山接洞庭春。',48,'御定全唐詩/json/285.json','["草色隨驄馬，悠悠共出秦。水傳雲夢曉，山接洞庭春。", "帆影連三峽，猿聲在四鄰。青門一分手，難見杜陵人。"]'),
('yuding-7','與鄭錫游春','李端','唐','御定全唐诗','yuding','','[]','東門垂柳長，回首獨心傷。日暖臨芳草，天晴憶故鄉。',48,'御定全唐詩/json/285.json','["東門垂柳長，回首獨心傷。日暖臨芳草，天晴憶故鄉。", "映花鶯上下，過水蝶飛揚。借問同行客，今朝淚幾行。"]'),
('yuding-8','送友人','李端','唐','御定全唐诗','yuding','','[]','聞說湘川路，年年古木多。猿啼巫峽夜，月照洞庭波。',48,'御定全唐詩/json/285.json','["聞說湘川路，年年古木多。猿啼巫峽夜，月照洞庭波。", "窮海人還去，孤城雁與過。青山不同賞，來往自蹉跎。"]'),
('yuding-9','題從叔沆林園','李端','唐','御定全唐诗','yuding','','[]','阮宅閑園暮，窗中見樹陰。樵歌依遠草，僧語過長林。',48,'御定全唐詩/json/285.json','["阮宅閑園暮，窗中見樹陰。樵歌依遠草，僧語過長林。", "鳥哢花間曲，人彈竹裏琴。自嫌身未老，已有住山心。"]'),
('yuding-10','送少微上人入蜀','李端','唐','御定全唐诗','yuding','','[]','削髮本求道，何方不是歸。松風開法席，江月濯禪衣。',48,'御定全唐詩/json/285.json','["削髮本求道，何方不是歸。松風開法席，江月濯禪衣。", "飛閣蟬鳴早，漫天客過稀。戴顒常執筆，不覺此身非。"]'),
('yuding-11','雨後遊輞川','李端','唐','御定全唐诗','yuding','','[]','驟雨歸山盡，頹陽入輞川。看虹登晚墅，踏石過青泉。',48,'御定全唐詩/json/285.json','["驟雨歸山盡，頹陽入輞川。看虹登晚墅，踏石過青泉。", "紫葛藏仙井，黃花出野田。自知無路去，回步就人煙。"]'),
('yuding-12','同皇甫侍禦題惟一上人房','李端','唐','御定全唐诗','yuding','','[]','焚香居一室，盡日見空林。得道輕年暮，安禪愛夜深。',48,'御定全唐詩/json/285.json','["焚香居一室，盡日見空林。得道輕年暮，安禪愛夜深。", "東西皆是夢，存沒豈關心。唯羨諸童子，持經在竹陰。"]'),
('yuding-13','同苗員外宿薦福寺僧舍','李端','唐','御定全唐诗','yuding','','[]','潘安秋興動，涼夜宿僧房。倚杖雲離月，垂簾竹有霜。',48,'御定全唐詩/json/285.json','["潘安秋興動，涼夜宿僧房。倚杖雲離月，垂簾竹有霜。", "回風生遠徑，落葉颯長廊。一與交親會，空貽別後傷。"]'),
('yuding-14','送客往湘江','李端','唐','御定全唐诗','yuding','','[]','識君年已老，孤棹向瀟湘。素發臨高鏡，清晨入遠鄉。',48,'御定全唐詩/json/285.json','["識君年已老，孤棹向瀟湘。素發臨高鏡，清晨入遠鄉。", "三山分夏口，五兩映涔陽。更逐巴東客，南行淚幾行。"]'),
('yuding-15','送友人游蜀','李端','唐','御定全唐诗','yuding','','[]','嘉陵天氣好，百里見雙流。帆影緣巴字，鐘聲出漢州。',48,'御定全唐詩/json/285.json','["嘉陵天氣好，百里見雙流。帆影緣巴字，鐘聲出漢州。", "綠原春草晚，青木暮猿愁。本是風流地，遊人易白頭。"]'),
('yuding-16','送友人游江東','李端','唐','御定全唐诗','yuding','','[]','江上花開盡，南行見杪春。鳥聲悲古木，雲影入通津。',48,'御定全唐詩/json/285.json','["江上花開盡，南行見杪春。鳥聲悲古木，雲影入通津。", "返景斜連草，回潮暗動蘋。謝公今在郡，應喜得詩人。"]'),
('yuding-17','送樂平苗明府得家字','李端','唐','御定全唐诗','yuding','','[]','本自求彭澤，誰雲道裏賒。山從石壁斷，江向弋陽斜。',48,'御定全唐詩/json/285.json','["本自求彭澤，誰雲道裏賒。山從石壁斷，江向弋陽斜。", "暮色隨楓樹，陰雲暗荻花。諸侯舊調鼎，應重宰臣家。"]'),
('yuding-18','過宋州','李端','唐','御定全唐诗','yuding','','[]','睢陽陷虜日，外絕救兵來。世亂忠臣死，時清明主哀。',48,'御定全唐詩/json/285.json','["睢陽陷虜日，外絕救兵來。世亂忠臣死，時清明主哀。", "荒郊春草遍，故壘野花開。欲為將軍哭，東流水不回。"]'),
('yuding-19','茂陵山行陪韋金部','李端','唐','御定全唐诗','yuding','','[]','宿雨朝來歇，空山秋氣清。盤雲雙鶴下，隔水一蟬鳴。',48,'御定全唐詩/json/285.json','["宿雨朝來歇，空山秋氣清。盤雲雙鶴下，隔水一蟬鳴。", "古道黃花落，平蕪赤燒生。茂陵雖有病，猶得伴君行。"]'),
('yuding-20','江上逢司空曙','李端','唐','御定全唐诗','yuding','','[]','共爾髫年故，相逢萬里餘。新春兩行淚，故國一封書。',48,'御定全唐詩/json/285.json','["共爾髫年故，相逢萬里餘。新春兩行淚，故國一封書。", "夏口帆初落，涔陽雁正疏。唯當執杯酒，暫食漢江魚。"]'),
('yuding-21','逢王泌自東京至','李端','唐','御定全唐诗','yuding','','[]','逢君自鄉至，雪涕問田園。幾處生喬木，誰家在舊村。',48,'御定全唐詩/json/285.json','["逢君自鄉至，雪涕問田園。幾處生喬木，誰家在舊村。", "山峰橫二室，水色映千門。愁見遊從處，如今花正繁。"]'),
('yuding-22','山中期吉中孚','李端','唐','御定全唐诗','yuding','','[]','行人路不同，花落到山中。水暗蒹葭霧，月明楊柳風。',48,'御定全唐詩/json/285.json','["行人路不同，花落到山中。水暗蒹葭霧，月明楊柳風。", "年華驚已擲，志業颯然空。何必龍鍾後，方期事遠公。"]'),
('yuding-23','酬前大理寺評事張芬','李端','唐','御定全唐诗','yuding','','[]','君家舊林壑，寄在亂峰西。近日春雲滿，相思路亦迷。',48,'御定全唐詩/json/285.json','["君家舊林壑，寄在亂峰西。近日春雲滿，相思路亦迷。", "聞鐘投野寺，待月過前溪。悵望成幽夢，依依識故蹊。"]'),
('yuding-24','賦得山泉送房造','李端','唐','御定全唐诗','yuding','','[]','泉水山邊去，高人月下看。潤松秋色淨，落澗夜聲寒。',48,'御定全唐詩/json/285.json','["泉水山邊去，高人月下看。潤松秋色淨，落澗夜聲寒。", "委曲穿深竹，潺湲過遠灘。聖朝無隱者，早晚罷漁竿。"]'),
('yuding-25','宿興善寺後堂池','李端','唐','御定全唐诗','yuding','','[]','草堂高樹下，月向後池生。野客如僧靜，新荷共水準。',48,'御定全唐詩/json/285.json','["草堂高樹下，月向後池生。野客如僧靜，新荷共水準。", "錦鱗沉不食，繡羽亂相鳴。即事思江海，誰能萬里行。"]'),
('yuding-26','憶皎然上人','李端','唐','御定全唐诗','yuding','','[]','未得從師去，人間萬事勞。雲門不可見，山木已應高。',48,'御定全唐詩/json/285.json','["未得從師去，人間萬事勞。雲門不可見，山木已應高。", "向日開柴戶，驚秋問敝袍。何由宿峰頂，窗裏望波濤。"]'),
('yuding-27','贈衡岳隱禪師','李端','唐','御定全唐诗','yuding','','[]','舊住衡州寺，隨緣偶北來。夜禪山雪下，朝汲竹門開。',48,'御定全唐詩/json/285.json','["舊住衡州寺，隨緣偶北來。夜禪山雪下，朝汲竹門開。", "半偈傳初盡，群生意未回。唯當與樵者，杖錫入天臺。"]'),
('yuding-28','雲陽觀寄袁稠','李端','唐','御定全唐诗','yuding','','[]','花洞晚陰陰，仙壇隔杏林。漱泉春谷冷，搗藥夜窗深。',48,'御定全唐詩/json/285.json','["花洞晚陰陰，仙壇隔杏林。漱泉春谷冷，搗藥夜窗深。", "石上開仙酌，松間對玉琴。戴家溪北住，雪後去相尋。"]'),
('yuding-29','晚游東田寄司空曙','李端','唐','御定全唐诗','yuding','','[]','暮來思遠客，獨立在東田。片雨無妨景，殘虹不映天。',48,'御定全唐詩/json/285.json','["暮來思遠客，獨立在東田。片雨無妨景，殘虹不映天。", "別愁逢夏果，歸興入秋蟬。莫作隳官意，陶潛未必賢。"]'),
('yuding-30','題崔端公園林','李端','唐','御定全唐诗','yuding','','[]','上士愛清輝，開門向翠微。抱琴看鶴去，枕石待雲歸。',48,'御定全唐詩/json/285.json','["上士愛清輝，開門向翠微。抱琴看鶴去，枕石待雲歸。", "野坐苔生席，高眠竹掛衣。舊山東望遠，惆悵暮花飛。"]'),
('yuding-31','早春雪夜寄盧綸兼呈秘書元丞','李端','唐','御定全唐诗','yuding','','[]','聞君隨謝脁，春夜宿前川。看竹雲垂地，尋僧月滿田。',48,'御定全唐詩/json/285.json','["聞君隨謝脁，春夜宿前川。看竹雲垂地，尋僧月滿田。", "熊寒方入樹，魚樂稍離船。獨夜羈愁客，惟知惜故年。"]'),
('yuding-32','早春夜集耿拾遺宅','李端','唐','御定全唐诗','yuding','','[]','如何逋客會，忽在侍臣家。新草猶停雪，寒梅未放花。',48,'御定全唐詩/json/285.json','["如何逋客會，忽在侍臣家。新草猶停雪，寒梅未放花。", "銜杯雞欲唱，逗月雁應斜。年齒俱憔悴，誰堪故國賒。"]'),
('yuding-33','元丞宅送胡浚及第東歸覲省','李端','唐','御定全唐诗','yuding','','[]','登龍兼折桂，歸去當高車。舊楚楓猶在，前隋柳已疏。',48,'御定全唐詩/json/285.json','["登龍兼折桂，歸去當高車。舊楚楓猶在，前隋柳已疏。", "月中逢海客，浪裏得鄉書。見說江邊住，知君不厭魚。"]'),
('yuding-34','送魏廣下第歸揚州甯親','李端','唐','御定全唐诗','yuding','','[]','遊宦今空返，浮淮一雁秋。白雲陰澤國，青草繞揚州。',48,'御定全唐詩/json/285.json','["遊宦今空返，浮淮一雁秋。白雲陰澤國，青草繞揚州。", "調膳過花下，張筵到水頭。昆山仍有玉，歲晏莫淹留。"]'),
('yuding-35','歸山與酒徒別','李端','唐','御定全唐诗','yuding','','[]','野客本無事，此來非有求。煩君征樂餞，未免憶山愁。',48,'御定全唐詩/json/285.json','["野客本無事，此來非有求。煩君征樂餞，未免憶山愁。", "紅燭侵明月，青娥促白頭。童心久已盡，豈為豔歌留。"]'),
('yuding-36','冬夜寄韓弇','李端','唐','御定全唐诗','yuding','','[]','獨坐知霜下，開門見木衰。壯應隨日去，老豈與人期。',48,'御定全唐詩/json/285.json','["獨坐知霜下，開門見木衰。壯應隨日去，老豈與人期。", "廢井蟲鳴早，陰階菊發遲。興來空憶戴，不似剡溪時。"]'),
('yuding-37','聞吉道士還俗因而有贈','李端','唐','御定全唐诗','yuding','','[]','聞有華陽客，儒裳謁紫微。舊山連藥賣，孤鶴帶雲歸。',48,'御定全唐詩/json/285.json','["聞有華陽客，儒裳謁紫微。舊山連藥賣，孤鶴帶雲歸。", "柳市名猶在，桃源夢已稀。還鄉見鷗鳥，應愧背船飛。"]'),
('yuding-38','韋員外東齋看花','李端','唐','御定全唐诗','yuding','','[]','入花凡幾步，此樹獨相留。發豔紅枝合，垂煙綠水幽。',48,'御定全唐詩/json/285.json','["入花凡幾步，此樹獨相留。發豔紅枝合，垂煙綠水幽。", "並開偏覺好，未落已成愁。一到芳菲下，空招兩鬢秋。"]'),
('yuding-39','邊頭作','李端','唐','御定全唐诗','yuding','','[]','邠郊泉脈動，落日上城樓。羊馬水草足，羌胡帳幕稠。',48,'御定全唐詩/json/285.json','["邠郊泉脈動，落日上城樓。羊馬水草足，羌胡帳幕稠。", "射雕過海岸，傳箭怯邊州。何事歸朝將，今年又拜侯。"]'),
('yuding-40','宿深上人院聽遠泉','李端','唐','御定全唐诗','yuding','','[]','泉聲宜遠聽，入夜對支公。斷續來方盡，潺湲咽又通。',48,'御定全唐詩/json/285.json','["泉聲宜遠聽，入夜對支公。斷續來方盡，潺湲咽又通。", "何年出石下，幾裏在山中。君問窮源處，禪心與此同。"]'),
('yuding-41','茂陵村行贈何兆','李端','唐','御定全唐诗','yuding','','[]','春天黃鳥囀，野徑白雲間。解帶依芳草，支頤想故山。',48,'御定全唐詩/json/285.json','["春天黃鳥囀，野徑白雲間。解帶依芳草，支頤想故山。", "人行九州路，樹老五陵間。誰道臨邛遠，相如自憶還。"]'),
('yuding-42','送友人還洛','李端','唐','御定全唐诗','yuding','','[]','去國渡關河，蟬鳴古樹多。平原正超忽，行子複蹉跎。',48,'御定全唐詩/json/285.json','["去國渡關河，蟬鳴古樹多。平原正超忽，行子複蹉跎。", "去事不可想，舊遊難再過。何當嵩嶽下，相見在煙蘿。"]'),
('yuding-43','送戴征士還山','李端','唐','御定全唐诗','yuding','','[]','柔桑錦臆雉，相送到煙霞。獨隱空山裏，閑門幾樹花。',48,'御定全唐詩/json/285.json','["柔桑錦臆雉，相送到煙霞。獨隱空山裏，閑門幾樹花。", "草生楊柳岸，鳥囀竹林家。不是謀生拙，無為末路賒。"]'),
('yuding-44','秋日旅舍別司空文明','李端','唐','御定全唐诗','yuding','','[]','涼風颯窮巷，秋思滿高雲。吏隱俱不就，此心仍別君。',48,'御定全唐詩/json/285.json','["涼風颯窮巷，秋思滿高雲。吏隱俱不就，此心仍別君。", "素懷宗淡泊，羈旅念功勳。轉憶西林寺，江聲月下聞。"]'),
('yuding-45','旅舍對雪贈考功王員外','李端','唐','御定全唐诗','yuding','','[]','楊花驚滿路，面市忽狂風。驟下搖蘭葉，輕飛集竹叢。',48,'御定全唐詩/json/285.json','["楊花驚滿路，面市忽狂風。驟下搖蘭葉，輕飛集竹叢。", "欲將瓊樹比，不共玉人同。獨望徽之棹，青山在雪中。"]'),
('yuding-46','送丁少府往唐上','李端','唐','御定全唐诗','yuding','','[]','因君灞陵別，故國一回看。共食田文飯，先之梅福官。',48,'御定全唐詩/json/285.json','["因君灞陵別，故國一回看。共食田文飯，先之梅福官。", "江風轉日暮，山月滿潮寒。不得同舟望，淹留歲月闌。"]'),
('yuding-47','贈李龜年','李端','唐','御定全唐诗','yuding','','[]','青春事漢主，白首入秦城。遍識才人字，多知舊曲名。',48,'御定全唐詩/json/285.json','["青春事漢主，白首入秦城。遍識才人字，多知舊曲名。", "風流隨故事，語笑合新聲。獨有垂楊樹，偏傷日暮情。"]'),
('yuding-48','送郭補闕歸江陽','李端','唐','御定全唐诗','yuding','','[]','東門春尚淺，楊柳未成陰。雁影愁斜日，鶯聲怨故林。',48,'御定全唐詩/json/285.json','["東門春尚淺，楊柳未成陰。雁影愁斜日，鶯聲怨故林。", "隋宮江上遠，梁苑雪中深。獨有懷歸客，難為欲別心。"]'),
('yuding-49','早春會王逵主人得蓬字','李端','唐','御定全唐诗','yuding','','[]','今年華鬢色，半在故人中。欲寫無窮恨，先期一醉同。',48,'御定全唐詩/json/285.json','["今年華鬢色，半在故人中。欲寫無窮恨，先期一醉同。", "綠叢猶覆雪，紅萼已凋風。莫負歸山契，君看陌上蓬。"]'),
('yuding-50','宿山寺思歸','李端','唐','御定全唐诗','yuding','','[]','僧房秋雨歇，愁臥夜更深。欹枕聞鴻雁，回燈見竹林。',48,'御定全唐詩/json/285.json','["僧房秋雨歇，愁臥夜更深。欹枕聞鴻雁，回燈見竹林。", "歸螢入草盡，落月映窗沉。拭淚無人覺，長謠向壁陰。"]'),
('yuding-51','送客赴江陵寄郢州郎士元','李端','唐','御定全唐诗','yuding','','[]','露下晚蟬愁，詩人舊怨秋。沅湘莫留滯，宛洛好遨遊。',48,'御定全唐詩/json/285.json','["露下晚蟬愁，詩人舊怨秋。沅湘莫留滯，宛洛好遨遊。", "飲馬逢黃菊，離家值白頭。竟陵明月夜，為上庾公樓。"]'),
('yuding-52','送客賦得巴江夜猿','李端','唐','御定全唐诗','yuding','','[]','巴水天邊路，啼猿傷客情。遲遲雲外盡，杳杳樹中生。',48,'御定全唐詩/json/285.json','["巴水天邊路，啼猿傷客情。遲遲雲外盡，杳杳樹中生。", "殘月暗將落，空霜寒欲明。楚人皆掩淚，聞到第三聲。"]'),
('yuding-53','秋日憶暕上人','李端','唐','御定全唐诗','yuding','','[]','一從持缽別，更未到人間。好靜居貧寺，遺名棄近山。',48,'御定全唐詩/json/285.json','["一從持缽別，更未到人間。好靜居貧寺，遺名棄近山。", "雨前縫百衲，葉下閉重關。若便潯陽去，須將舊客還。"]'),
('yuding-54','寄上舍人叔','李端','唐','御定全唐诗','yuding','','[]','車馬朝初下，看山憶獨尋。會知逢水盡，且愛入雲深。',48,'御定全唐詩/json/285.json','["車馬朝初下，看山憶獨尋。會知逢水盡，且愛入雲深。", "殘雨開斜日，新蟬發迥林。阮咸雖別巷，遙識此時心。"]'),
('yuding-55','送古之奇赴安西幕','李端','唐','御定全唐诗','yuding','','[]','疇昔十年兄，相逢五校營。今宵舉杯酒，隴月見軍城。',48,'御定全唐詩/json/285.json','["疇昔十年兄，相逢五校營。今宵舉杯酒，隴月見軍城。", "堠火經陰絕，邊人接曉行。殷勤送書記，強虜幾時平。"]'),
('yuding-56','送張芬歸江東兼寄柳中庸','李端','唐','御定全唐诗','yuding','','[]','久是天涯客，偏傷落木時。如何故國見，更欲異鄉期。',48,'御定全唐詩/json/285.json','["久是天涯客，偏傷落木時。如何故國見，更欲異鄉期。", "鳥暮東西急，波寒上下遲。空將滿眼淚，千里怨相思。"]'),
('yuding-57','送丘丹歸江東','李端','唐','御定全唐诗','yuding','','[]','故山霜落久，才子憶荊扉。旅舍尋人別，秋風逐雁歸。',48,'御定全唐詩/json/285.json','["故山霜落久，才子憶荊扉。旅舍尋人別，秋風逐雁歸。", "夢愁楓葉盡，醉惜菊花稀。肯學求名者，經年未拂衣。"]'),
('yuding-58','臥病寄苗員外','李端','唐','御定全唐诗','yuding','','[]','故人初未貴，相見得淹留。一自朝天去，因成計日遊。',48,'御定全唐詩/json/285.json','["故人初未貴，相見得淹留。一自朝天去，因成計日遊。", "月明應獨醉，葉下肯同愁。因恨劉楨病，空園臥見秋。"]'),
('yuding-59','送楊皋擢第歸江東','李端','唐','御定全唐诗','yuding','','[]','隋堤望楚國，江上一歸人。綠氣千檣暮，青風萬里春。',48,'御定全唐詩/json/285.json','["隋堤望楚國，江上一歸人。綠氣千檣暮，青風萬里春。", "試才初得桂，泊渚肯傷蘋。拜手終悽愴，恭承中外親。"]'),
('yuding-60','題鄭少府林園','李端','唐','御定全唐诗','yuding','','[]','謝家今日晚，詞客願抽毫。櫪馬方回影，池鵝正理毛。',48,'御定全唐詩/json/285.json','["謝家今日晚，詞客願抽毫。櫪馬方回影，池鵝正理毛。", "竹筒傳水遠，麈尾坐僧高。獨有宗雷賤，過君著敝袍。"]'),
('yuding-61','送吉中孚拜官歸業','李端','唐','御定全唐诗','yuding','','[]','南入華陽洞，無人古樹寒。吟詩開舊帙，帶綬上荒壇。',48,'御定全唐詩/json/285.json','["南入華陽洞，無人古樹寒。吟詩開舊帙，帶綬上荒壇。", "因病求歸易，沾恩更隱難。孟宗應獻鮓，家近守漁官。"]'),
('yuding-62','送楊少府赴陽翟','李端','唐','御定全唐诗','yuding','','[]','冠帶仁兄後，光輝壽母前。陸雲還入洛，潘嶽更張筵。',48,'御定全唐詩/json/285.json','["冠帶仁兄後，光輝壽母前。陸雲還入洛，潘嶽更張筵。", "井邑嵩山對，園林潁水連。東人欲相送，旅舍已潸然。"]'),
('yuding-63','慈恩寺暕上人房招耿拾遺','李端','唐','御定全唐诗','yuding','','[]','悠然對惠遠，共結故山期。汲井樹陰下，閉門亭午時。',48,'御定全唐詩/json/285.json','["悠然對惠遠，共結故山期。汲井樹陰下，閉門亭午時。", "地閑花落厚，石淺水流遲。願與神仙客，同來事本師。"]'),
('yuding-64','宿山寺雪夜寄吉中孚','李端','唐','御定全唐诗','yuding','','[]','獨愛僧房竹，春來長到池。雲遮皆晃朗，雪壓半低垂。',48,'御定全唐詩/json/285.json','["獨愛僧房竹，春來長到池。雲遮皆晃朗，雪壓半低垂。", "不見侵山葉，空聞拂地枝。鄙夫今夜興，唯有子猷知。"]'),
('yuding-65','贈趙神童','李端','唐','御定全唐诗','yuding','','[]','聖朝殊漢令，才子少登科。每見先鳴早，常驚後進多。',48,'御定全唐詩/json/285.json','["聖朝殊漢令，才子少登科。每見先鳴早，常驚後進多。", "獨居方寂寞，相對覺蹉跎。不是通家舊，頻勞文舉過。"]'),
('yuding-66','宿雲際寺贈深上人','李端','唐','御定全唐诗','yuding','','[]','暫別青藍寺，今來發欲斑。獨眠孤燭下，風雨在前山。',48,'御定全唐詩/json/285.json','["暫別青藍寺，今來發欲斑。獨眠孤燭下，風雨在前山。", "壞宅終須去，空門不易還。支公有方便，一願啟玄關。"]'),
('yuding-67','送從兄赴洪州別駕兄善琴','李端','唐','御定全唐诗','yuding','','[]','援琴兼愛竹，遙夜在湘沅。鶴舞月將下，烏啼霜正繁。',48,'御定全唐詩/json/285.json','["援琴兼愛竹，遙夜在湘沅。鶴舞月將下，烏啼霜正繁。", "亂流喧橘岸，飛雪暗荊門。佐郡無辭屈，其如相府恩。"]'),
('yuding-68','山中期張芬不至','李端','唐','御定全唐诗','yuding','','[]','石堤春草碧，雙燕向西飛。悵望雲天暮，佳人何處歸。',48,'御定全唐詩/json/285.json','["石堤春草碧，雙燕向西飛。悵望雲天暮，佳人何處歸。", "藥欄蟲網遍，苔井水痕稀。誰道嵇康懶，山中自掩扉。"]'),
('yuding-69','寄暢當','李端','唐','御定全唐诗','yuding','','[]','麥秀草芊芊，幽人好晝眠。雲霞生嶺上，猿鳥下床前。',48,'御定全唐詩/json/285.json','["麥秀草芊芊，幽人好晝眠。雲霞生嶺上，猿鳥下床前。", "顏子方敦行，支郎久住禪。中林輕暫別，約略已經年。"]'),
('yuding-70','送義興元少府','李端','唐','御定全唐诗','yuding','','[]','逢君惠連第，初命便光輝。已得群公祖，終妨太傅譏。',48,'御定全唐詩/json/285.json','["逢君惠連第，初命便光輝。已得群公祖，終妨太傅譏。", "路長人反顧，草斷燕回飛。本是江南客，還同衣錦歸。"]'),
('yuding-71','臥病別鄭錫','李端','唐','御定全唐诗','yuding','','[]','病來喜無事，多臥竹林間。此日一相見，明朝還掩關。',48,'御定全唐詩/json/285.json','["病來喜無事，多臥竹林間。此日一相見，明朝還掩關。", "幽人愛芳草，志士惜頹顏。歲晏不我棄，期君在故山。"]'),
('yuding-72','書志贈暢當','李端','唐','御定全唐诗','yuding','','[]','少喜神仙術，未去已蹉跎。壯志一為累，浮生事漸多。',48,'御定全唐詩/json/285.json','["少喜神仙術，未去已蹉跎。壯志一為累，浮生事漸多。", "衰顏不相識，歲暮定相過。請問宗居士，君其奈老何。"]'),
('yuding-73','送諸暨裴少府','李端','唐','御定全唐诗','yuding','','[]','山公訪嵇紹，趙武見韓侯。事去恩猶在，名成淚卻流。',48,'御定全唐詩/json/285.json','["山公訪嵇紹，趙武見韓侯。事去恩猶在，名成淚卻流。", "一官同北去，千里赴南州。才子清風後，無貽相府憂。"]'),
('yuding-74','送鄭宥入蜀迎覲','李端','唐','御定全唐诗','yuding','','[]','寧親西陟險，君去異王陽。在世誰非客，還家即是鄉。',48,'御定全唐詩/json/285.json','["寧親西陟險，君去異王陽。在世誰非客，還家即是鄉。", "劍門千轉盡，巴水一支長。請語愁猿道，無煩促淚行。"]'),
('yuding-75','送耿拾遺湋使江南括圖書','李端','唐','御定全唐诗','yuding','','[]','驅傳草連天，回風滿樹蟬。將過夫子宅，前問孝廉船。',48,'御定全唐詩/json/285.json','["驅傳草連天，回風滿樹蟬。將過夫子宅，前問孝廉船。", "漢使收三篋，周詩采百篇。別來將有淚，不是怨流年。"]'),
('yuding-76','送王少府游河南','李端','唐','御定全唐诗','yuding','','[]','馬卿方失意，東去謁諸侯。過宋人應少，游梁客獨愁。',48,'御定全唐詩/json/285.json','["馬卿方失意，東去謁諸侯。過宋人應少，游梁客獨愁。", "鳥翻千室暮，蟬急兩河秋。僕本無媒者，因君淚亦流。"]'),
('yuding-77','送別駕赴晉陵即舍人叔之兄','李端','唐','御定全唐诗','yuding','','[]','諸宗稱叔父，從子亦光輝。謝脁中書直，王祥別乘歸。',48,'御定全唐詩/json/285.json','["諸宗稱叔父，從子亦光輝。謝脁中書直，王祥別乘歸。", "江帆沖雨上，海樹隔潮微。南阮貧無酒，唯將淚濕衣。"]'),
('yuding-78','臥病寄閻寀','李端','唐','御定全唐诗','yuding','','[]','病中貪好景，強步出幽居。紫葛垂山徑，黃花繞野渠。',48,'御定全唐詩/json/285.json','["病中貪好景，強步出幽居。紫葛垂山徑，黃花繞野渠。", "荒林飛老鶴，敗堰過遊魚。縱憶同年友，無人可寄書。"]'),
('yuding-79','晚夏聞蟬寄廣文','李端','唐','御定全唐诗','yuding','','[]','昨日鶯囀聲，今朝蟬忽鳴。朱顏向華髮，定是幾年程。',48,'御定全唐詩/json/285.json','["昨日鶯囀聲，今朝蟬忽鳴。朱顏向華髮，定是幾年程。", "故國白雲遠，閒居青草生。因垂數行淚，書報十年兄。"]'),
('yuding-80','歸山居寄錢起','李端','唐','御定全唐诗','yuding','','[]','悵望青山下，回頭淚滿巾。故鄉多古樹，落日少行人。',48,'御定全唐詩/json/285.json','["悵望青山下，回頭淚滿巾。故鄉多古樹，落日少行人。", "髮鬢將回色，簪纓未到身。誰知武陵路，亦有漢家臣。"]'),
('yuding-81','曉發瓜州','李端','唐','御定全唐诗','yuding','','[]','曉發悲行客，停橈獨未前。寒江半有月，野戍漸無煙。',48,'御定全唐詩/json/285.json','["曉發悲行客，停橈獨未前。寒江半有月，野戍漸無煙。", "棹唱臨高岸，鴻嘶發遠田。誰知避徒禦，對酒一潸然。"]'),
('yuding-82','江上喜逢司空文明','李端','唐','御定全唐诗','yuding','','[]','秦人江上見，握手淚沾巾。落日見秋草，暮年逢故人。',48,'御定全唐詩/json/285.json','["秦人江上見，握手淚沾巾。落日見秋草，暮年逢故人。", "非夫長作客，多病淺謀身。台閣舊親友，誰曾見苦辛。"]'),
('yuding-83','同苗發慈恩寺避暑','李端','唐','御定全唐诗','yuding','','[]','追涼尋寶刹，畏日望璿題。臥草同鴛侶，臨池似虎溪。',48,'御定全唐詩/json/285.json','["追涼尋寶刹，畏日望璿題。臥草同鴛侶，臨池似虎溪。", "樹閑人跡外，山晚鳥行西。若問無心法，蓮花隔淤泥。"]'),
('yuding-84','送潘述宏詞下第歸江外','李端','唐','御定全唐诗','yuding','','[]','唱高人不和，此去淚難收。上國經年住，長江滿目流。',48,'御定全唐詩/json/285.json','["唱高人不和，此去淚難收。上國經年住，長江滿目流。", "弈棋知勝偶，射策請焚舟。應是田□□，玄成許爾遊。"]'),
('yuding-85','送張少府赴夏縣','李端','唐','御定全唐诗','yuding','','[]','雖為州縣職，還欲抱琴過。樹古聞風早，山枯見雪多。',48,'御定全唐詩/json/285.json','["雖為州縣職，還欲抱琴過。樹古聞風早，山枯見雪多。", "雞聲連絳市，馬色傍黃河。太守新臨郡，還逢五袴歌。"]'),
('yuding-86','酬秘書元丞郊園臥疾見寄','李端','唐','御定全唐诗','yuding','','[]','聞說漳濱臥，題詩怨歲華。求醫主高手，報疾到貧家。',48,'御定全唐詩/json/285.json','["聞說漳濱臥，題詩怨歲華。求醫主高手，報疾到貧家。", "撒枕銷行蟻，移杯失畫蛇。明朝九衢上，應見玉人車。"]'),
('yuding-87','送成都韋丞還蜀','李端','唐','御定全唐诗','yuding','','[]','蜀門雲樹合，高棧有猿愁。驅傳加新命，之官向舊遊。',48,'御定全唐詩/json/285.json','["蜀門雲樹合，高棧有猿愁。驅傳加新命，之官向舊遊。", "晨裝逢酒雨，夜夢見刀州。遠別長相憶，當年莫滯留。"]'),
('yuding-88','晚秋旅舍寄苗員外','李端','唐','御定全唐诗','yuding','','[]','爭途苦不前，貧病遂連牽。向暮同行客，當秋獨長年。',48,'御定全唐詩/json/285.json','["爭途苦不前，貧病遂連牽。向暮同行客，當秋獨長年。", "晚花唯有菊，寒葉已無蟬。吏部逢今日，還應甕下眠。"]'),
('yuding-89','送惟良上人歸潤州','李端','唐','御定全唐诗','yuding','','[]','擬詩偏不類，又送上人歸。寄世同高鶴，尋仙稱壞衣。',48,'御定全唐詩/json/285.json','["擬詩偏不類，又送上人歸。寄世同高鶴，尋仙稱壞衣。", "雨行江草短，露坐海帆稀。正被空門縛，臨岐乞解圍。"]'),
('yuding-90','送何兆下第還蜀','李端','唐','御定全唐诗','yuding','','[]','重江不可涉，孤客莫晨裝。高木莎城小，殘星棧道長。',48,'御定全唐詩/json/285.json','["重江不可涉，孤客莫晨裝。高木莎城小，殘星棧道長。", "嫋猿楓子落，過雨荔枝香。勸爾成都住，文翁有草堂。"]'),
('yuding-91','送友人宰湘陰','李端','唐','御定全唐诗','yuding','','[]','從宦舟行遠，浮湘又入閩。蒹葭無朔雁，檉栝有蠻神。',48,'御定全唐詩/json/285.json','["從宦舟行遠，浮湘又入閩。蒹葭無朔雁，檉栝有蠻神。", "傳吏閑調象，山精暗訟人。唯須千樹橘，暫救李衡貧。"]'),
('yuding-92','送元晟歸江東舊居','李端','唐','御定全唐诗','yuding','','[]','澤國舟車接，關門雨雪乖。春天行故楚，夜月下清淮。',48,'御定全唐詩/json/285.json','["澤國舟車接，關門雨雪乖。春天行故楚，夜月下清淮。", "講易居山寺，論詩到郡齋。蔣家人暫別，三路草連階。"]'),
('yuding-93','送黎少府赴陽翟','李端','唐','御定全唐诗','yuding','','[]','詩禮稱才子，神仙是丈人。玉山那惜醉，金穀已無春。',48,'御定全唐詩/json/285.json','["詩禮稱才子，神仙是丈人。玉山那惜醉，金穀已無春。", "白馬如風疾，青袍奪草新。不嫌鳴吠客，願用百年身。"]'),
('yuding-94','送夏侯審游蜀','李端','唐','御定全唐诗','yuding','','[]','西望煙綿樹，愁君上蜀時。同林息商客，隔棧見罛師。',48,'御定全唐詩/json/285.json','["西望煙綿樹，愁君上蜀時。同林息商客，隔棧見罛師。", "石滑羊腸險，山空杜宇悲。琴心正幽怨，莫奏鳳凰詩。"]'),
('yuding-95','單推官廳前雙桐詠','李端','唐','御定全唐诗','yuding','','[]','封植因高興，孤貞契素期。由來得地早，何事結花遲。',48,'御定全唐詩/json/285.json','["封植因高興，孤貞契素期。由來得地早，何事結花遲。", "葉重凝煙後，條寒過雨時。還同李家樹，爭賦角弓詩。"]'),
('yuding-96','送宋校書赴宣州幕','李端','唐','御定全唐诗','yuding','','[]','浮舟壓芳草，容裔逐江春。遠避看書吏，行當入幕賓。',48,'御定全唐詩/json/285.json','["浮舟壓芳草，容裔逐江春。遠避看書吏，行當入幕賓。", "夜潮沖老樹，曉雨破輕蘋。鴛鷺多傷別，欒家德在人。"]'),
('yuding-97','送趙給事侄尉丹陽','李端','唐','御定全唐诗','yuding','','[]','太傅憐群從，門人亦賤回。入官先愛子，賜酒許同杯。',48,'御定全唐詩/json/285.json','["太傅憐群從，門人亦賤回。入官先愛子，賜酒許同杯。", "淮海春多雨，蒹葭夜有雷。遙知拜慶後，梅尉稱仙才。"]'),
('yuding-98','宿瓜洲寄柳中庸','李端','唐','御定全唐诗','yuding','','[]','懷人同不寐，清夜起論文。月魄正出海，雁行斜上雲。',48,'御定全唐詩/json/285.json','["懷人同不寐，清夜起論文。月魄正出海，雁行斜上雲。", "寒潮來灩灩，秋葉下紛紛。便送江東去，徘徊只待君。"]'),
('yuding-99','夜宴虢縣張明府宅逢宇文評事','李端','唐','御定全唐诗','yuding','','[]','虢田留古宅，入夜足秋風。月影來窗裏，燈光落水中。',48,'御定全唐詩/json/285.json','["虢田留古宅，入夜足秋風。月影來窗裏，燈光落水中。", "征詩逢謝客，飲酒得陶公。更愛疏籬下，繁霜濕菊叢。"]'),
('yuding-100','冬夜集張尹後閣','李端','唐','御定全唐诗','yuding','','[]','乘龜兼戴豸，白麵映朱衣。安石還須起，泉明不得歸。',48,'御定全唐詩/json/285.json','["乘龜兼戴豸，白麵映朱衣。安石還須起，泉明不得歸。", "應門常吏在，登席舊寮稀。遠客長先醉，那知亞相威。"]'),
('yuding-101','將之澤潞留別王郎中','李端','唐','御定全唐诗','yuding','','[]','弱年知己少，前路主人稀。貧病期相惜，艱難又憶歸。',48,'御定全唐詩/json/285.json','["弱年知己少，前路主人稀。貧病期相惜，艱難又憶歸。", "事成應未蔔，身賤又無機。幸到龍門下，須因羽翼飛。"]'),
('yuding-102','晚次巴陵','李端','唐','御定全唐诗','yuding','','[]','雪後柳條新，巴陵城下人。烹魚邀水客，載酒奠山神。',48,'御定全唐詩/json/285.json','["雪後柳條新，巴陵城下人。烹魚邀水客，載酒奠山神。", "雲去低斑竹，波回動白蘋。不堪逢楚老，日暮正江春。"]'),
('yuding-103','送荀道士歸廬山','李端','唐','御定全唐诗','yuding','','[]','先生歸有處，欲別笑無言。綠水到山口，青林連洞門。',48,'御定全唐詩/json/285.json','["先生歸有處，欲別笑無言。綠水到山口，青林連洞門。", "月明尋石路，雲霽望花源。早晚還乘鶴，悲歌向故園。"]'),
('yuding-104','送張淑歸覲叔父','李端','唐','御定全唐诗','yuding','','[]','日慘長亭暮，天高大澤閑。風中聞草木，雪裏見江山。',48,'御定全唐詩/json/285.json','["日慘長亭暮，天高大澤閑。風中聞草木，雪裏見江山。", "馬向塞雲去，人隨古道還。阮家今夜樂，應在竹林間。"]'),
('yuding-105','送郭參軍赴絳州','李端','唐','御定全唐诗','yuding','','[]','登車君莫望，故絳柳條春。蒲澤逢胡雁，桃源見晉人。',48,'御定全唐詩/json/285.json','["登車君莫望，故絳柳條春。蒲澤逢胡雁，桃源見晉人。", "佐軍髯尚短，擲地思還新。小謝常攜手，因之醉路塵。"]'),
('yuding-106','送袁稠游江南','李端','唐','御定全唐诗','yuding','','[]','江南衰草遍，十裏見長亭。客去逢搖落，鴻飛入杳冥。',48,'御定全唐詩/json/285.json','["江南衰草遍，十裏見長亭。客去逢搖落，鴻飛入杳冥。", "空城寒雨細，深院曉燈青。欲去行人起，徘徊恨酒醒。"]'),
('yuding-107','送夏中丞赴甯國任','李端','唐','御定全唐诗','yuding','','[]','楚縣入青楓，長江一派通。板橋尋謝客，古邑事陶公。',48,'御定全唐詩/json/285.json','["楚縣入青楓，長江一派通。板橋尋謝客，古邑事陶公。", "片雨收山外，連雲上漢東。陸機猶滯洛，念子望南鴻。"]'),
('yuding-108','送衛雄下第歸同州','李端','唐','御定全唐诗','yuding','','[]','不才先上第，詞客卻空還。邊地行人少，平蕪盡日閑。',48,'御定全唐詩/json/285.json','["不才先上第，詞客卻空還。邊地行人少，平蕪盡日閑。", "一蟬陂樹裏，眾火隴雲間。羨汝歸茅屋，書窗見遠山。"]'),
('yuding-109','送單少府赴扶風','李端','唐','御定全唐诗','yuding','','[]','少年趨盛府，顏色比花枝。范匄非童子，楊修豈小兒。',48,'御定全唐詩/json/285.json','["少年趨盛府，顏色比花枝。范匄非童子，楊修豈小兒。", "叨陪丈人行，常恐阿戎欺。此去雲霄近，看君逸足馳。"]'),
('yuding-110','題山中別業','李端','唐','御定全唐诗','yuding','','[]','舊宅在山中，閑門與寺通。往來黃葉路，交結白頭翁。',48,'御定全唐詩/json/285.json','["舊宅在山中，閑門與寺通。往來黃葉路，交結白頭翁。", "晚筍難成竹，秋花不滿叢。生涯只粗糲，吾豈諱言窮。"]'),
('yuding-111','送司空文明歸江上舊居','李端','唐','御定全唐诗','yuding','','[]','野菊有黃花，送君千里還。鴻來燕又去，離別惜容顏。',48,'御定全唐詩/json/285.json','["野菊有黃花，送君千里還。鴻來燕又去，離別惜容顏。", "流水通歸夢，行雲失故關。江風正搖落，宋玉莫登山。"]'),
('yuding-112','送新城戴叔倫明府','李端','唐','御定全唐诗','yuding','','[]','遙想隋堤路，春天楚國情。白雲當海斷，青草隔淮生。',48,'御定全唐詩/json/285.json','["遙想隋堤路，春天楚國情。白雲當海斷，青草隔淮生。", "雁起斜還直，潮回遠複平。萊蕪不可到，一醉送君行。"]'),
('yuding-113','送雍丘任少府','李端','唐','御定全唐诗','yuding','','[]','叢車餞才子，路走許東偏。遠水同春色，繁花勝雪天。',48,'御定全唐詩/json/285.json','["叢車餞才子，路走許東偏。遠水同春色，繁花勝雪天。", "鳥行侵楚邑，樹影向殷田。莫學生鄉思，梅真正少年。"]'),
('yuding-114','送雍郢州','李端','唐','御定全唐诗','yuding','','[]','厭郎思出守，遂領漢東軍。望月逢殷浩，緣江送範雲。',48,'御定全唐詩/json/285.json','["厭郎思出守，遂領漢東軍。望月逢殷浩，緣江送範雲。", "城閑煙草遍，浦迥雪林分。誰伴樓中宿，吟詩估客聞。"]'),
('yuding-115','寄王密卿','李端','唐','御定全唐诗','yuding','','[]','酒樂今年少，僧期近日頻。買山多為竹，卜宅不緣貧。',48,'御定全唐詩/json/285.json','["酒樂今年少，僧期近日頻。買山多為竹，卜宅不緣貧。", "志業歸初地，文章寄此身。嵇康雖有病，猶得見情人。"]'),
('yuding-116','與蕭遠上人游少華山寄皇甫侍禦','李端','唐','御定全唐诗','yuding','','[]','尋危兼采藥，渡水又登山。獨與高僧去，逍遙落日間。',48,'御定全唐詩/json/285.json','["尋危兼采藥，渡水又登山。獨與高僧去，逍遙落日間。", "漸看閭裏遠，自覺性情閑。回首知音在，因令悵望還。"]'),
('yuding-117','代村中老人答','李端','唐','御定全唐诗','yuding','','[]','京洛風塵後，村鄉煙火稀。少年曾失所，衰暮欲何依。',48,'御定全唐詩/json/285.json','["京洛風塵後，村鄉煙火稀。少年曾失所，衰暮欲何依。", "夜靜臨江哭，天寒踏雪歸。時清應不見，言罷淚盈衣。"]'),
('yuding-118','贈故將軍','李端','唐','御定全唐诗','yuding','','[]','平生在邊日，鞍馬若星流。獨出間千里，相知滿九州。',48,'御定全唐詩/json/285.json','["平生在邊日，鞍馬若星流。獨出間千里，相知滿九州。", "恃功淩主將，作氣見王侯。誰道廉頗老，猶能報遠讎。"]'),
('yuding-119','送陸郎中歸田司空幕','李端','唐','御定全唐诗','yuding','','[]','漢家分列宿，東土佐諸侯。結束還軍府，光輝過禦溝。',48,'御定全唐詩/json/285.json','["漢家分列宿，東土佐諸侯。結束還軍府，光輝過禦溝。", "農桑連紫陌，分野入青州。覆被恩難報，西看成白頭。"]'),
('yuding-120','酬晉侍禦見寄','李端','唐','御定全唐诗','yuding','','[]','野客蒙詩贈，殊恩欲報難。本求文舉識，不在子真官。',48,'御定全唐詩/json/285.json','["野客蒙詩贈，殊恩欲報難。本求文舉識，不在子真官。", "細雨雙林暮，重陽九日寒。貧齋一叢菊，願與上賓看。"]'),
('yuding-121','送銅澤王歸城','李端','唐','御定全唐诗','yuding','','[]','昔聞公族出，其從亦高車。為善唯求樂，分貧必及疏。',48,'御定全唐詩/json/285.json','["昔聞公族出，其從亦高車。為善唯求樂，分貧必及疏。", "身承漢枝葉，手習魯詩書。尚說無功德，三年在石渠。"]'),
('yuding-122','江上別柳中庸','李端','唐','御定全唐诗','yuding','','[]','秦人江上見，握手便沾衣。近日相知少，往年親故稀。',48,'御定全唐詩/json/285.json','["秦人江上見，握手便沾衣。近日相知少，往年親故稀。", "遠遊何處去，舊業幾時歸。更向巴陵宿，堪聞雁北飛。"]'),
('yuding-123','喜皇甫郎中拜諭德兼集賢學士','李端','唐','御定全唐诗','yuding','','[]','為郎三載後，寵命一朝新。望苑遷詞客，儒林拜丈人。',48,'御定全唐詩/json/285.json','["為郎三載後，寵命一朝新。望苑遷詞客，儒林拜丈人。", "鶯飛綺閣曙，柳拂畫堂春。幾日調金鼎，諸君欲望塵。"]'),
('yuding-124','送黎兵曹往陝府結婚','李端','唐','御定全唐诗','yuding','','[]','東方發車騎，君是上頭人。奠雁逢良日，行媒及仲春。',48,'御定全唐詩/json/285.json','["東方發車騎，君是上頭人。奠雁逢良日，行媒及仲春。", "時稱渡河婦，宜配坦床賓。安得同門吏，揚鞭入後塵。"]'),
('yuding-125','送竇兵曹','李端','唐','御定全唐诗','yuding','','[]','梨花開上苑，游女著羅衣。聞道情人怨，應須走馬歸。',48,'御定全唐詩/json/285.json','["梨花開上苑，游女著羅衣。聞道情人怨，應須走馬歸。", "禦橋遲日暖，官渡早鶯稀。莫遣佳期過，看看蝴蝶飛。"]'),
('yuding-126','留別故人','李端','唐','御定全唐诗','yuding','','[]','此別不可道，此心當語誰。春風灞水上，飲馬桃花時。',48,'御定全唐詩/json/285.json','["此別不可道，此心當語誰。春風灞水上，飲馬桃花時。", "誤作好文士，只應游宦遲。留書下朝客，我有故山期。"]'),
('yuding-127','奉送宋中丞使河源','李端','唐','御定全唐诗','yuding','','[]','東周遣戍役，才子欲離群。部領河源去，悠悠隴水分。',48,'御定全唐詩/json/285.json','["東周遣戍役，才子欲離群。部領河源去，悠悠隴水分。", "笳聲悲塞草，馬首渡關雲。辛苦逢炎熱，何時及漢軍。"]'),
('yuding-128','都亭驛送郭判官之幽州幕府','李端','唐','御定全唐诗','yuding','','[]','幕府參戎事，承明伏奏歸。都亭使者出，杯酒故人違。',48,'御定全唐詩/json/285.json','["幕府參戎事，承明伏奏歸。都亭使者出，杯酒故人違。", "細雨沾官騎，輕風拂客衣。還從大夫後，吾党亦光輝。"]'),
('yuding-129','送王羽林往秦州','李端','唐','御定全唐诗','yuding','','[]','秦州貴公子，漢日羽林郎。事主來中禁，榮親上北堂。',48,'御定全唐詩/json/285.json','["秦州貴公子，漢日羽林郎。事主來中禁，榮親上北堂。", "輶車花擁路，寶劍雪生光。直掃三邊靖，承恩向建章。"]'),
('yuding-130','送友入關','李端','唐','御定全唐诗','yuding','','[]','聞君帝城去，西望一沾巾。落日見秋草，暮年逢故人。',48,'御定全唐詩/json/285.json','["聞君帝城去，西望一沾巾。落日見秋草，暮年逢故人。", "非才長作客，有命懶謀身。近更嬰衰疾，空思老漢濱。"]'),
('yuding-131','代宗挽歌','李端','唐','御定全唐诗','yuding','','[]','祖庭三獻罷，嚴衛百靈朝。警蹕移前殿，宮車上渭橋。',48,'御定全唐詩/json/285.json','["祖庭三獻罷，嚴衛百靈朝。警蹕移前殿，宮車上渭橋。", "寒霜凝羽葆，野吹咽笳簫。已向新京兆，誰雲天路遙。"]'),
('yuding-132','張左丞挽歌二首','李端','唐','御定全唐诗','yuding','','[]','素旆低寒水，清笳出曉風。鳥來傷賈傅，馬立葬滕公。',96,'御定全唐詩/json/285.json','["素旆低寒水，清笳出曉風。鳥來傷賈傅，馬立葬滕公。", "松柏青山上，城池白日中。一朝今古隔，唯有月明同。", "禍集鉤方失，災生劍忽飛。無由就日拜，空憶自天歸。", "門吏看還葬，宮官識賜衣。東堂哀贈畢，從此故臣稀。"]'),
('yuding-133','奉和王元二相避暑懷杜太尉','李端','唐','御定全唐诗','yuding','','[]','艱難嘗共理，海晏更相悲。況複登堂處，分明避暑時。',48,'御定全唐詩/json/285.json','["艱難嘗共理，海晏更相悲。況複登堂處，分明避暑時。", "綠槐千穗綻，丹藥一番遲。蓬蓽今何幸，先朝大雅詩。"]'),
('yuding-134','青龍寺題故曇上人房','李端','唐','御定全唐诗','yuding','','[]','遠公留故院，一徑雪中微。童子逢皆老，門人問亦稀。',48,'御定全唐詩/json/285.json','["遠公留故院，一徑雪中微。童子逢皆老，門人問亦稀。", "翻經徒有處，攜履遂無歸。空念尋巢鶴，時來傍影飛。"]'),
('yuding-135','早春夜望','李端','唐','御定全唐诗','yuding','','[]','舊雪逐泥沙，新雷發草芽。曉霜應傍鬢，夜雨莫催花。',48,'御定全唐詩/json/285.json','["舊雪逐泥沙，新雷發草芽。曉霜應傍鬢，夜雨莫催花。", "行矣前途晚，歸與故國賒。不勞報春盡，從此惜年華。"]'),
('yuding-136','宴伊東岸','李端','唐','御定全唐诗','yuding','','[]','晴洲無遠近，一樹一潭春。芳草留歸騎，朱櫻擲舞人。',48,'御定全唐詩/json/285.json','["晴洲無遠近，一樹一潭春。芳草留歸騎，朱櫻擲舞人。", "空花對酒落，小翠隔林新。竟日皆攜手，何由遇此辰。"]'),
('yuding-137','雲際中峰居喜見苗發','李端','唐','御定全唐诗','yuding','','[]','自得中峰住，深林亦閉關。經秋無客到，入夜有僧還。',48,'御定全唐詩/json/285.json','["自得中峰住，深林亦閉關。經秋無客到，入夜有僧還。", "暗澗泉聲小，荒村樹影閑。高窗不可望，星月滿空山。"]'),
('yuding-138','宿洞庭','李端','唐','御定全唐诗','yuding','','[]','白水連天暮，洪波帶日流。風高雲夢夕，月滿洞庭秋。',48,'御定全唐詩/json/285.json','["白水連天暮，洪波帶日流。風高雲夢夕，月滿洞庭秋。", "沙上漁人火，煙中賈客舟。西園與南浦，萬里共悠悠。"]'),
('yuding-139','江上賽神','李端','唐','御定全唐诗','yuding','','[]','疏鼓應繁絲，送神歸九疑。蒼龍隨赤鳳，帝子上天時。',48,'御定全唐詩/json/285.json','["疏鼓應繁絲，送神歸九疑。蒼龍隨赤鳳，帝子上天時。", "驟雨歸山疾，長江下日遲。獨憐遊宦子，今夜泊天涯。"]'),
('yuding-140','奉和元丞侍從游南城別業','李端','唐','御定全唐诗','yuding','','[]','垂朱領孫子，從宴在池塘。獻壽回龜顧，和羹躍鯉香。',48,'御定全唐詩/json/285.json','["垂朱領孫子，從宴在池塘。獻壽回龜顧，和羹躍鯉香。", "高松先草晚，平石助泉涼。餘橘期相及，門生有陸郎。"]'),
('yuding-141','送從舅成都丞廣南歸蜀','李端','唐','御定全唐诗','yuding','','[]','巴字天邊水，秦人去是歸。棧長山雨響，溪亂火田稀。',48,'御定全唐詩/json/285.json','["巴字天邊水，秦人去是歸。棧長山雨響，溪亂火田稀。", "俗富行應樂，官雄祿豈微。魏舒終有淚，還濕寧家衣。"]'),
('yuding-0','贈郭駙馬','李端','唐','御定全唐诗','yuding','','[]','青春都尉最風流，二十功成便拜侯。金距鬥雞過上苑，',80,'御定全唐詩/json/286.json','["青春都尉最風流，二十功成便拜侯。金距鬥雞過上苑，", "日暮吹簫楊柳陌，路人遙指鳳凰樓。", "方塘似鏡草芊芊，初月如鉤未上弦。新開金埒看調馬，", "今朝都尉如相顧，原脫長裾學少年。"]'),
('yuding-1','宿淮浦憶司空文明','李端','唐','御定全唐诗','yuding','','[]','愁心一倍長離憂，夜思千重戀舊遊。秦地故人成遠夢，',40,'御定全唐詩/json/286.json','["愁心一倍長離憂，夜思千重戀舊遊。秦地故人成遠夢，", "別恨轉深何處寫，前程唯有一登樓。"]'),
('yuding-2','送濮陽錄事赴忠州','李端','唐','御定全唐诗','yuding','','[]','成名不遂雙旌遠，主印還為一郡雄。赤葉黃花隨野岸，',40,'御定全唐詩/json/286.json','["成名不遂雙旌遠，主印還為一郡雄。赤葉黃花隨野岸，", "聞說古書多未校，肯令才子久西東。"]'),
('yuding-3','送馬尊師','李端','唐','御定全唐诗','yuding','','[]','南入商山松路深，石床溪水晝陰陰。雲中采藥隨青節，',40,'御定全唐詩/json/286.json','["南入商山松路深，石床溪水晝陰陰。雲中采藥隨青節，", "武陵花木應長在，願與漁人更一尋。"]'),
('yuding-4','題元注林園','李端','唐','御定全唐诗','yuding','','[]','謝家門館似山林，碧石青苔滿樹陰。乳鵲眄巢花巷靜，',40,'御定全唐詩/json/286.json','["謝家門館似山林，碧石青苔滿樹陰。乳鵲眄巢花巷靜，", "獨有野人箕踞慣，過君始得一長吟。"]'),
('yuding-5','野寺病居喜盧綸見訪','李端','唐','御定全唐诗','yuding','','[]','青青麥壟白雲陰，古寺無人新草深。乳燕拾泥依古井，',40,'御定全唐詩/json/286.json','["青青麥壟白雲陰，古寺無人新草深。乳燕拾泥依古井，", "一臥漳濱今欲老，誰知才子忽相尋。"]'),
('yuding-6','送皎然上人歸山','李端','唐','御定全唐诗','yuding','','[]','適來世上豈緣名，適去人間豈為情。古寺山中幾日到，',40,'御定全唐詩/json/286.json','["適來世上豈緣名，適去人間豈為情。古寺山中幾日到，", "法主欲歸須有說，門人流淚厭浮生。"]'),
('yuding-7','贈道士','李端','唐','御定全唐诗','yuding','','[]','姓氏不書高士傳，形神自得逸人風。已傳花洞將秦接，',40,'御定全唐詩/json/286.json','["姓氏不書高士傳，形神自得逸人風。已傳花洞將秦接，", "終朝賣卜無人識，敝服徒行入市中。"]'),
('yuding-8','題雲際寺准上人房','李端','唐','御定全唐诗','yuding','','[]','高僧居處似天臺，錫仗銅瓶對綠苔。竹巷雨晴春鳥囀，',40,'御定全唐詩/json/286.json','["高僧居處似天臺，錫仗銅瓶對綠苔。竹巷雨晴春鳥囀，", "獨夜焚香禮遺像，空林月出始應回。"]'),
('yuding-9','山中寄苗員外','李端','唐','御定全唐诗','yuding','','[]','鳥鳴花發空山裏，衡嶽幽人藉草時。既近淺流安筆硯，',40,'御定全唐詩/json/286.json','["鳥鳴花發空山裏，衡嶽幽人藉草時。既近淺流安筆硯，", "聞說潘安方寓直，與君相見漸難期。"]'),
('yuding-10','憶故山贈司空曙','李端','唐','御定全唐诗','yuding','','[]','漢主金門正召才，馬卿多病自遲回。舊山暫別老將至，',40,'御定全唐詩/json/286.json','["漢主金門正召才，馬卿多病自遲回。舊山暫別老將至，", "知君素有棲禪意，歲晏蓬門遲爾開。"]'),
('yuding-11','閑園即事贈考功王員外','李端','唐','御定全唐诗','yuding','','[]','南陌晴雲稍變霞，東風動柳水紋斜。園林帶雪潛生草，',40,'御定全唐詩/json/286.json','["南陌晴雲稍變霞，東風動柳水紋斜。園林帶雪潛生草，", "今朝一望還成暮，欲別芳菲戀歲華。"]'),
('yuding-12','寄廬山真上人','李端','唐','御定全唐诗','yuding','','[]','高僧無跡本難尋，更得禪行去轉深。青草湖中看五老，',40,'御定全唐詩/json/286.json','["高僧無跡本難尋，更得禪行去轉深。青草湖中看五老，", "更說謝公南座好，煙蘿到地幾重陰。"]'),
('yuding-13','題覺公新蘭若','李端','唐','御定全唐诗','yuding','','[]','頭白禪師何處還，獨開蘭若樹林間。鬼因巫祝傳移社，',40,'御定全唐詩/json/286.json','["頭白禪師何處還，獨開蘭若樹林間。鬼因巫祝傳移社，", "新齋結誓如相許，願與雷宗永閉關。"]'),
('yuding-14','贈道者','李端','唐','御定全唐诗','yuding','','[]','窗中忽有鶴飛聲，方士因知道欲成。來取圖書安枕裏，',40,'御定全唐詩/json/286.json','["窗中忽有鶴飛聲，方士因知道欲成。來取圖書安枕裏，", "送客自傷身易老，不知何處待先生。"]'),
('yuding-15','代棄婦答賈客','李端','唐','御定全唐诗','yuding','','[]','玉壘城邊爭走馬，銅鞮市里共乘舟。鳴環動佩恩無盡，',40,'御定全唐詩/json/286.json','["玉壘城邊爭走馬，銅鞮市里共乘舟。鳴環動佩恩無盡，", "忍懷賤妾平生曲，獨上襄陽舊酒樓。"]'),
('yuding-16','和李舍人直中書對月見寄','李端','唐','御定全唐诗','yuding','','[]','名卿步月正淹留，上客裁詩怨別遊。素魄近成班女扇，',40,'御定全唐詩/json/286.json','["名卿步月正淹留，上客裁詩怨別遊。素魄近成班女扇，", "盈手入懷皆不見，陽春曲麗轉難酬。"]'),
('yuding-17','臥病聞吉中孚拜官寄元秘書昆季','李端','唐','御定全唐诗','yuding','','[]','漢家采使不求聲，自慰文章道欲行。毛遂登門雖異賞，',40,'御定全唐詩/json/286.json','["漢家采使不求聲，自慰文章道欲行。毛遂登門雖異賞，", "年少奉親皆願達，敢將心事向玄成。"]'),
('yuding-18','江上逢柳中庸','李端','唐','御定全唐诗','yuding','','[]','舊住衡山曾夜歸，見君江客憶荊扉。星沉嶺上人行早，',40,'御定全唐詩/json/286.json','["舊住衡山曾夜歸，見君江客憶荊扉。星沉嶺上人行早，", "今來唯有禪心在，鄉路翻成向翠微。"]'),
('yuding-19','戲贈韓判官紳卿','李端','唐','御定全唐诗','yuding','','[]','少尋道士居嵩嶺，晚事高僧住沃洲。齒發未知何處老，',40,'御定全唐詩/json/286.json','["少尋道士居嵩嶺，晚事高僧住沃洲。齒發未知何處老，", "獨怪子猷緣掌馬，雪時不肯更乘舟。"]'),
('yuding-20','送周長史','李端','唐','御定全唐诗','yuding','','[]','青楓樹裏宣城郡，獨佐諸侯上板橋。江客亦能傳好信，',40,'御定全唐詩/json/286.json','["青楓樹裏宣城郡，獨佐諸侯上板橋。江客亦能傳好信，", "別有空園落桃杏，知將絲組系蘭橈。"]'),
('yuding-21','題故將軍莊','李端','唐','御定全唐诗','yuding','','[]','曾將數騎過桑幹，遙對單于飭馬鞍。塞北征兒諳用劍，',40,'御定全唐詩/json/286.json','["曾將數騎過桑幹，遙對單于飭馬鞍。塞北征兒諳用劍，", "唯有老身如刻畫，猶期聖主解衣看。"]'),
('yuding-22','夜投豐德寺謁海上人','李端','唐','御定全唐诗','yuding','','[]','半夜中峰有磬聲，偶尋樵者問山名。上方月曉聞僧語，',40,'御定全唐詩/json/286.json','["半夜中峰有磬聲，偶尋樵者問山名。上方月曉聞僧語，", "願得遠山知姓字，焚香洗缽過餘生。"]'),
('yuding-23','塞上','李端','唐','御定全唐诗','yuding','','[]','二十在邊城，軍中得勇名。卷旗收敗馬，占磧擁殘兵。',72,'御定全唐詩/json/286.json','["二十在邊城，軍中得勇名。卷旗收敗馬，占磧擁殘兵。", "覆陣烏鳶起，燒山草木明。塞閑思遠獵，師老厭分營。", "雪嶺無人跡，冰河足雁聲。李陵甘此沒，惆悵漢公卿。"]'),
('yuding-24','送彭將軍雲中覲兄','李端','唐','御定全唐诗','yuding','','[]','聞說蒼鷹守，今朝欲下鞲。因令白馬將，兼道覓封侯。',72,'御定全唐詩/json/286.json','["聞說蒼鷹守，今朝欲下鞲。因令白馬將，兼道覓封侯。", "略地關山冷，防河雨雪稠。翻弓騁猿臂，承箭惜貂裘。", "設伏軍謀密，坑降塞邑愁。報恩唯有死，莫使漢家羞。"]'),
('yuding-25','奉贈苗員外','李端','唐','御定全唐诗','yuding','','[]','朱戶敞高扉，青槐礙落暉。八龍承慶重，三虎遞朝歸。',72,'御定全唐詩/json/286.json','["朱戶敞高扉，青槐礙落暉。八龍承慶重，三虎遞朝歸。", "坐竹人聲絕，橫琴鳥語稀。花慚潘嶽貌，年稱老萊衣。", "葉暗新櫻熟，絲長粉蝶飛。應憐魯儒賤，空與故山違。"]'),
('yuding-26','酬丘拱外甥覽余舊文見寄','李端','唐','御定全唐诗','yuding','','[]','丘遲本才子，始冠即周旋。舅乏郤鑒愛，君如衛玠賢。',120,'御定全唐詩/json/286.json','["丘遲本才子，始冠即周旋。舅乏郤鑒愛，君如衛玠賢。", "禮將金友等，情向玉人偏。鄙俗那勞似，龍鍾卻要憐。", "投磚聊取笑，贈綺一何妍。野坐臨黃菊，溪行踏綠錢。", "岩高雲反下，洞黑水潛穿。僻嶺猿偷栗，枯池雁唼蓮。", "身居霞外寺，思發月明田。猶恨縈塵網，昏昏過歲年。"]'),
('yuding-27','贈岐山薑明府','李端','唐','御定全唐诗','yuding','','[]','昨夜聞山雨，歸心便似遲。幾回驚葉落，即到白頭時。',132,'御定全唐詩/json/286.json','["昨夜聞山雨，歸心便似遲。幾回驚葉落，即到白頭時。", "雁影將魂去，蟲聲與淚期。馬卿兼病老，宋玉對秋悲。", "謝客才為別，陶公已見思。非關口腹累，自是雪霜姿。", "釀酒栽黃菊，炊粳折綠葵。山河方入望，風日正宜詩。", "牧豎寒騎馬，邊烽晚立旗。蘭凋猶有氣，柳脆不成絲。", "別後如相問，高僧知所之。"]'),
('yuding-28','下第上薛侍郎','李端','唐','御定全唐诗','yuding','','[]','蓬蓽春風起，開簾卻自悲。如何飄梗處，又到采蘭時。',96,'御定全唐詩/json/286.json','["蓬蓽春風起，開簾卻自悲。如何飄梗處，又到采蘭時。", "明鏡方重照，微誠寄一辭。家貧求祿早，身賤報恩遲。", "幸得皮存矣，須勞翼長之。銘肌非厚答，肉骨是前期。", "縱覺新人好，寧忘舊主疑。終慚太丘道，不為小生私。"]'),
('yuding-29','奉和秘書元丞杪秋憶終南舊居','李端','唐','御定全唐诗','yuding','','[]','高門有才子，能履古人蹤。白社陶元亮，青雲阮仲容。',96,'御定全唐詩/json/286.json','["高門有才子，能履古人蹤。白社陶元亮，青雲阮仲容。", "田園忽歸去，車馬杳難逢。廢巷臨秋水，支頤向暮峰。", "行魚避楊柳，驚鴨觸芙蓉。石竇紅泉細，山橋紫菜重。", "鳳雛終食竹，鶴侶暫巢松。願接煙霞賞，羈離計不從。"]'),
('yuding-30','送歸中丞使新羅','李端','唐','御定全唐诗','yuding','','[]','東望扶桑日，何年是到時。片帆通雨露，積水隔華夷。',72,'御定全唐詩/json/286.json','["東望扶桑日，何年是到時。片帆通雨露，積水隔華夷。", "浩淼風來遠，虛冥鳥去遲。長波靜雲月，孤島宿旌旗。", "別葉傳秋意，回潮動客思。滄溟無舊路，何處問前期。"]'),
('yuding-31','暮春尋終南柳處士','李端','唐','御定全唐诗','yuding','','[]','龐眉一居士，鶉服隱堯時。種豆初成畝，還丹舊日師。',72,'御定全唐詩/json/286.json','["龐眉一居士，鶉服隱堯時。種豆初成畝，還丹舊日師。", "入溪花徑遠，向嶺鳥行遲。紫葛垂苔壁，青菰映柳絲。", "偶來塵外事，暫與素心期。終恨遊春客，同為歲月悲。"]'),
('yuding-32','雪夜尋太白道士','李端','唐','御定全唐诗','yuding','','[]','雪路夜朦朧，尋師杏樹東。石壇連竹靜，醮火照山紅。',96,'御定全唐詩/json/286.json','["雪路夜朦朧，尋師杏樹東。石壇連竹靜，醮火照山紅。", "再拜開金籙，焚香使玉童。蓬瀛三島至，天地一壺通。", "別客曾留藥，逢舟或借風。出遊居鶴上，避禍入羊中。", "過洞偏回首，登門未發蒙。桑田如可見，滄海幾時空。"]'),
('yuding-33','得山中道友書寄苗錢二員外','李端','唐','御定全唐诗','yuding','','[]','有謀皆轗軻，非病亦遲回。壯志年年減，馳暉日日催。',120,'御定全唐詩/json/286.json','["有謀皆轗軻，非病亦遲回。壯志年年減，馳暉日日催。", "還山不及伴，到闕又無媒。高臥成長策，微官稱下才。", "詩人識何謝，居士別宗雷。跡向塵中隱，書從穀口來。", "藥欄遭鹿踐，澗戶被猿開。野鶴巢雲竇，遊龜上水苔。", "新歡追易失，故思渺難裁。自有歸期在，勞君示劫灰。"]'),
('yuding-34','酬前駕部員外郎苗發','李端','唐','御定全唐诗','yuding','','[]','馬融方值校，閱簡複持鉛。素業高風繼，青春壯思全。',120,'御定全唐詩/json/286.json','["馬融方值校，閱簡複持鉛。素業高風繼，青春壯思全。", "論文多在夜，宿寺不虛年。自署區中職，同荒郭外田。", "山鄰三徑絕，野意八行傳。煮玉矜新法，留符識舊仙。", "涵苔溪溜淺，搖浪竹橋懸。複洞潛棲燕，疏楊半翳蟬。", "詠歌雖有和，雲錦獨成妍。應以馮唐老，相譏示此篇。"]'),
('yuding-35','宿薦福寺東池有懷故園因寄元校書','李端','唐','御定全唐诗','yuding','','[]','暮雨風吹盡，東池一夜涼。伏流回弱荇，明月入垂楊。',168,'御定全唐詩/json/286.json','["暮雨風吹盡，東池一夜涼。伏流回弱荇，明月入垂楊。", "石竹閑開碧，薔薇暗吐黃。倚琴看鶴舞，搖扇引桐香。", "舊筍方辭籜，新蓮未滿房。林幽花晚發，地遠草先長。", "撫枕愁華鬢，憑欄想故鄉。露餘清漢直，雲卷白榆行。", "驚鵲仍依樹，游魚不過梁。系舟偏憶戴，炊黍願期張。", "末路還思借，前恩詎敢忘。從來叔夜懶，非是接輿狂。", "眾病嬰公幹，群憂集孝璋。慚將多誤曲，今日獻周郎。"]'),
('yuding-36','送王副使還並州','李端','唐','御定全唐诗','yuding','','[]','並州近胡地，此去事風沙。鐵馬垂金絡，貂裘犯雪花。',72,'御定全唐詩/json/286.json','["並州近胡地，此去事風沙。鐵馬垂金絡，貂裘犯雪花。", "曾持兩郡印，多比五侯家。繼世新恩厚，從軍舊國賒。", "戍煙千里直，邊雁一行斜。想到清油幕，長謀出左車。"]'),
('yuding-37','晚春過夏侯校書值其沉醉戲贈','李端','唐','御定全唐诗','yuding','','[]','欹冠枕如意，獨寢落花前。姚馥清時醉，邊韶白日眠。',168,'御定全唐詩/json/286.json','["欹冠枕如意，獨寢落花前。姚馥清時醉，邊韶白日眠。", "曝褌還當屋，張幕便成天。謁客唯題鳳，偷兒欲覘氈。", "失杯猶離席，墜履反登筵。本是牆東隱，今為甕下仙。", "臥龍髯乍磔，棲蝶腹何便。阮籍供琴韻，陶潛餘秫田。", "人逢轂陽望，春似永和年。顧我非工飲，期君行見憐。", "嘗知渴羌好，亦覺醉胡賢。炙熟樽方竭，車回轄且全。", "噀風仍作雨，灑地即成泉。自鄙新豐過，遲回惜十年。"]'),
('yuding-38','哭張南史因寄南史侄叔宗','李端','唐','御定全唐诗','yuding','','[]','爭路忽摧車，沈鉤未得魚。結交唯我少，喪舊自君初。',96,'御定全唐詩/json/286.json','["爭路忽摧車，沈鉤未得魚。結交唯我少，喪舊自君初。", "諫草文難似，圍棋智不如。仲宣新有賦，叔夜近無書。", "地閉滕公宅，山荒謝客廬。殲良從此恨，福善竟成虛。", "釀酒多同醉，烹雞或取餘。阮咸雖永別，豈共仲容疏。"]'),
('yuding-39','長安感事呈盧綸','李端','唐','御定全唐诗','yuding','','[]','十五事文翰，大兒輕孔融。長裾游邸第，笑傲五侯中。',240,'御定全唐詩/json/286.json','["十五事文翰，大兒輕孔融。長裾游邸第，笑傲五侯中。", "諫獵一朝寢，論邊素未工。蹉跎潘鬢至，蹭蹬阮途窮。", "貸布憐寧與，無金命未通。王陵固似戇，郭最遂非雄。", "斂板辭群彥，回車訪老農。詠詩懷洛下，送客憶山東。", "沈病魂神濁，清齋思慮空。羸將衛玠比，冷共鄴侯同。", "草舍才遮雨，荊窗不礙風。梨教通子守，酒是遠師供。", "捫虱欣時泰，迎貓達歲豐。原門唯有席，井飲但加蔥。", "少壯矜齊德，高年覺宋聾。寓書先論懶，讀易反求蒙。", "昔慕能鳴雁，今憐半死桐。秉心猶似矢，搔首忽如蓬。", "赤葉翻藤架，黃花蓋菊叢。聊將呈匠伯，今已學愚公。"]'),
('yuding-40','遊終南山因寄蘇奉禮士尊師苗員外','李端','唐','御定全唐诗','yuding','','[]','半嶺逢仙駕，清晨獨采芝。壺中開白日，霧裏卷朱旗。',108,'御定全唐詩/json/286.json','["半嶺逢仙駕，清晨獨采芝。壺中開白日，霧裏卷朱旗。", "猿鳥知歸路，松蘿見會時。雞聲傳洞遠，鶴語報家遲。", "童子閑驅石，樵夫樂看棋。依稀醉後拜，恍惚夢中辭。", "海上終難接，人間益自疑。風塵甘獨老，山水但相思。", "願得燒丹訣，流沙永待師。"]'),
('yuding-41','長安書事寄盧綸','李端','唐','御定全唐诗','yuding','','[]','弱冠家廬岳，從師歲月深。翻同老夫見，殊寡少年心。',120,'御定全唐詩/json/286.json','["弱冠家廬岳，從師歲月深。翻同老夫見，殊寡少年心。", "及此時方晏，因之名亦沈。趨途非要路，避事樂空林。", "素業在山下，青泉當樹陰。交遊有凋喪，離別代追尋。", "向秀初聞笛，鐘期久罷琴。殘愁猶滿貌，餘淚可沾襟。", "勿以朱顏好，而忘白髮侵。終期入靈洞，相與煉黃金。"]'),
('yuding-42','送郭良輔下第東歸','李端','唐','御定全唐诗','yuding','','[]','獻策不得意，馳車東出秦。暮年千里客，落日萬家春。',24,'御定全唐詩/json/286.json','["獻策不得意，馳車東出秦。暮年千里客，落日萬家春。"]'),
('yuding-43','妾薄命','李端','唐','御定全唐诗','yuding','','[]','自從君棄妾，憔悴不羞人。唯餘壞粉淚，未免映衫勻。',24,'御定全唐詩/json/286.json','["自從君棄妾，憔悴不羞人。唯餘壞粉淚，未免映衫勻。"]'),
('yuding-44','送暕上人游春','李端','唐','御定全唐诗','yuding','','[]','獨將支遁去，欲往戴顒家。晴野人臨水，春山樹發花。',24,'御定全唐詩/json/286.json','["獨將支遁去，欲往戴顒家。晴野人臨水，春山樹發花。"]'),
('yuding-45','晦日同苗員外游曲江','李端','唐','御定全唐诗','yuding','','[]','晦日同攜手，臨流一望春。可憐楊柳陌，愁殺故鄉人。',24,'御定全唐詩/json/286.json','["晦日同攜手，臨流一望春。可憐楊柳陌，愁殺故鄉人。"]'),
('yuding-46','溪行逢雨與柳中庸','李端','唐','御定全唐诗','yuding','','[]','日落眾山昏，蕭蕭暮雨繁。那堪兩處宿，共聽一聲猿。',24,'御定全唐詩/json/286.json','["日落眾山昏，蕭蕭暮雨繁。那堪兩處宿，共聽一聲猿。"]'),
('yuding-47','和張尹憶東籬菊','李端','唐','御定全唐诗','yuding','','[]','傳書報劉尹，何事憶陶家。若為籬邊菊，山中有此花。',24,'御定全唐詩/json/286.json','["傳書報劉尹，何事憶陶家。若為籬邊菊，山中有此花。"]'),
('yuding-48','幽居作','李端','唐','御定全唐诗','yuding','','[]','山舍千年樹，江亭萬里雲。回潮迎伍相，驟雨送湘君。',24,'御定全唐詩/json/286.json','["山舍千年樹，江亭萬里雲。回潮迎伍相，驟雨送湘君。"]'),
('yuding-49','題雲際寺暕上人故院','李端','唐','御定全唐诗','yuding','','[]','白髮匆匆色，青山草草心。遠公仍下世，從此別東林。',24,'御定全唐詩/json/286.json','["白髮匆匆色，青山草草心。遠公仍下世，從此別東林。"]'),
('yuding-50','觀鄰老栽松','李端','唐','御定全唐诗','yuding','','[]','雖過老人宅，不解老人心。何事殘陽裏，栽松欲待陰。',24,'御定全唐詩/json/286.json','["雖過老人宅，不解老人心。何事殘陽裏，栽松欲待陰。"]'),
('yuding-51','贈胡居士','李端','唐','御定全唐诗','yuding','','[]','孔融過五十，海內故人稀。相府恩猶在，知君未拂衣。',24,'御定全唐詩/json/286.json','["孔融過五十，海內故人稀。相府恩猶在，知君未拂衣。"]'),
('yuding-52','薦福寺送元偉','李端','唐','御定全唐诗','yuding','','[]','送客攀花後，尋僧坐竹時。明朝莫回望，青草馬行遲。',24,'御定全唐詩/json/286.json','["送客攀花後，尋僧坐竹時。明朝莫回望，青草馬行遲。"]'),
('yuding-53','哭苗垂','李端','唐','御定全唐诗','yuding','','[]','舊友無由見，孤墳草欲長。月斜鄰笛盡，車馬出山陽。',24,'御定全唐詩/json/286.json','["舊友無由見，孤墳草欲長。月斜鄰笛盡，車馬出山陽。"]'),
('yuding-54','客行贈馮著','李端','唐','御定全唐诗','yuding','','[]','旅行雖別路，日暮各思歸。欲下今朝淚，知君亦濕衣。',24,'御定全唐詩/json/286.json','["旅行雖別路，日暮各思歸。欲下今朝淚，知君亦濕衣。"]'),
('yuding-55','蕪城','李端','唐','御定全唐诗','yuding','','[]','風吹城上樹，草沒城邊路。城裏月明時，精靈自來去。',24,'御定全唐詩/json/286.json','["風吹城上樹，草沒城邊路。城裏月明時，精靈自來去。"]'),
('yuding-56','贈山中老人','李端','唐','御定全唐诗','yuding','','[]','白首獨一身，青山為四鄰。雖行故鄉陌，不見故鄉人。',24,'御定全唐詩/json/286.json','["白首獨一身，青山為四鄰。雖行故鄉陌，不見故鄉人。"]'),
('yuding-57','拜新月','李端','唐','御定全唐诗','yuding','','[]','開簾見新月，便即下階拜。細語人不聞，北風吹裙帶。',24,'御定全唐詩/json/286.json','["開簾見新月，便即下階拜。細語人不聞，北風吹裙帶。"]'),
('yuding-58','聽箏','李端','唐','御定全唐诗','yuding','','[]','鳴箏金粟柱，素手玉房前。欲得周郎顧，時時誤拂弦。',24,'御定全唐詩/json/286.json','["鳴箏金粟柱，素手玉房前。欲得周郎顧，時時誤拂弦。"]'),
('yuding-59','贈何兆','李端','唐','御定全唐诗','yuding','','[]','文章似揚馬，風骨又清羸。江漢君猶在，英靈信未衰。',24,'御定全唐詩/json/286.json','["文章似揚馬，風骨又清羸。江漢君猶在，英靈信未衰。"]'),
('yuding-60','同司空文明過堅上人故院','李端','唐','御定全唐诗','yuding','','[]','我與雷居士，平生事遠公。無人知是舊，共到影堂中。',24,'御定全唐詩/json/286.json','["我與雷居士，平生事遠公。無人知是舊，共到影堂中。"]'),
('yuding-61','雜詩','李端','唐','御定全唐诗','yuding','','[]','主第辭高飲，石家赴宵會。金谷走車來，玉人騎馬待。',24,'御定全唐詩/json/286.json','["主第辭高飲，石家赴宵會。金谷走車來，玉人騎馬待。"]'),
('yuding-62','感興','李端','唐','御定全唐诗','yuding','','[]','香爐最高頂，中有高人住。日暮下山來，月明上山去。',24,'御定全唐詩/json/286.json','["香爐最高頂，中有高人住。日暮下山來，月明上山去。"]'),
('yuding-63','問張山人疾','李端','唐','御定全唐诗','yuding','','[]','先生沈病意何如，蓬艾門前客轉疏。',32,'御定全唐詩/json/286.json','["先生沈病意何如，蓬艾門前客轉疏。", "不見領徒過絳帳，唯聞與婢削丹書。"]'),
('yuding-64','江上送客','李端','唐','御定全唐诗','yuding','','[]','故人南去漢江陰，秋雨蕭蕭雲夢深。',32,'御定全唐詩/json/286.json','["故人南去漢江陰，秋雨蕭蕭雲夢深。", "江上見人應下淚，由來遠客易傷心。"]'),
('yuding-65','閨情','李端','唐','御定全唐诗','yuding','','[]','月落星稀天欲明，孤燈未滅夢難成。',32,'御定全唐詩/json/286.json','["月落星稀天欲明，孤燈未滅夢難成。", "披衣更向門前望，不忿朝來鵲喜聲。"]'),
('yuding-66','送劉侍郎','李端','唐','御定全唐诗','yuding','','[]','幾人同去謝宣城，未及酬恩隔死生。',32,'御定全唐詩/json/286.json','["幾人同去謝宣城，未及酬恩隔死生。", "唯有夜猿知客恨，嶧陽溪路第三聲。"]'),
('yuding-67','重送鄭宥歸蜀因寄何兆','李端','唐','御定全唐诗','yuding','','[]','黃花西上路何如，青壁連天雁亦疏。',32,'御定全唐詩/json/286.json','["黃花西上路何如，青壁連天雁亦疏。", "為報長卿休滌器，漢家思見茂陵書。"]'),
('yuding-68','宿石澗店聞婦人哭','李端','唐','御定全唐诗','yuding','','[]','山店門前一婦人，哀哀夜哭向秋雲。',32,'御定全唐詩/json/286.json','["山店門前一婦人，哀哀夜哭向秋雲。", "自說夫因征戰死，朝來逢著舊將軍。"]'),
('yuding-69','與道者別','李端','唐','御定全唐诗','yuding','','[]','聞說滄溟今已淺，何當白鶴更歸來。',32,'御定全唐詩/json/286.json','["聞說滄溟今已淺，何當白鶴更歸來。", "舊師唯有先生在，忍見門人掩淚回。"]'),
('yuding-70','長門怨','李端','唐','御定全唐诗','yuding','','[]','金壺漏盡禁門開，飛燕昭陽侍寢回。',32,'御定全唐詩/json/286.json','["金壺漏盡禁門開，飛燕昭陽侍寢回。", "隨分獨眠秋殿裏，遙聞語笑自天來。"]'),
('yuding-71','憶友懷野寺舊居','李端','唐','御定全唐诗','yuding','','[]','自嫌野性共人疏，憶向西林更結廬。',32,'御定全唐詩/json/286.json','["自嫌野性共人疏，憶向西林更結廬。", "寄謝山陰許都講，昨來頻得遠公書。"]'),
('yuding-72','聽夜雨寄盧綸','李端','唐','御定全唐诗','yuding','','[]','暮雨蕭條過鳳城，霏霏颯颯重還輕。',32,'御定全唐詩/json/286.json','["暮雨蕭條過鳳城，霏霏颯颯重還輕。", "聞君此夜東林宿，聽得荷池幾番聲。"]'),
('yuding-73','昭君詞','李端','唐','御定全唐诗','yuding','','[]','李陵初送子卿回，漢月明時惆悵來。',32,'御定全唐詩/json/286.json','["李陵初送子卿回，漢月明時惆悵來。", "憶著長安舊遊處，千門萬戶玉樓臺。"]'),
('yuding-74','春晚游鶴林寺寄使府諸公','李端','唐','御定全唐诗','yuding','','[]','野寺尋春花已遲，背岩惟有兩三枝。',32,'御定全唐詩/json/286.json','["野寺尋春花已遲，背岩惟有兩三枝。", "明朝攜酒猶堪醉，為報春風且莫吹。"]'),
('yuding-0','南充謝郡客遊澧州留贈宇文中丞','暢當','唐','御定全唐诗','yuding','','[]','僕本濩落人，辱當州郡使。量力頗及早，謝歸今即己。',96,'御定全唐詩/json/287.json','["僕本濩落人，辱當州郡使。量力頗及早，謝歸今即己。", "蕭蕭若淩虛，襟帶頓銷靡。車服率然來，涔陽作遊子。", "鬱鬱寡開顏，默默獨行李。忽逢平生友，一笑方在此。", "秋情寧風日，楚思浩雲水。為語弋林者，冥冥鴻遠矣。"]'),
('yuding-1','宿報恩寺精舍','暢當','唐','御定全唐诗','yuding','','[]','鐘梵送沈景，星多露漸光。風中蘭靡靡，月下樹蒼蒼。',72,'御定全唐詩/json/287.json','["鐘梵送沈景，星多露漸光。風中蘭靡靡，月下樹蒼蒼。", "夜殿若山橫，深松如澗涼。羸然虎溪子，遲我一虛床。", "杳杳空寂舍，濛濛蓮桂香。擁褐依西壁，紗燈靄中央。"]'),
('yuding-2','自平陽館赴郡','暢當','唐','御定全唐诗','yuding','','[]','晨興平陽館，見月沈江水。溶溶山霧披，肅肅沙鷺起。',96,'御定全唐詩/json/287.json','["晨興平陽館，見月沈江水。溶溶山霧披，肅肅沙鷺起。", "奉恩謬符竹，伏軾省頑鄙。何當施教化，愧迎小郡吏。", "寥落火耕俗，征途青冥裏。德綏及吾民，不德將鹿矣。", "擒奸非性能，多湣會衰齒。恭承共理詔，恒懼墜諸地。"]'),
('yuding-3','天柱隱所重答江州應物','暢當','唐','御定全唐诗','yuding','','[]','寂寞一悵望，秋風山景清。此中惟草色，翻意見人行。',72,'御定全唐詩/json/287.json','["寂寞一悵望，秋風山景清。此中惟草色，翻意見人行。", "荒徑饒松子，深蘿絕鳥聲。陽崖全帶日，寬嶂偶通耕。", "拙昧難容世，貧寒別有情。煩君瓊玖贈，幽懶百無成。"]'),
('yuding-4','山居酬韋蘇州見寄','暢當','唐','御定全唐诗','yuding','','[]','孤柴泄煙處，此中山叟居。觀雲寧有事，耽酒詎知餘。',48,'御定全唐詩/json/287.json','["孤柴泄煙處，此中山叟居。觀雲寧有事，耽酒詎知餘。", "水定鶴翻去，松歌峰儼如。猶煩使君問，更欲結深廬。"]'),
('yuding-5','春日過奉誠園','暢當','唐','御定全唐诗','yuding','','[]','帝裏陽和日，遊人到禦園。暖催新景氣，春認舊蘭蓀。',72,'御定全唐詩/json/287.json','["帝裏陽和日，遊人到禦園。暖催新景氣，春認舊蘭蓀。", "詠德先臣沒，成蹊大樹存。見桐猶近井，看柳尚依門。", "獻地非更宅，遺忠永奉恩。又期攀桂後，來賞百花繁。"]'),
('yuding-6','軍中醉飲寄沈八劉叟','暢當','唐','御定全唐诗','yuding','','[]','酒渴愛江清，餘酣漱晚汀。軟莎欹坐穩，冷石醉眠醒。',48,'御定全唐詩/json/287.json','["酒渴愛江清，餘酣漱晚汀。軟莎欹坐穩，冷石醉眠醒。", "野膳隨行帳，華音發從伶。數杯君不見，都已遣沈冥。"]'),
('yuding-7','偶宴西蜀摩訶池','暢當','唐','御定全唐诗','yuding','','[]','珍木郁清池，風荷左右披。淺觴寧及醉，慢舸不知移。',48,'御定全唐詩/json/287.json','["珍木郁清池，風荷左右披。淺觴寧及醉，慢舸不知移。", "蔭簟流光冷，凝簪照影欹。胡為獨羈者，雪涕向漣漪。"]'),
('yuding-8','奉送杜中丞赴洪州','暢當','唐','御定全唐诗','yuding','','[]','詔出鳳凰宮，新恩連帥雄。江湖經戰陣，草木待仁風。',48,'御定全唐詩/json/287.json','["詔出鳳凰宮，新恩連帥雄。江湖經戰陣，草木待仁風。", "豪右貪威愛，紆繁德簡通。多慚君子顧，攀餞路塵中。"]'),
('yuding-9','九日陪皇甫使君泛江宴赤岸亭','暢當','唐','御定全唐诗','yuding','','[]','羈旅逢佳節，逍遙忽見招。同傾菊花酒，緩棹木蘭橈。',72,'御定全唐詩/json/287.json','["羈旅逢佳節，逍遙忽見招。同傾菊花酒，緩棹木蘭橈。", "平楚堪愁思，長江去寂寥。猿啼不離峽，灘沸鎮如潮。", "舉目關山異，傷心鄉國遙。徒言歡滿座，誰覺客魂消。"]'),
('yuding-10','蒲中道中二首','暢當','唐','御定全唐诗','yuding','','[]','蒼蒼中條山，厥形極奇磈。我欲涉其崖，濯足黃河水。',48,'御定全唐詩/json/287.json','["蒼蒼中條山，厥形極奇磈。我欲涉其崖，濯足黃河水。", "古刹棲柿林，綠陰覆蒼瓦。歲晏來品題，拾葉總堪寫。"]'),
('yuding-11','登鸛雀樓','暢當','唐','御定全唐诗','yuding','','[]','迥臨飛鳥上，高出世塵間。天勢圍平野，河流入斷山。',24,'御定全唐詩/json/287.json','["迥臨飛鳥上，高出世塵間。天勢圍平野，河流入斷山。"]'),
('yuding-12','宿潭上二首','暢當','唐','御定全唐诗','yuding','','[]','夜潭有仙舸，與月當水中。嘉賓愛明月，遊子驚秋風。',48,'御定全唐詩/json/287.json','["夜潭有仙舸，與月當水中。嘉賓愛明月，遊子驚秋風。", "青蒲野陂水，白露明月天。中夜秋風起，心事坐潸然。"]'),
('yuding-13','別盧綸','暢當','唐','御定全唐诗','yuding','','[]','故交君獨在，又欲與君離。我有新秋淚，非關宋玉悲。',24,'御定全唐詩/json/287.json','["故交君獨在，又欲與君離。我有新秋淚，非關宋玉悲。"]'),
('yuding-14','題沈八齋','暢當','唐','御定全唐诗','yuding','','[]','江齋一入何亭亭，因寄淪漣心杳冥。',32,'御定全唐詩/json/287.json','["江齋一入何亭亭，因寄淪漣心杳冥。", "綠綺琴彈白雪引，烏絲絹勒黃庭經。"]'),
('yuding-15','早春','暢諸','唐','御定全唐诗','yuding','','[]','獻歲春猶淺，園林未盡開。雪和新雨落，風帶舊寒來。',48,'御定全唐詩/json/287.json','["獻歲春猶淺，園林未盡開。雪和新雨落，風帶舊寒來。", "聽鳥聞歸雁，看花識早梅。生涯知幾日，更被一年催。"]'),
('yuding-0','曉過南宮聞太常清樂','陸贄','唐','御定全唐诗','yuding','','[]','南宮聞古樂，拂曙聽初驚。煙靄遙迷處，絲桐暗辨名。',72,'御定全唐詩/json/288.json','["南宮聞古樂，拂曙聽初驚。煙靄遙迷處，絲桐暗辨名。", "節隨新律改，聲帶緒風輕。合雅將移俗，同和自感情。", "遠音兼曉漏，餘響過春城。九奏明初日，寥寥天地清。"]'),
('yuding-1','禁中春松','陸贄','唐','御定全唐诗','yuding','','[]','陰陰清禁裏，蒼翠滿春松。雨露恩偏近，陽和色更濃。',72,'御定全唐詩/json/288.json','["陰陰清禁裏，蒼翠滿春松。雨露恩偏近，陽和色更濃。", "高枝分曉日，虛吹雜宵鐘。香助爐煙遠，形疑蓋影重。", "願符千載壽，不羨五株封。倘得回天眷，全勝老碧峰。"]'),
('yuding-2','賦得禦園芳草','陸贄','唐','御定全唐诗','yuding','','[]','陰陰禦園裏，瑤草日光長。靃靡含煙霧，依稀帶夕陽。',72,'御定全唐詩/json/288.json','["陰陰禦園裏，瑤草日光長。靃靡含煙霧，依稀帶夕陽。", "雨餘荑更密，風暖蕙初香。擁杖緣馳道，乘輿入建章。", "濕煙搖不散，細影亂無行。恒恐韶光晚，何人辨早芳。"]'),
('yuding-3','句','陸贄','唐','御定全唐诗','yuding','','[]','繞階流dA々，來砌樹陰陰。',13,'御定全唐詩/json/288.json','["繞階流dA々，來砌樹陰陰。"]'),
('yuding-4','曉過南宮聞太常清樂','張蒙','唐','御定全唐诗','yuding','','[]','玉珂經禮寺，金奏過南宮。雅調乘清曉，飛聲向遠空。',72,'御定全唐詩/json/288.json','["玉珂經禮寺，金奏過南宮。雅調乘清曉，飛聲向遠空。", "慢隨飄去雪，輕逐度來風。迥出重城裏，傍聞九陌中。", "應將肆夏比，更與五英同。一聽南熏曲，因知大舜功。"]'),
('yuding-5','禁中春松','常沂','唐','御定全唐诗','yuding','','[]','映殿松偏好，森森列禁中。攢柯沾聖澤，疏蓋引皇風。',72,'御定全唐詩/json/288.json','["映殿松偏好，森森列禁中。攢柯沾聖澤，疏蓋引皇風。", "晚色連秦苑，春香滿漢宮。操將金石固，材與直臣同。", "翠影宜青瑣，蒼枝秀碧空。還知沐天眷，千載更蔥蘢。"]'),
('yuding-6','禁中春松','周存','唐','御定全唐诗','yuding','','[]','幾歲含貞節，青青紫禁中。日華留偃蓋，雉尾轉春風。',72,'御定全唐詩/json/288.json','["幾歲含貞節，青青紫禁中。日華留偃蓋，雉尾轉春風。", "不為繁霜改，那將眾木同。千條攢翠色，百尺澹晴空。", "影密金莖近，花明鳳沼通。安知幽澗側，獨與散樗叢。"]'),
('yuding-7','西戎獻馬','周存','唐','御定全唐诗','yuding','','[]','天馬從東道，皇威被遠戎。來參八駿列，不假貳師功。',72,'御定全唐詩/json/288.json','["天馬從東道，皇威被遠戎。來參八駿列，不假貳師功。", "影別流沙路，嘶流上苑風。望雲時蹀足，向月每爭雄。", "稟異才難狀，標奇志豈同。驅馳如見許，千里一朝通。"]'),
('yuding-8','小苑春望宮池柳色','黎逢','唐','御定全唐诗','yuding','','[]','上林新柳變，小苑暮天晴。始望和煙密，遙憐拂水輕。',72,'御定全唐詩/json/288.json','["上林新柳變，小苑暮天晴。始望和煙密，遙憐拂水輕。", "色承陽氣暖，陰帶禦溝清。不厭隨風弱，仍宜向日明。", "垂絲遍閣榭，飛絮觸簾旌。漸到依依處，思聞出穀鶯。"]'),
('yuding-9','夏首猶清和','黎逢','唐','御定全唐诗','yuding','','[]','早夏宜初景，和光起禁城。祝融將禦節，炎帝啟朱明。',72,'御定全唐詩/json/288.json','["早夏宜初景，和光起禁城。祝融將禦節，炎帝啟朱明。", "日送殘花晚，風過御苑清。郊原浮麥氣，池沼發荷英。", "樹影臨山動，禽飛入漢輕。幸逢堯禹化，全勝穀中情。"]'),
('yuding-10','小苑春望宮池柳色','張昔','唐','御定全唐诗','yuding','','[]','小苑春初至，皇衢日更清。遙分萬條柳，回出九重城。',72,'御定全唐詩/json/288.json','["小苑春初至，皇衢日更清。遙分萬條柳，回出九重城。", "隱映龍池潤，參差鳳闕明。影宜宮雪曙，色帶禁煙晴。", "深淺殘陽變，高低曉吹輕。年光正堪折，欲寄一枝榮。"]'),
('yuding-11','小苑春望宮池柳色','丁位','唐','御定全唐诗','yuding','','[]','小苑宜春望，宮池柳色輕。低昂含曉景，縈轉帶新晴。',72,'御定全唐詩/json/288.json','["小苑宜春望，宮池柳色輕。低昂含曉景，縈轉帶新晴。", "似蓋芳初合，如絲蔭漸成。依依連水暗，嫋嫋出牆明。", "雖以陽和發，能令旅思生。他時花滿路，從此接遷鶯。"]'),
('yuding-12','小苑春望宮池柳色','元友直','唐','御定全唐诗','yuding','','[]','柳色新池遍，春光御苑晴。葉依青閣密，條向碧流傾。',72,'御定全唐詩/json/288.json','["柳色新池遍，春光御苑晴。葉依青閣密，條向碧流傾。", "路暗陰初重，波搖影轉清。風從垂處度，煙就望中生。", "斷續遊蜂聚，飄颻戲蝶輕。怡然變芳節，願及一枝榮。"]'),
('yuding-13','小苑春望宮池柳色','楊系','唐','御定全唐诗','yuding','','[]','勝游從小苑，宮柳望春晴。拂地青絲嫩，縈風綠帶輕。',72,'御定全唐詩/json/288.json','["勝游從小苑，宮柳望春晴。拂地青絲嫩，縈風綠帶輕。", "光含煙色遠，影透水文清。玉笛吟何得，金閨畫豈成。", "皇風吹欲斷，聖日映逾明。願駐高枝上，還同出穀鶯。"]'),
('yuding-14','小苑春望宮池柳色','崔績','唐','御定全唐诗','yuding','','[]','帝京春氣早，禦柳已先榮。嫩葉隨風散，浮光向日明。',72,'御定全唐詩/json/288.json','["帝京春氣早，禦柳已先榮。嫩葉隨風散，浮光向日明。", "悠揚生別意，斷續引芳聲。積翠連馳道，飄花出禁城。", "柔條依水弱，遠色帶煙輕。南望龍池畔，斜光照晚晴。"]'),
('yuding-15','小苑春望宮池柳色','張季略','唐','御定全唐诗','yuding','','[]','韶光歸漢苑，柳色發春城。半見離宮出，才分遠水明。',72,'御定全唐詩/json/288.json','["韶光歸漢苑，柳色發春城。半見離宮出，才分遠水明。", "青蔥當淑景，隱映媚新晴。積翠煙初合，微黃葉未生。", "迎春看尚嫩，照日見先榮。倘得辭幽谷，高枝寄一名。"]'),
('yuding-16','小苑春望宮池柳色','裴達','唐','御定全唐诗','yuding','','[]','勝游經小苑，閑望上春城。禦路韶光發，宮池柳色輕。',72,'御定全唐詩/json/288.json','["勝游經小苑，閑望上春城。禦路韶光發，宮池柳色輕。", "乍濃含雨潤，微澹帶雲晴。冪曆殘煙斂，搖揚落照明。", "幾條垂廣殿，數樹影高旌。獨有風塵客，思同雨露榮。"]'),
('yuding-17','南至日太史登臺書雲物','裴逵','唐','御定全唐诗','yuding','','[]','圓丘才展禮，佳氣近初分。太史新簪筆，高臺紀彩雲。',72,'御定全唐詩/json/288.json','["圓丘才展禮，佳氣近初分。太史新簪筆，高臺紀彩雲。", "煙空和縹緲，曉色共氛氳。道泰資賢輔，年豐荷聖君。", "恭惟司國瑞，兼用察人文。應念懷鉛客，終朝望碧雰。"]'),
('yuding-18','小苑春望宮池柳色','沈回','唐','御定全唐诗','yuding','','[]','今來游上苑，春染柳條輕。濯濯方含色，依依若有情。',72,'御定全唐詩/json/288.json','["今來游上苑，春染柳條輕。濯濯方含色，依依若有情。", "分行臨曲沼，先發媚重城。拂水枝偏弱，搖風絲已生。", "變黃隨淑景，吐翠逐新晴。佇立徒延首，裴回欲寄誠。"]'),
('yuding-0','長安春夜宿開元觀','楊憑','唐','御定全唐诗','yuding','','[]','霓裳下晚煙，留客杏花前。遍問人寰事，新從洞府天。',48,'御定全唐詩/json/289.json','["霓裳下晚煙，留客杏花前。遍問人寰事，新從洞府天。", "長松皆掃月，老鶴不知年。為說蓬瀛路，雲濤幾處連。"]'),
('yuding-1','晚泊江戍','楊憑','唐','御定全唐诗','yuding','','[]','旅棹依遙戍，清湘急晚流。若為南浦宿，逢此北風秋。',48,'御定全唐詩/json/289.json','["旅棹依遙戍，清湘急晚流。若為南浦宿，逢此北風秋。", "雲月孤鴻晚，關山幾路愁。年年不得意，零落對滄洲。"]'),
('yuding-2','巴江雨夜','楊憑','唐','御定全唐诗','yuding','','[]','五嶺天無雁，三巴客問津。紛紛輕漢暮，漠漠暗江春。',48,'御定全唐詩/json/289.json','["五嶺天無雁，三巴客問津。紛紛輕漢暮，漠漠暗江春。", "青草連湖岸，繁花憶楚人。芳菲無限路，幾夜月明新。"]'),
('yuding-3','邊塞行','楊憑','唐','御定全唐诗','yuding','','[]','九原臨得水，雙足是重城。獨許為儒老，相憐從騎行。',48,'御定全唐詩/json/289.json','["九原臨得水，雙足是重城。獨許為儒老，相憐從騎行。", "細叢榆塞迥，高點雁山晴。聖主嗤炎漢，無心自勒兵。"]'),
('yuding-4','樂遊園望月','楊憑','唐','御定全唐诗','yuding','','[]','炎靈全盛地，明月半秋時。今古人同望，盈虧節暗移。',48,'御定全唐詩/json/289.json','["炎靈全盛地，明月半秋時。今古人同望，盈虧節暗移。", "彩凝雙月迥，輪度八川遲。共惜鳴珂去，金波送酒卮。"]'),
('yuding-5','千葉桃花','楊憑','唐','御定全唐诗','yuding','','[]','千葉桃花勝百花，孤榮春晚駐年華。',32,'御定全唐詩/json/289.json','["千葉桃花勝百花，孤榮春晚駐年華。", "若教避俗秦人見，知向河源舊侶誇。"]'),
('yuding-6','春中泛舟','楊憑','唐','御定全唐诗','yuding','','[]','仙郎歸奏過湘東，正值三湘二月中。',32,'御定全唐詩/json/289.json','["仙郎歸奏過湘東，正值三湘二月中。", "惆悵滿川桃杏醉，醉看還與曲江同。"]'),
('yuding-7','雨中怨秋','楊憑','唐','御定全唐诗','yuding','','[]','辭家遠客愴秋風，千里寒雲與斷蓬。',32,'御定全唐詩/json/289.json','["辭家遠客愴秋風，千里寒雲與斷蓬。", "日暮隔山投古寺，鐘聲何處雨濛濛。"]'),
('yuding-8','秋日獨游曲江','楊憑','唐','御定全唐诗','yuding','','[]','信馬閑過憶所親，秋山行盡路無塵。',32,'御定全唐詩/json/289.json','["信馬閑過憶所親，秋山行盡路無塵。", "主人莫惜松陰醉，還有千錢沽酒人。"]'),
('yuding-9','寄別','楊憑','唐','御定全唐诗','yuding','','[]','晚煙洲霧並蒼蒼，河雁驚飛不作行。',32,'御定全唐詩/json/289.json','["晚煙洲霧並蒼蒼，河雁驚飛不作行。", "回旆轉舟行數裏，歌聲猶自逐清湘。"]'),
('yuding-10','邊情','楊憑','唐','御定全唐诗','yuding','','[]','新種如今屢請和，玉關邊上幸無他。',32,'御定全唐詩/json/289.json','["新種如今屢請和，玉關邊上幸無他。", "欲知北海苦辛處，看取節毛餘幾多。"]'),
('yuding-11','早發湘中','楊憑','唐','御定全唐诗','yuding','','[]','按節鳴笳中貴催，紅旌白旆滿船開。',32,'御定全唐詩/json/289.json','["按節鳴笳中貴催，紅旌白旆滿船開。", "迎愁湓浦登城望，西見荊門積水來。"]'),
('yuding-12','海榴','楊憑','唐','御定全唐诗','yuding','','[]','海榴殷色透簾櫳，看盛看衰意欲同。',32,'御定全唐詩/json/289.json','["海榴殷色透簾櫳，看盛看衰意欲同。", "若許三英隨五馬，便將濃豔鬥繁紅。"]'),
('yuding-13','春情','楊憑','唐','御定全唐诗','yuding','','[]','暮雨朝雲幾日歸，如絲如霧濕人衣。',32,'御定全唐詩/json/289.json','["暮雨朝雲幾日歸，如絲如霧濕人衣。", "三湘二月春光早，莫逐狂風繚亂飛。"]'),
('yuding-14','送客往荊州','楊憑','唐','御定全唐诗','yuding','','[]','巴丘過日又登城，雲水湘東一日平。',32,'御定全唐詩/json/289.json','["巴丘過日又登城，雲水湘東一日平。", "若愛春秋繁露學，正逢元凱鎮南荊。"]'),
('yuding-15','贈馬煉師','楊憑','唐','御定全唐诗','yuding','','[]','心嫌碧落更何從，月帔花冠冰雪容。',32,'御定全唐詩/json/289.json','["心嫌碧落更何從，月帔花冠冰雪容。", "行雨若迷歸處路，近南惟見祝融峰。"]'),
('yuding-16','湘江泛舟','楊憑','唐','御定全唐诗','yuding','','[]','湘川洛浦三千里，地角天涯南北遙。',32,'御定全唐詩/json/289.json','["湘川洛浦三千里，地角天涯南北遙。", "除卻同傾百壺外，不愁誰奈兩魂銷。"]'),
('yuding-17','送別','楊憑','唐','御定全唐诗','yuding','','[]','江岸梅花雪不如，看君驛馭向南徐。',32,'御定全唐詩/json/289.json','["江岸梅花雪不如，看君驛馭向南徐。", "相聞不必因來雁，雲裏飛輧落素書。"]'),
('yuding-18','贈竇牟','楊憑','唐','御定全唐诗','yuding','','[]','直用天才眾卻瞋，應欺李杜久為塵。',32,'御定全唐詩/json/289.json','["直用天才眾卻瞋，應欺李杜久為塵。", "南荒不死中華老，別玉翻同西國人。"]'),
('yuding-0','送別','楊凝','唐','御定全唐诗','yuding','','[]','樽酒郵亭暮，雲帆驛使歸。野鷗寒不起，川雨凍難飛。',48,'御定全唐詩/json/290.json','["樽酒郵亭暮，雲帆驛使歸。野鷗寒不起，川雨凍難飛。", "吳會家移遍，軒轅夢去稀。姓楊皆足淚，非是強沾衣。"]'),
('yuding-1','送客東歸','楊凝','唐','御定全唐诗','yuding','','[]','君向古營州，邊風戰地愁。草青縵別路，柳亞拂孤樓。',48,'御定全唐詩/json/290.json','["君向古營州，邊風戰地愁。草青縵別路，柳亞拂孤樓。", "人意傷難醉，鶯啼咽不流。芳菲只合樂，離思返如秋。"]'),
('yuding-2','送客歸湖南','楊凝','唐','御定全唐诗','yuding','','[]','湖南樹色盡，了了辨潭州。雨散今為別，雲飛何處遊。',48,'御定全唐詩/json/290.json','["湖南樹色盡，了了辨潭州。雨散今為別，雲飛何處遊。", "情來偏似醉，淚迸不成流。那向蕭條路，緣湘篁竹愁。"]'),
('yuding-3','送客歸淮南','楊凝','唐','御定全唐诗','yuding','','[]','畫舫照河堤，暄風百草齊。行絲直網蝶，去燕旋遺泥。',48,'御定全唐詩/json/290.json','["畫舫照河堤，暄風百草齊。行絲直網蝶，去燕旋遺泥。", "郡向高天近，人從別路迷。非關禦溝上，今日各東西。"]'),
('yuding-4','春情','楊凝','唐','御定全唐诗','yuding','','[]','舊宅洛川陽，曾游遊俠場。水添楊柳色，花絆綺羅香。',48,'御定全唐詩/json/290.json','["舊宅洛川陽，曾游遊俠場。水添楊柳色，花絆綺羅香。", "趙瑟多愁曲，秦家足豔妝。江潭遠相憶，春夢不勝長。"]'),
('yuding-5','秋夜聽擣衣','楊凝','唐','御定全唐诗','yuding','','[]','砧杵聞秋夜，裁縫寄遠方。聲微漸濕露，響細未經霜。',48,'御定全唐詩/json/290.json','["砧杵聞秋夜，裁縫寄遠方。聲微漸濕露，響細未經霜。", "蘭牖唯遮樹，風簾不礙涼。雲中望何處，聽此斷人腸。"]'),
('yuding-6','從軍行','楊凝','唐','御定全唐诗','yuding','','[]','都尉出居延，強兵集五千。還將張博望，直救范祁連。',48,'御定全唐詩/json/290.json','["都尉出居延，強兵集五千。還將張博望，直救范祁連。", "漢卒悲簫鼓，胡姬濕采旃。如今意氣盡，流淚挹流泉。"]'),
('yuding-7','和直禁省','楊凝','唐','御定全唐诗','yuding','','[]','宵直丹宮近，風傳碧樹涼。漏稀銀箭滴，月度網軒光。',48,'御定全唐詩/json/290.json','["宵直丹宮近，風傳碧樹涼。漏稀銀箭滴，月度網軒光。", "鳳詔裁多暇，蘭燈夢更長。此時顏范貴，十步舊連行。"]'),
('yuding-8','留別','楊凝','唐','御定全唐诗','yuding','','[]','玉節隨東閣，金閨別舊僚。若為花滿寺，躍馬上河橋。',24,'御定全唐詩/json/290.json','["玉節隨東閣，金閨別舊僚。若為花滿寺，躍馬上河橋。"]'),
('yuding-9','送客往洞庭','楊凝','唐','御定全唐诗','yuding','','[]','九江歸路遠，萬里客舟還。若過巴江水，湘東滿碧煙。',24,'御定全唐詩/json/290.json','["九江歸路遠，萬里客舟還。若過巴江水，湘東滿碧煙。"]'),
('yuding-10','別友人','楊凝','唐','御定全唐诗','yuding','','[]','倦客驚危路，傷禽繞樹枝。非逢暴公子，不敢涕流離。',24,'御定全唐詩/json/290.json','["倦客驚危路，傷禽繞樹枝。非逢暴公子，不敢涕流離。"]'),
('yuding-11','初渡淮北岸','楊凝','唐','御定全唐诗','yuding','','[]','別夢雖難覺，悲魂最易銷。殷勤淮北岸，鄉近去家遙。',24,'御定全唐詩/json/290.json','["別夢雖難覺，悲魂最易銷。殷勤淮北岸，鄉近去家遙。"]'),
('yuding-12','詠雨','楊凝','唐','御定全唐诗','yuding','','[]','塵浥多人路，泥歸足燕家。可憐繚亂點，濕盡滿宮花。',24,'御定全唐詩/json/290.json','["塵浥多人路，泥歸足燕家。可憐繚亂點，濕盡滿宮花。"]'),
('yuding-13','柳絮','楊凝','唐','御定全唐诗','yuding','','[]','河畔多楊柳，追遊盡狹斜。春風一回送，亂入莫愁家。',24,'御定全唐詩/json/290.json','["河畔多楊柳，追遊盡狹斜。春風一回送，亂入莫愁家。"]'),
('yuding-14','花枕','楊凝','唐','御定全唐诗','yuding','','[]','席上沈香枕，樓中蕩子妻。那堪一夜裏，長濕兩行啼。',24,'御定全唐詩/json/290.json','["席上沈香枕，樓中蕩子妻。那堪一夜裏，長濕兩行啼。"]'),
('yuding-15','送客往鄜州','楊凝','唐','御定全唐诗','yuding','','[]','新參將相事營平，錦帶騂弓結束輕。曉上關城吟畫角，',40,'御定全唐詩/json/290.json','["新參將相事營平，錦帶騂弓結束輕。曉上關城吟畫角，", "近喜扶陽系戎相，從來衛霍笑長纓。"]'),
('yuding-16','送客往夏州','楊凝','唐','御定全唐诗','yuding','','[]','憐君此去過居延，古塞黃雲共渺然。沙闊獨行尋馬跡，',40,'御定全唐詩/json/290.json','["憐君此去過居延，古塞黃雲共渺然。沙闊獨行尋馬跡，", "聞有故交今從騎，何須著論更言錢。"]'),
('yuding-17','春霽晚望','楊凝','唐','御定全唐诗','yuding','','[]','細雨晴深小苑東，春雲開氣逐光風。雄兒走馬神光上，',40,'御定全唐詩/json/290.json','["細雨晴深小苑東，春雲開氣逐光風。雄兒走馬神光上，", "南歸路極天連海，惟有相思明月同。"]'),
('yuding-18','唐昌觀玉蕊花','楊凝','唐','御定全唐诗','yuding','','[]','瑤華瓊蕊種何年，蕭史秦嬴向紫煙。',32,'御定全唐詩/json/290.json','["瑤華瓊蕊種何年，蕭史秦嬴向紫煙。", "時控彩鸞過舊邸，摘花持獻玉皇前。"]'),
('yuding-19','別李協','楊凝','唐','御定全唐诗','yuding','','[]','江邊日暮不勝愁，送客沾衣江上樓。',32,'御定全唐詩/json/290.json','["江邊日暮不勝愁，送客沾衣江上樓。", "明月峽添明月照，蛾眉峰似兩眉愁。"]'),
('yuding-20','初次巴陵','楊凝','唐','御定全唐诗','yuding','','[]','西江浪接洞庭波，積水遙連天上河。',32,'御定全唐詩/json/290.json','["西江浪接洞庭波，積水遙連天上河。", "鄉信為憑誰寄去，汀洲燕雁漸來多。"]'),
('yuding-21','上巳','楊凝','唐','御定全唐诗','yuding','','[]','帝京元巳足繁華，細管清弦七貴家。',32,'御定全唐詩/json/290.json','["帝京元巳足繁華，細管清弦七貴家。", "此日風光誰不共，紛紛皆是掖垣花。"]'),
('yuding-22','春怨','楊凝','唐','御定全唐诗','yuding','','[]','花滿簾櫳欲度春，此時夫婿在咸秦。',32,'御定全唐詩/json/290.json','["花滿簾櫳欲度春，此時夫婿在咸秦。", "綠窗孤寢難成寐，紫燕雙飛似弄人。"]'),
('yuding-23','送客歸常州','楊凝','唐','御定全唐诗','yuding','','[]','行到河邊從此辭，寒天日遠暮帆遲。',32,'御定全唐詩/json/290.json','["行到河邊從此辭，寒天日遠暮帆遲。", "可憐芳草成衰草，公子歸時過綠時。"]'),
('yuding-24','送別','楊凝','唐','御定全唐诗','yuding','','[]','春愁不盡別愁來，舊淚猶長新淚催。',32,'御定全唐詩/json/290.json','["春愁不盡別愁來，舊淚猶長新淚催。", "相思倘寄相思字，君到揚州揚子回。"]'),
('yuding-25','送客入蜀','楊凝','唐','御定全唐诗','yuding','','[]','劍閣迢迢夢想間，行人歸路繞梁山。',32,'御定全唐詩/json/290.json','["劍閣迢迢夢想間，行人歸路繞梁山。", "明朝騎馬搖鞭去，秋雨槐花子午關。"]'),
('yuding-26','送別','楊凝','唐','御定全唐诗','yuding','','[]','仙花笑盡石門中，石室重重掩綠空。',32,'御定全唐詩/json/290.json','["仙花笑盡石門中，石室重重掩綠空。", "暫下雲峰能幾日，卻回煙駕馭春風。"]'),
('yuding-27','殘花','楊凝','唐','御定全唐诗','yuding','','[]','五馬踟躕在路岐，南來隻為看花枝。',32,'御定全唐詩/json/290.json','["五馬踟躕在路岐，南來隻為看花枝。", "鶯銜蝶弄紅芳盡，此日深閨那得知。"]'),
('yuding-28','戲贈友人','楊凝','唐','御定全唐诗','yuding','','[]','湘陰直與地陰連，此日相逢憶醉年。',32,'御定全唐詩/json/290.json','["湘陰直與地陰連，此日相逢憶醉年。", "美酒非如平樂貴，十升不用一千錢。"]'),
('yuding-29','贈同游','楊凝','唐','御定全唐诗','yuding','','[]','此□風雨後，已覺減年華。若待皆無事，應難更有花。',48,'御定全唐詩/json/290.json','["此□風雨後，已覺減年華。若待皆無事，應難更有花。", "管弦臨夜急，榆柳向江斜。且莫看歸路，同須醉酒家。"]'),
('yuding-30','送人出塞','楊凝','唐','御定全唐诗','yuding','','[]','北風吹雨雪，舉目已淒淒。戰鬼秋頻哭，征鴻夜不棲。',48,'御定全唐詩/json/290.json','["北風吹雨雪，舉目已淒淒。戰鬼秋頻哭，征鴻夜不棲。", "沙平關路直，磧廣郡樓低。此去非東魯，人多事鼓鼙。"]'),
('yuding-31','尋僧元皎因病','楊凝','唐','御定全唐诗','yuding','','[]','此僧迷有著，因病得尋師。話盡山中事，歸當月上時。',48,'御定全唐詩/json/290.json','["此僧迷有著，因病得尋師。話盡山中事，歸當月上時。", "高松連寺影，亞竹入窗枝。閑憶草堂路，相逢非素期。"]'),
('yuding-32','夜泊渭津','楊凝','唐','御定全唐诗','yuding','','[]','飄飄東去客，一宿渭城邊。遠處星垂岸，中流月滿船。',48,'御定全唐詩/json/290.json','["飄飄東去客，一宿渭城邊。遠處星垂岸，中流月滿船。", "涼歸夜深簟，秋入雨餘天。漸覺家山小，殘程尚幾年。"]'),
('yuding-33','晚夏逢友人','楊凝','唐','御定全唐诗','yuding','','[]','一別同袍友，相思已十年。長安多在客，久病忽聞蟬。',48,'御定全唐詩/json/290.json','["一別同袍友，相思已十年。長安多在客，久病忽聞蟬。", "驟雨才沾地，陰雲不遍天。微涼堪話舊，移榻晚風前。"]'),
('yuding-34','別謫者','楊凝','唐','御定全唐诗','yuding','','[]','此地聞猶惡，人言是所之。一家書絕久，孤驛夢成遲。',48,'御定全唐詩/json/290.json','["此地聞猶惡，人言是所之。一家書絕久，孤驛夢成遲。", "八月三湘道，聞猿冒雨時。不須祠楚相，臣節轉堪疑。"]'),
('yuding-35','行思','楊凝','唐','御定全唐诗','yuding','','[]','千里豈雲去，欲歸如路窮。人間無暇日，馬上又秋風。',48,'御定全唐詩/json/290.json','["千里豈雲去，欲歸如路窮。人間無暇日，馬上又秋風。", "破月銜高嶽，流星拂曉空。此時皆在夢，行色獨匆匆。"]'),
('yuding-36','感懷題從舅宅','楊凝','唐','御定全唐诗','yuding','','[]','郤家庭樹下，幾度醉春風。今日花還發，當時事不同。',48,'御定全唐詩/json/290.json','["郤家庭樹下，幾度醉春風。今日花還發，當時事不同。", "流言應未息，直道竟難通。徒遣相思者，悲歌向暮空。"]'),
('yuding-37','與友人會','楊凝','唐','御定全唐诗','yuding','','[]','蟬吟槐蕊落，的的是愁端。病覺離家遠，貧知處事難。',48,'御定全唐詩/json/290.json','["蟬吟槐蕊落，的的是愁端。病覺離家遠，貧知處事難。", "真交無所隱，深語有餘歡。未必聞歌吹，羈心得暫寬。"]'),
('yuding-38','下第後蒙侍郎示意指于新先輩宣恩感謝','楊凝','唐','御定全唐诗','yuding','','[]','才薄命如此，自嗟兼自疑。遭逢好交日，黜落至公時。',48,'御定全唐詩/json/290.json','["才薄命如此，自嗟兼自疑。遭逢好交日，黜落至公時。", "倚玉甘無路，穿楊卻未期。更慚君侍坐，問許可言詩。"]'),
('yuding-0','奉酬韋滁州寄示','楊淩','唐','御定全唐诗','yuding','','[]','淮揚為郡暇，坐惜流芳歇。散懷累榭風，清暑澄潭月。',48,'御定全唐詩/json/291.json','["淮揚為郡暇，坐惜流芳歇。散懷累榭風，清暑澄潭月。", "陪燕辭三楚，戒途綿百越。非當遠別離，雅奏何由發。"]'),
('yuding-1','梅裏旅夕','楊淩','唐','御定全唐诗','yuding','','[]','滄洲東望路，旅棹愴羈遊。楓浦蟬隨岸，沙汀鷗轉流。',48,'御定全唐詩/json/291.json','["滄洲東望路，旅棹愴羈遊。楓浦蟬隨岸，沙汀鷗轉流。", "露天星上月，水國夜生秋。誰忍持相憶，南歸一葉舟。"]'),
('yuding-2','鐘陵雪夜酬友人','楊淩','唐','御定全唐诗','yuding','','[]','窮臘催年急，陽春怯和歌。殘燈閃壁盡，夜雪透窗多。',48,'御定全唐詩/json/291.json','["窮臘催年急，陽春怯和歌。殘燈閃壁盡，夜雪透窗多。", "歸路山川險，遊人夢寐過。龍洲不可泊，歲晚足驚波。"]'),
('yuding-3','潤州水樓','楊淩','唐','御定全唐诗','yuding','','[]','歸心不可留，雪桂一叢秋。葉雨空江月，螢飛白露洲。',48,'御定全唐詩/json/291.json','["歸心不可留，雪桂一叢秋。葉雨空江月，螢飛白露洲。", "野蟬依獨樹，水郭帶孤樓。遙望山川路，相思萬里遊。"]'),
('yuding-4','江上秋月','楊淩','唐','御定全唐诗','yuding','','[]','隴雁送鄉心，羈情屬歲陰。驚秋黃葉遍，愁暮碧雲深。',48,'御定全唐詩/json/291.json','["隴雁送鄉心，羈情屬歲陰。驚秋黃葉遍，愁暮碧雲深。", "月色吳江上，風聲楚木林。交親幾重別，歸夢並愁侵。"]'),
('yuding-5','閣前雙槿','楊淩','唐','御定全唐诗','yuding','','[]','群玉開雙槿，丹榮對絳紗。含煙疑出火，隔雨怪舒霞。',48,'御定全唐詩/json/291.json','["群玉開雙槿，丹榮對絳紗。含煙疑出火，隔雨怪舒霞。", "向晚爭辭蕊，迎朝鬥發花。非關後桃李，為欲繼年華。"]'),
('yuding-6','小苑春望宮池柳色','楊淩','唐','御定全唐诗','yuding','','[]','上苑閒遊早，東風柳色輕。儲胥遙掩映，池水隔微明。',72,'御定全唐詩/json/291.json','["上苑閒遊早，東風柳色輕。儲胥遙掩映，池水隔微明。", "春至條偏弱，寒餘葉未成。和煙變濃淡，轉日異陰晴。", "不獨芳菲好，還因雨露榮。行人望攀折，遠翠暮愁生。"]'),
('yuding-7','送客往睦州','楊淩','唐','御定全唐诗','yuding','','[]','水闊盡南天，孤舟去渺然。驚秋路傍客，日暮數聲蟬。',24,'御定全唐詩/json/291.json','["水闊盡南天，孤舟去渺然。驚秋路傍客，日暮數聲蟬。"]'),
('yuding-8','送客之蜀','楊淩','唐','御定全唐诗','yuding','','[]','西蜀三千里，巴南水一方。曉雲天際斷，夜月峽中長。',24,'御定全唐詩/json/291.json','["西蜀三千里，巴南水一方。曉雲天際斷，夜月峽中長。"]'),
('yuding-9','剡溪看花','楊淩','唐','御定全唐诗','yuding','','[]','花落千回舞，鶯聲百囀歌。還同異方樂，不奈客愁多。',24,'御定全唐詩/json/291.json','["花落千回舞，鶯聲百囀歌。還同異方樂，不奈客愁多。"]'),
('yuding-10','江中風','楊淩','唐','御定全唐诗','yuding','','[]','白浪暗江中，南泠路不通。高檣帆自滿，出浦莫呼風。',24,'御定全唐詩/json/291.json','["白浪暗江中，南泠路不通。高檣帆自滿，出浦莫呼風。"]'),
('yuding-11','詠破扇','楊淩','唐','御定全唐诗','yuding','','[]','粉落空床棄，塵生故篋留。先來無一半，情斷不勝愁。',24,'御定全唐詩/json/291.json','["粉落空床棄，塵生故篋留。先來無一半，情斷不勝愁。"]'),
('yuding-12','賈客愁','楊淩','唐','御定全唐诗','yuding','','[]','山水路悠悠，逢灘即殢留。西江風未便，何日到荊州。',24,'御定全唐詩/json/291.json','["山水路悠悠，逢灘即殢留。西江風未便，何日到荊州。"]'),
('yuding-13','即事寄人','楊淩','唐','御定全唐诗','yuding','','[]','中禁鳴鐘日欲高，北窗欹枕望頻搔。',32,'御定全唐詩/json/291.json','["中禁鳴鐘日欲高，北窗欹枕望頻搔。", "相思寂寞青苔合，唯有春風啼伯勞。"]'),
('yuding-14','早春雪中','楊淩','唐','御定全唐诗','yuding','','[]','新年雨雪少晴時，屢失尋梅看柳期。',32,'御定全唐詩/json/291.json','["新年雨雪少晴時，屢失尋梅看柳期。", "鄉信憶隨回雁早，江春寒帶故陰遲。"]'),
('yuding-15','北行留別','楊淩','唐','御定全唐诗','yuding','','[]','日日山川烽火頻，山河重起舊煙塵。',32,'御定全唐詩/json/291.json','["日日山川烽火頻，山河重起舊煙塵。", "一生孤負龍泉劍，羞把詩書問故人。"]'),
('yuding-16','秋原野望','楊淩','唐','御定全唐诗','yuding','','[]','客雁秋來次第逢，家書頻寄兩三封。',32,'御定全唐詩/json/291.json','["客雁秋來次第逢，家書頻寄兩三封。", "夕陽天外雲歸盡，亂見青山無數峰。"]'),
('yuding-17','春霽花萼樓南聞宮鶯','楊淩','唐','御定全唐诗','yuding','','[]','祥煙瑞氣曉來輕，柳變花開共作晴。',32,'御定全唐詩/json/291.json','["祥煙瑞氣曉來輕，柳變花開共作晴。", "黃鳥遠啼鳷鵲觀，春風流出鳳凰城。"]'),
('yuding-18','明妃怨','楊淩','唐','御定全唐诗','yuding','','[]','漢國明妃去不還，馬馱弦管向陰山。',32,'御定全唐詩/json/291.json','["漢國明妃去不還，馬馱弦管向陰山。", "匣中縱有菱花鏡，羞對單于照舊顏。"]'),
('yuding-19','句','楊淩','唐','御定全唐诗','yuding','','[]','南園桃李花落盡，春風寂寞搖空枝。',16,'御定全唐詩/json/291.json','["南園桃李花落盡，春風寂寞搖空枝。"]'),
('yuding-0','題玉真觀公主山池院','司空曙','唐','御定全唐诗','yuding','','[]','香殿留遺影，春朝玉戶開。羽衣重素幾，珠網儼輕埃。',72,'御定全唐詩/json/292.json','["香殿留遺影，春朝玉戶開。羽衣重素幾，珠網儼輕埃。", "石自蓬山得，泉經太液來。柳絲遮綠浪，花粉落青苔。", "鏡掩鸞空在，霞消鳳不回。唯餘古桃樹，傳是上仙栽。"]'),
('yuding-1','送永陽崔明府','司空曙','唐','御定全唐诗','yuding','','[]','古國群舒地，前當桐柏關。連綿江上雨，稠疊楚南山。',48,'御定全唐詩/json/292.json','["古國群舒地，前當桐柏關。連綿江上雨，稠疊楚南山。", "沙館行帆息，楓洲候吏還。乘籃若有暇，精舍在林間。"]'),
('yuding-2','送曹三同猗遊山寺','司空曙','唐','御定全唐诗','yuding','','[]','山蹋青蕪盡，涼秋古寺深。何時得連策，此夜更聞琴。',48,'御定全唐詩/json/292.json','["山蹋青蕪盡，涼秋古寺深。何時得連策，此夜更聞琴。", "窮水雲同穴，過僧虎共林。殷勤如念我，遺爾掛冠心。"]'),
('yuding-3','送崔校書赴梓幕','司空曙','唐','御定全唐诗','yuding','','[]','碧峰天柱下，鼓角鎮南軍。管記催飛檄，蓬萊輟校文。',48,'御定全唐詩/json/292.json','["碧峰天柱下，鼓角鎮南軍。管記催飛檄，蓬萊輟校文。", "棧霜朝似雪，江霧晚成雲。想出褒中望，巴庸方路分。"]'),
('yuding-4','送夔州班使君','司空曙','唐','御定全唐诗','yuding','','[]','魚國巴庸路，麾幢漢守過。曉檣爭市隘，夜鼓祭神多。',48,'御定全唐詩/json/292.json','["魚國巴庸路，麾幢漢守過。曉檣爭市隘，夜鼓祭神多。", "雲白當山雨，風清滿峽波。夷陵舊人吏，猶誦兩岐歌。"]'),
('yuding-5','送菊潭王明府','司空曙','唐','御定全唐诗','yuding','','[]','業成洙泗客，皓發著儒衣。一與遊人別，仍聞帶印歸。',48,'御定全唐詩/json/292.json','["業成洙泗客，皓發著儒衣。一與遊人別，仍聞帶印歸。", "林多宛地古，雲盡漢山稀。莫愛潯陽隱，嫌官計亦非。"]'),
('yuding-6','送太易上人赴東洛','司空曙','唐','御定全唐诗','yuding','','[]','遙見登山處，青蕪雪後春。雲深嶽廟火，寺宿洛陽人。',48,'御定全唐詩/json/292.json','["遙見登山處，青蕪雪後春。雲深嶽廟火，寺宿洛陽人。", "餌藥將齋折，唯詩與道親。凡經幾回別，麈尾不離身。"]'),
('yuding-7','和王卿立秋即事','司空曙','唐','御定全唐诗','yuding','','[]','秋宜何處看，試問白雲官。暗入蟬鳴樹，微侵蝶繞蘭。',96,'御定全唐詩/json/292.json','["秋宜何處看，試問白雲官。暗入蟬鳴樹，微侵蝶繞蘭。", "向風涼稍動，近日暑猶殘。九陌浮埃減，千峰爽氣攢。", "換衣防竹暮，沈果訝泉寒。宮響傳花杵，天清出露盤。", "高禽當側弁，遊鮪對憑欄。一奏招商曲，空令繼唱難。"]'),
('yuding-8','和李員外與舍人詠玫瑰花寄徐侍郎','司空曙','唐','御定全唐诗','yuding','','[]','仙吏紫薇郎，奇花共玩芳。攢星排綠蒂，照眼發紅光。',96,'御定全唐詩/json/292.json','["仙吏紫薇郎，奇花共玩芳。攢星排綠蒂，照眼發紅光。", "暗妒翻階藥，遙連直署香。游枝蜂繞易，礙刺鳥銜妨。", "露濕凝衣粉，風吹散蕊黃。蒙蘢珠樹合，煥爛錦屏張。", "留客勝看竹，思人比愛棠。如傳采蘋詠，遠思滿瀟湘。"]'),
('yuding-9','冬夜耿拾遺王秀才就宿因傷故人','司空曙','唐','御定全唐诗','yuding','','[]','舊時聞笛淚，今夜重沾衣。方恨同人少，何堪相見稀。',48,'御定全唐詩/json/292.json','["舊時聞笛淚，今夜重沾衣。方恨同人少，何堪相見稀。", "竹煙凝澗壑，林雪似芳菲。多謝勞車馬，應憐獨掩扉。"]'),
('yuding-10','早春遊慈恩南池','司空曙','唐','御定全唐诗','yuding','','[]','山寺臨池水，春愁望遠生。蹋橋逢鶴起，尋竹值泉橫。',48,'御定全唐詩/json/292.json','["山寺臨池水，春愁望遠生。蹋橋逢鶴起，尋竹值泉橫。", "新柳絲猶短，輕蘋葉未成。還如虎溪上，日暮伴僧行。"]'),
('yuding-11','雨夜見投之作','司空曙','唐','御定全唐诗','yuding','','[]','出戶繁星盡，池塘暗不開。動衣涼氣度，遰樹遠聲來。',48,'御定全唐詩/json/292.json','["出戶繁星盡，池塘暗不開。動衣涼氣度，遰樹遠聲來。", "燈外初行電，城隅偶隱雷。因知謝文學，曉望比塵埃。"]'),
('yuding-12','龍池寺望月寄韋使君閻別駕','司空曙','唐','御定全唐诗','yuding','','[]','清光此夜中，萬古望應同。當野山沈霧，低城樹有風。',48,'御定全唐詩/json/292.json','["清光此夜中，萬古望應同。當野山沈霧，低城樹有風。", "花宮紛共邃，水府皓相空。遙想高樓上，唯君對庾公。"]'),
('yuding-13','秋夜憶興善院寄苗發','司空曙','唐','御定全唐诗','yuding','','[]','右軍多住寺，此夜後池秋。自與山僧伴，那因洛客愁。',48,'御定全唐詩/json/292.json','["右軍多住寺，此夜後池秋。自與山僧伴，那因洛客愁。", "捲簾霜靄靄，滿目水悠悠。若有詩相贈，期君憶惠休。"]'),
('yuding-14','病中寄鄭十六兄','司空曙','唐','御定全唐诗','yuding','','[]','倦枕欲徐行，開簾秋月明。手便筇杖冷，頭喜葛巾輕。',48,'御定全唐詩/json/292.json','["倦枕欲徐行，開簾秋月明。手便筇杖冷，頭喜葛巾輕。", "綠草前侵水，黃花半上城。虛消此塵景，不見十年兄。"]'),
('yuding-15','衛明府寄枇杷葉以詩答','司空曙','唐','御定全唐诗','yuding','','[]','傾筐呈綠葉，重疊色何鮮。詎是秋風裏，猶如曉露前。',48,'御定全唐詩/json/292.json','["傾筐呈綠葉，重疊色何鮮。詎是秋風裏，猶如曉露前。", "仙方當見重，消疾本應便。全勝甘蕉贈，空投謝氏篇。"]'),
('yuding-16','過慶寶寺','司空曙','唐','御定全唐诗','yuding','','[]','黃葉前朝寺，無僧寒殿開。池晴龜出曝，松暮鶴飛回。',48,'御定全唐詩/json/292.json','["黃葉前朝寺，無僧寒殿開。池晴龜出曝，松暮鶴飛回。", "古井碑橫草，陰廊畫雜苔。禪宮亦銷歇，塵世轉堪哀。"]'),
('yuding-17','奉和張大夫酬高山人','司空曙','唐','御定全唐诗','yuding','','[]','野客居鈴閣，重門將校稀。豸冠親穀弁，龜印識荷衣。',48,'御定全唐詩/json/292.json','["野客居鈴閣，重門將校稀。豸冠親穀弁，龜印識荷衣。", "座右寒飆爽，談餘暮角微。蒼生須太傅，山在豈容歸。"]'),
('yuding-18','送嚴使君游山','司空曙','唐','御定全唐诗','yuding','','[]','家楚依三戶，辭州選一錢。酒杯同寄世，客棹任銷年。',48,'御定全唐詩/json/292.json','["家楚依三戶，辭州選一錢。酒杯同寄世，客棹任銷年。", "赤燒兼山遠，青蕪與浪連。青春明月夜，知上鄂君船。"]'),
('yuding-19','送柳震歸蜀','司空曙','唐','御定全唐诗','yuding','','[]','白日雙流靜，西看蜀國春。桐花能乳鳥，竹節競祠神。',48,'御定全唐詩/json/292.json','["白日雙流靜，西看蜀國春。桐花能乳鳥，竹節競祠神。", "蹇步徒相望，先鞭不可親。知從江僕射，登榻更何人。"]'),
('yuding-20','送樂平苗明府','司空曙','唐','御定全唐诗','yuding','','[]','天際山多處，東安古邑深。綠田通竹裏，白浪隔楓林。',48,'御定全唐詩/json/292.json','["天際山多處，東安古邑深。綠田通竹裏，白浪隔楓林。", "詩有江僧和，門唯越客尋。應將放魚化，一境表吾心。"]'),
('yuding-21','贈送鄭錢二郎中','司空曙','唐','御定全唐诗','yuding','','[]','梅含柳已動，昨日起東風。惆悵心徒壯，無如鬢作翁。',48,'御定全唐詩/json/292.json','["梅含柳已動，昨日起東風。惆悵心徒壯，無如鬢作翁。", "百年飄若水，萬緒盡歸空。何可宗禪客，遲回岐路中。"]'),
('yuding-22','酬鄭十四望驛不得同宿見贈因寄張參軍','司空曙','唐','御定全唐诗','yuding','','[]','逢君喜成淚，暫似故鄉中。謫宦猶多懼，清宵不得終。',48,'御定全唐詩/json/292.json','["逢君喜成淚，暫似故鄉中。謫宦猶多懼，清宵不得終。", "月煙高有鶴，宿草淨無蟲。明日郤超會，應思下客同。"]'),
('yuding-23','暮春野望寄錢起','司空曙','唐','御定全唐诗','yuding','','[]','草長花落樹，羸病強尋春。無複少年意，空餘華髮新。',48,'御定全唐詩/json/292.json','["草長花落樹，羸病強尋春。無複少年意，空餘華髮新。", "青原高見水，白社靜逢人。寄謝南宮客，軒車不可親。"]'),
('yuding-24','送王使君小子孝廉登科歸省','司空曙','唐','御定全唐诗','yuding','','[]','年少通經學，登科尚佩觿。張馮本名士，蔡廓是佳兒。',48,'御定全唐詩/json/292.json','["年少通經學，登科尚佩觿。張馮本名士，蔡廓是佳兒。", "鞍馬臨岐路，龍鍾對別離。寄書胡太守，請與故人知。"]'),
('yuding-25','雲陽寺石竹花','司空曙','唐','御定全唐诗','yuding','','[]','一自幽山別，相逢此寺中。高低俱出葉，深淺不分叢。',48,'御定全唐詩/json/292.json','["一自幽山別，相逢此寺中。高低俱出葉，深淺不分叢。", "野蝶難爭白，庭榴暗讓紅。誰憐芳最久，春露到秋風。"]'),
('yuding-26','送高勝重謁曹王','司空曙','唐','御定全唐诗','yuding','','[]','江上青楓岸，陰陰萬里春。朝辭郢城酒，暮見洞庭人。',48,'御定全唐詩/json/292.json','["江上青楓岸，陰陰萬里春。朝辭郢城酒，暮見洞庭人。", "興比乘舟訪，恩懷倒屣親。想君登舊榭，重喜掃芳塵。"]'),
('yuding-27','閑園書事招暢當','司空曙','唐','御定全唐诗','yuding','','[]','聞蟬晝眠後，欹枕對蓬蒿。羸病懶尋戴，田園方詠陶。',48,'御定全唐詩/json/292.json','["聞蟬晝眠後，欹枕對蓬蒿。羸病懶尋戴，田園方詠陶。", "傍簷蟲掛靜，出樹蝶飛高。惆悵臨清鏡，思君見鬢毛。"]'),
('yuding-28','過錢員外','司空曙','唐','御定全唐诗','yuding','','[]','為郎頭已白，跡向市朝稀。移病居荒宅，安貧著敗衣。',48,'御定全唐詩/json/292.json','["為郎頭已白，跡向市朝稀。移病居荒宅，安貧著敗衣。", "野園隨客醉，雪寺伴僧歸。自說東峰下，松蘿滿故扉。"]'),
('yuding-29','贈庾侍禦','司空曙','唐','御定全唐诗','yuding','','[]','年少身無累，相逢憶此時。雪過雲寺宿，酒向竹園期。',48,'御定全唐詩/json/292.json','["年少身無累，相逢憶此時。雪過雲寺宿，酒向竹園期。", "白髮今催老，清琴但起悲。唯應逐宗炳，內學願為師。"]'),
('yuding-30','贈李端','司空曙','唐','御定全唐诗','yuding','','[]','共憶南浮日，登高望若何。楚田湖草遠，江寺海榴多。',48,'御定全唐詩/json/292.json','["共憶南浮日，登高望若何。楚田湖草遠，江寺海榴多。", "載酒尋山宿，思人帶雪過。東西幾回別，此會各蹉跎。"]'),
('yuding-31','送流人','司空曙','唐','御定全唐诗','yuding','','[]','聞說南中事，悲君重竄身。山村楓子鬼，江廟石郎神。',48,'御定全唐詩/json/292.json','["聞說南中事，悲君重竄身。山村楓子鬼，江廟石郎神。", "童稚留荒宅，圖書托故人。青門好風景，為爾一沾巾。"]'),
('yuding-32','過胡居士睹王右丞遺文','司空曙','唐','御定全唐诗','yuding','','[]','舊日相知盡，深居獨一身。閉門空有雪，看竹永無人。',48,'御定全唐詩/json/292.json','["舊日相知盡，深居獨一身。閉門空有雪，看竹永無人。", "每許前山隱，曾憐陋巷貧。題詩今尚在，暫為拂流塵。"]'),
('yuding-33','送郎使君赴郢州','司空曙','唐','御定全唐诗','yuding','','[]','使君持節去，雲水滿前程。楚寺多連竹，江檣遠映城。',48,'御定全唐詩/json/292.json','["使君持節去，雲水滿前程。楚寺多連竹，江檣遠映城。", "登樓向月望，賽廟傍山行。若動思鄉詠，應貽謝步兵。"]'),
('yuding-34','賊平後送人北歸','司空曙','唐','御定全唐诗','yuding','','[]','世亂同南去，時清獨北還。他鄉生白髮，舊國見青山。',48,'御定全唐詩/json/292.json','["世亂同南去，時清獨北還。他鄉生白髮，舊國見青山。", "曉月過殘壘，繁星宿故關。寒禽與衰草，處處伴愁顏。"]'),
('yuding-35','觀獵騎','司空曙','唐','御定全唐诗','yuding','','[]','纏臂繡綸巾，貂裘窄稱身。射禽風助箭，走馬雪翻塵。',48,'御定全唐詩/json/292.json','["纏臂繡綸巾，貂裘窄稱身。射禽風助箭，走馬雪翻塵。", "金埒爭開道，香車為駐輪。翩翩不知處，傳是霍家親。"]'),
('yuding-36','同苗員外宿薦福常師房','司空曙','唐','御定全唐诗','yuding','','[]','浮生共多故，聚宿喜君同。人息時聞磬，燈搖乍有風。',48,'御定全唐詩/json/292.json','["浮生共多故，聚宿喜君同。人息時聞磬，燈搖乍有風。", "霜階疑水際，夜木似山中。一願持如意，長來事遠公。"]'),
('yuding-37','送喬廣下第歸淮南','司空曙','唐','御定全唐诗','yuding','','[]','遙想長淮盡，荒堤楚路斜。戍旌標白浪，罟網入青葭。',48,'御定全唐詩/json/292.json','["遙想長淮盡，荒堤楚路斜。戍旌標白浪，罟網入青葭。", "啼鳥仍臨水，愁人更見花。東堂一枝在，為子惜年華。"]'),
('yuding-38','風箏','司空曙','唐','御定全唐诗','yuding','','[]','高風吹玉柱，萬籟忽齊飄。颯樹遲難度，縈空細漸銷。',48,'御定全唐詩/json/292.json','["高風吹玉柱，萬籟忽齊飄。颯樹遲難度，縈空細漸銷。", "松泉鹿門夜，笙鶴洛濱朝。坐與真僧聽，支頤向寂寥。"]'),
('yuding-39','閒居寄苗發','司空曙','唐','御定全唐诗','yuding','','[]','漸向浮生老，前期竟若何。獨身居處靜，永夜坐時多。',48,'御定全唐詩/json/292.json','["漸向浮生老，前期竟若何。獨身居處靜，永夜坐時多。", "厭逐青林客，休吟白雪歌。支公有遺寺，重與謝安過。"]'),
('yuding-40','送王先生歸南山','司空曙','唐','御定全唐诗','yuding','','[]','儒中年最老，獨有濟南生。愛子方傳業，無官自耦耕。',48,'御定全唐詩/json/292.json','["儒中年最老，獨有濟南生。愛子方傳業，無官自耦耕。", "竹通山舍遠，雲接雪田平。願作門人去，相隨隱姓名。"]'),
('yuding-41','寄天臺秀師','司空曙','唐','御定全唐诗','yuding','','[]','天臺瀑布寺，傳有白頭師。幻跡示羸病，空門無住持。',48,'御定全唐詩/json/292.json','["天臺瀑布寺，傳有白頭師。幻跡示羸病，空門無住持。", "雪晴看鶴去，海夜與龍期。永願親瓶屨，呈功得問疑。"]'),
('yuding-42','送夏侯審赴甯國','司空曙','唐','御定全唐诗','yuding','','[]','青圻連白浪，曉日渡南津。山疊陵陽樹，舟多建業人。',48,'御定全唐詩/json/292.json','["青圻連白浪，曉日渡南津。山疊陵陽樹，舟多建業人。", "煙霞高占寺，楓竹暗停神。如接玄暉集，江丞獨見親。"]'),
('yuding-43','雲陽館與韓紳宿別','司空曙','唐','御定全唐诗','yuding','','[]','故人江海別，幾度隔山川。乍見翻疑夢，相悲各問年。',48,'御定全唐詩/json/292.json','["故人江海別，幾度隔山川。乍見翻疑夢，相悲各問年。", "孤燈寒照雨，濕竹暗浮煙。更有明朝恨，離杯惜共傳。"]'),
('yuding-44','送盧使君赴夔州','司空曙','唐','御定全唐诗','yuding','','[]','鐃管隨旌旆，高秋遠上巴。白波連霧雨，青壁斷蒹葭。',48,'御定全唐詩/json/292.json','["鐃管隨旌旆，高秋遠上巴。白波連霧雨，青壁斷蒹葭。", "憑幾雙童靜，登樓萬井斜。政成知變俗，當應畫輪車。"]'),
('yuding-45','夜聞回雁','司空曙','唐','御定全唐诗','yuding','','[]','雁響天邊過，高高望不分。颼飀傳細雨，嘹唳隔長雲。',48,'御定全唐詩/json/292.json','["雁響天邊過，高高望不分。颼飀傳細雨，嘹唳隔長雲。", "散向誰家盡，歸來幾客聞。還將今夜意，西海話蘇君。"]'),
('yuding-46','賦得的的帆向浦','司空曙','唐','御定全唐诗','yuding','','[]','向浦參差去，隨波遠近還。初移芳草裏，正在夕陽間。',48,'御定全唐詩/json/292.json','["向浦參差去，隨波遠近還。初移芳草裏，正在夕陽間。", "隱映回孤驛，微明出亂山。向空看不盡，歸思滿江關。"]'),
('yuding-47','秋思呈尹植裴說','司空曙','唐','御定全唐诗','yuding','','[]','靜向懶相偶，年將衰共催。前途歡不集，往事恨空來。',48,'御定全唐詩/json/292.json','["靜向懶相偶，年將衰共催。前途歡不集，往事恨空來。", "晝景委紅葉，月華銷綠苔。沈思竟何有，坐結玉琴哀。"]'),
('yuding-48','閑園即事寄暕公','司空曙','唐','御定全唐诗','yuding','','[]','欲就東林寄一身，尚憐兒女未成人。柴門客去殘陽在，',40,'御定全唐詩/json/292.json','["欲就東林寄一身，尚憐兒女未成人。柴門客去殘陽在，", "深山蘭若何時到，羨與閑雲作四鄰。"]'),
('yuding-49','題暕上人院','司空曙','唐','御定全唐诗','yuding','','[]','閉門不出自焚香，擁褐看山歲月長。雨後綠苔生石井，',40,'御定全唐詩/json/292.json','["閉門不出自焚香，擁褐看山歲月長。雨後綠苔生石井，", "更說本師同學在，幾時攜手見衡陽。"]'),
('yuding-50','長安曉望寄程補闕','司空曙','唐','御定全唐诗','yuding','','[]','迢遞山河擁帝京，參差宮殿接雲平。風吹曉漏經長樂，',40,'御定全唐詩/json/292.json','["迢遞山河擁帝京，參差宮殿接雲平。風吹曉漏經長樂，", "獨有淺才甘未達，多慚名在魯諸生。"]'),
('yuding-51','下第日書情寄上叔父','司空曙','唐','御定全唐诗','yuding','','[]','微才空覺滯京師，末學曾為叔父知。雪裏題詩偏見賞，',40,'御定全唐詩/json/292.json','["微才空覺滯京師，末學曾為叔父知。雪裏題詩偏見賞，", "欲歸江海尋山去，願報何人得桂枝。"]'),
('yuding-52','南原望漢宮','司空曙','唐','御定全唐诗','yuding','','[]','荒原空有漢宮名，衰草茫茫雉堞平。連雁下時秋水在，',40,'御定全唐詩/json/292.json','["荒原空有漢宮名，衰草茫茫雉堞平。連雁下時秋水在，", "故事悠悠不可問，寒禽野水自縱橫。"]'),
('yuding-53','早夏寄元校書','司空曙','唐','御定全唐诗','yuding','','[]','獨遊野徑送芳菲，高竹林居接翠微。綠岸草深蟲入遍，',40,'御定全唐詩/json/292.json','["獨遊野徑送芳菲，高竹林居接翠微。綠岸草深蟲入遍，", "蓬蓽永無車馬到，更當齋夜憶玄暉。"]'),
('yuding-54','贈衡岳隱禪師','司空曙','唐','御定全唐诗','yuding','','[]','擁褐安居南嶽頭，白雲高寺見衡州。石窗湖水搖寒月，',40,'御定全唐詩/json/292.json','["擁褐安居南嶽頭，白雲高寺見衡州。石窗湖水搖寒月，", "垂垂身老將傳法，因下人間遂北遊。"]'),
('yuding-55','題淩雲寺','司空曙','唐','御定全唐诗','yuding','','[]','春山古寺繞滄波，石磴盤空鳥道過。百丈金身開翠壁，',40,'御定全唐詩/json/292.json','["春山古寺繞滄波，石磴盤空鳥道過。百丈金身開翠壁，", "不與方袍同結社，下歸塵世竟如何。"]'),
('yuding-56','晦日益州北池陪宴','司空曙','唐','御定全唐诗','yuding','','[]','臨泛從公日，仙舟翠幕張。七橋通碧沼，雙樹接花塘。',96,'御定全唐詩/json/292.json','["臨泛從公日，仙舟翠幕張。七橋通碧沼，雙樹接花塘。", "玉燭收寒氣，金波隱夕光。野聞歌管思，水靜綺羅香。", "游騎縈林遠，飛橈截岸長。郊原懷灞滻，陂溠寫江潢。", "常侍傳花詔，偏裨問羽觴。豈令南峴首，千載播餘芳。"]'),
('yuding-57','送曲山人之衡州','司空曙','唐','御定全唐诗','yuding','','[]','白石先生眉發光，已分甜雪飲紅漿。衣巾半染煙霞氣，',40,'御定全唐詩/json/292.json','["白石先生眉發光，已分甜雪飲紅漿。衣巾半染煙霞氣，", "千年城郭如相問，華表峨峨有夜霜。"]'),
('yuding-58','立秋日','司空曙','唐','御定全唐诗','yuding','','[]','律變新秋至，蕭條自此初。花酣蓮報謝，葉在柳呈疏。',72,'御定全唐詩/json/292.json','["律變新秋至，蕭條自此初。花酣蓮報謝，葉在柳呈疏。", "澹日非雲映，清風似雨餘。捲簾涼暗度，迎扇暑先除。", "草靜多翻燕，波澄乍露魚。今朝散騎省，作賦興何如。"]'),
('yuding-59','詠古寺花','司空曙','唐','御定全唐诗','yuding','','[]','共愛芳菲此樹中，千跗萬萼裹枝紅。',32,'御定全唐詩/json/292.json','["共愛芳菲此樹中，千跗萬萼裹枝紅。", "遲遲欲去猶回望，覆地無人滿寺風。"]'),
('yuding-60','酬張芬有赦後見贈','司空曙','唐','御定全唐诗','yuding','','[]','紫鳳朝銜五色書，陽春忽布網羅除。已將心變寒灰後，',40,'御定全唐詩/json/292.json','["紫鳳朝銜五色書，陽春忽布網羅除。已將心變寒灰後，", "勞君故有詩相贈，欲報瓊瑤恨不如。"]'),
('yuding-61','哭苗員外呈張參軍','司空曙','唐','御定全唐诗','yuding','','[]','思君寧家宅，久接竹林期。嘗值偷琴處，親聞比玉時。',96,'御定全唐詩/json/292.json','["思君寧家宅，久接竹林期。嘗值偷琴處，親聞比玉時。", "高人不易合，弱冠早相知。試藝臨諸友，能文即我師。", "淩寒松未老，先暮槿何衰。季子生前別，羊曇醉後悲。", "壽堂乖一慟，奠席阻長辭。因瀝殊方淚，遙成墓下詩。"]'),
('yuding-62','金陵懷古','司空曙','唐','御定全唐诗','yuding','','[]','輦路江楓暗，宮庭野草春。傷心庾開府，老作北朝臣。',24,'御定全唐詩/json/292.json','["輦路江楓暗，宮庭野草春。傷心庾開府，老作北朝臣。"]'),
('yuding-63','發渝州卻寄韋判官','司空曙','唐','御定全唐诗','yuding','','[]','紅燭津亭夜見君，繁弦急管兩紛紛。',32,'御定全唐詩/json/292.json','["紅燭津亭夜見君，繁弦急管兩紛紛。", "平明分手空江轉，唯有猿聲滿水雲。"]'),
('yuding-64','送盧徹之太原謁馬尚書','司空曙','唐','御定全唐诗','yuding','','[]','榆落雕飛關塞秋，黃雲畫角見並州。',32,'御定全唐詩/json/292.json','["榆落雕飛關塞秋，黃雲畫角見並州。", "翩翩羽騎雙旌後，上客親隨郭細侯。"]'),
('yuding-65','峽口送友人','司空曙','唐','御定全唐诗','yuding','','[]','峽口花飛欲盡春，天涯去住淚沾巾。',32,'御定全唐詩/json/292.json','["峽口花飛欲盡春，天涯去住淚沾巾。", "來時萬里同為客，今日翻成送故人。"]'),
('yuding-66','故郭婉儀挽歌','司空曙','唐','御定全唐诗','yuding','','[]','一日辭秦鏡，千秋別漢宮。豈唯泉路掩，長使月輪空。',48,'御定全唐詩/json/292.json','["一日辭秦鏡，千秋別漢宮。豈唯泉路掩，長使月輪空。", "苦色凝朝露，悲聲切暝風。婉儀餘舊德，仍載禮經中。"]'),
('yuding-67','送翰林張學士嶺南勒聖碑','司空曙','唐','御定全唐诗','yuding','','[]','漢恩天外洽，周頌日邊稱。文獨司空羨，書兼太尉能。',48,'御定全唐詩/json/292.json','["漢恩天外洽，周頌日邊稱。文獨司空羨，書兼太尉能。", "出關逢北雁，度嶺逐南鵬。使者翰林客，餘春歸灞陵。"]'),
('yuding-68','送吉校書東歸','司空曙','唐','御定全唐诗','yuding','','[]','少年芸閣吏，罷直暫歸休。獨與親知別，行逢江海秋。',48,'御定全唐詩/json/292.json','["少年芸閣吏，罷直暫歸休。獨與親知別，行逢江海秋。", "聽猿看楚岫，隨雁到吳洲。處處園林好，何人待子猷。"]'),
('yuding-69','早春遊望','司空曙','唐','御定全唐诗','yuding','','[]','東風春未足，試望秦城曲。青草狀寒蕪，黃花似秋菊。',48,'御定全唐詩/json/292.json','["東風春未足，試望秦城曲。青草狀寒蕪，黃花似秋菊。", "壯將歡共去，老與悲相逐。獨作遊社人，暮過威輦宿。"]'),
('yuding-70','秋日趨府上張大夫','司空曙','唐','御定全唐诗','yuding','','[]','重城洞啟肅秋煙，共說羊公在鎮年。鞞鼓暗驚林葉落，',40,'御定全唐詩/json/292.json','["重城洞啟肅秋煙，共說羊公在鎮年。鞞鼓暗驚林葉落，", "謫吏何能沐風化，空將歌頌拜車前。"]'),
('yuding-71','竹裏徑','司空曙','唐','御定全唐诗','yuding','','[]','幽徑行跡稀，清陰苔色古。蕭蕭風欲來，乍似蓬山雨。',24,'御定全唐詩/json/292.json','["幽徑行跡稀，清陰苔色古。蕭蕭風欲來，乍似蓬山雨。"]'),
('yuding-72','黃子陂','司空曙','唐','御定全唐诗','yuding','','[]','岸芳春色曉，水影夕陽微。寂寂深煙裏，漁舟夜不歸。',24,'御定全唐詩/json/292.json','["岸芳春色曉，水影夕陽微。寂寂深煙裏，漁舟夜不歸。"]'),
('yuding-73','田鶴','司空曙','唐','御定全唐诗','yuding','','[]','散下渚田中，隱見菰蒲裏。哀鳴自相應，欲作淩風起。',24,'御定全唐詩/json/292.json','["散下渚田中，隱見菰蒲裏。哀鳴自相應，欲作淩風起。"]'),
('yuding-74','藥園','司空曙','唐','御定全唐诗','yuding','','[]','春園芳已遍，綠蔓雜紅英。獨有深山客，時來辨藥名。',24,'御定全唐詩/json/292.json','["春園芳已遍，綠蔓雜紅英。獨有深山客，時來辨藥名。"]'),
('yuding-75','石井','司空曙','唐','御定全唐诗','yuding','','[]','苔色遍春石，桐陰入寒井。幽人獨汲時，先樂殘陽影。',24,'御定全唐詩/json/292.json','["苔色遍春石，桐陰入寒井。幽人獨汲時，先樂殘陽影。"]'),
('yuding-76','板橋','司空曙','唐','御定全唐诗','yuding','','[]','橫遮野水石，前帶荒村道。來往見愁人，清風柳陰好。',24,'御定全唐詩/json/292.json','["橫遮野水石，前帶荒村道。來往見愁人，清風柳陰好。"]'),
('yuding-77','石蓮花','司空曙','唐','御定全唐诗','yuding','','[]','今逢石上生，本自波中有。紅豔秋風裏，誰憐眾芳後。',24,'御定全唐詩/json/292.json','["今逢石上生，本自波中有。紅豔秋風裏，誰憐眾芳後。"]'),
('yuding-78','遠寺鐘','司空曙','唐','御定全唐诗','yuding','','[]','杳杳疏鐘發，因風清複引。中宵獨聽之，似與東林近。',24,'御定全唐詩/json/292.json','["杳杳疏鐘發，因風清複引。中宵獨聽之，似與東林近。"]'),
('yuding-79','松下雪','司空曙','唐','御定全唐诗','yuding','','[]','不隨晴野盡，獨向深松積。落照入寒光，偏能伴幽寂。',24,'御定全唐詩/json/292.json','["不隨晴野盡，獨向深松積。落照入寒光，偏能伴幽寂。"]'),
('yuding-80','新柳','司空曙','唐','御定全唐诗','yuding','','[]','全欺芳蕙晚，似妒寒梅疾。撩亂發青條，春風來幾日。',24,'御定全唐詩/json/292.json','["全欺芳蕙晚，似妒寒梅疾。撩亂發青條，春風來幾日。"]'),
('yuding-81','唐昌公主院看花','司空曙','唐','御定全唐诗','yuding','','[]','遺殿空長閉，乘鸞自不回。至今荒草上，寥落舊花開。',24,'御定全唐詩/json/292.json','["遺殿空長閉，乘鸞自不回。至今荒草上，寥落舊花開。"]'),
('yuding-82','別張贊','司空曙','唐','御定全唐诗','yuding','','[]','今日山晴後，殘蟬菊發時。登樓見秋色，何處最相思。',24,'御定全唐詩/json/292.json','["今日山晴後，殘蟬菊發時。登樓見秋色，何處最相思。"]'),
('yuding-83','晚思','司空曙','唐','御定全唐诗','yuding','','[]','蛩餘窗下月，草濕階前露。晚景淒我衣，秋風入庭樹。',24,'御定全唐詩/json/292.json','["蛩餘窗下月，草濕階前露。晚景淒我衣，秋風入庭樹。"]'),
('yuding-84','留盧秦卿','司空曙','唐','御定全唐诗','yuding','','[]','知有前期在，難分此夜中。無將故人酒，不及石尤風。',24,'御定全唐詩/json/292.json','["知有前期在，難分此夜中。無將故人酒，不及石尤風。"]'),
('yuding-85','登峴亭','司空曙','唐','御定全唐诗','yuding','','[]','峴山回首望秦關，南向荊州幾日還。',32,'御定全唐詩/json/292.json','["峴山回首望秦關，南向荊州幾日還。", "今日登臨唯有淚，不知風景在何山。"]'),
('yuding-86','哭麹山人','司空曙','唐','御定全唐诗','yuding','','[]','憶昔秋風起，君曾歎逐臣。何言芳草日，自作九泉人。',24,'御定全唐詩/json/292.json','["憶昔秋風起，君曾歎逐臣。何言芳草日，自作九泉人。"]'),
('yuding-87','過堅上人故院與李端同賦','司空曙','唐','御定全唐诗','yuding','','[]','舊依支遁宿，曾與戴顒來。今日空林下，唯知見綠苔。',24,'御定全唐詩/json/292.json','["舊依支遁宿，曾與戴顒來。今日空林下，唯知見綠苔。"]'),
('yuding-88','病中嫁女妓','司空曙','唐','御定全唐诗','yuding','','[]','萬事傷心在目前，一身垂淚對花筵。',32,'御定全唐詩/json/292.json','["萬事傷心在目前，一身垂淚對花筵。", "黃金用盡教歌舞，留與他人樂少年。"]'),
('yuding-89','江村即事','司空曙','唐','御定全唐诗','yuding','','[]','釣罷歸來不系船，江村月落正堪眠。',32,'御定全唐詩/json/292.json','["釣罷歸來不系船，江村月落正堪眠。", "縱然一夜風吹去，只在蘆花淺水邊。"]'),
('yuding-0','送鄭明府貶嶺南','司空曙','唐','御定全唐诗','yuding','','[]','青楓江色晚，楚客獨傷春。共對一尊酒，相看萬里人。',48,'御定全唐詩/json/293.json','["青楓江色晚，楚客獨傷春。共對一尊酒，相看萬里人。", "猜嫌成謫宦，正直不防身。莫畏炎方久，年年雨露新。"]'),
('yuding-1','寄衛明府常見短靴褐裘，又務持誦是以有末句之贈','司空曙','唐','御定全唐诗','yuding','','[]','柴桑官舍近東林，兒稚初髫即道心。側寄繩床嫌憑幾，',40,'御定全唐詩/json/293.json','["柴桑官舍近東林，兒稚初髫即道心。側寄繩床嫌憑幾，", "翠竹黃花皆佛性，莫教塵境誤相侵。"]'),
('yuding-2','酬李端校書見贈','司空曙','唐','御定全唐诗','yuding','','[]','綠槐垂穗乳烏飛，忽憶山中獨未歸。青鏡流年看發變，',40,'御定全唐詩/json/293.json','["綠槐垂穗乳烏飛，忽憶山中獨未歸。青鏡流年看發變，", "昨日聞君到城闕，莫將簪弁勝荷衣。"]');
